-- Poems batch 323
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('5bec1e5f-d181-43fe-92a4-860de86fa832','蒙泉','孫僅','宋','宋诗','song-poetry','','[]','孤城深鎖亂雲間，城上雲開面面山。',32,'全唐诗/poet.song.5000.json','["孤城深鎖亂雲間，城上雲開面面山。", "負郭惠泉誰共訪，衛公詩碣綠苔班。"]'),
('baa979e9-6082-42cb-a531-b27fa75e8bbf','題潛山','孫僅','宋','宋诗','song-poetry','','[]','勢參吳楚分，作鎮向同安。',288,'全唐诗/poet.song.5000.json','["勢參吳楚分，作鎮向同安。", "地勝塵寰隔，天深洞府寬。", "位將衡嶽敵，根與霍山盤。", "塵見千年白，霞生萬仞丹。", "崖秋爭峭拔，峰霽間巑岏。", "日轉香爐煖，風生玉照寒。", "石棲平郡堞，天柱倚雲端。", "絕頂人遊少，高空鳥度難。", "風雷生別壑，星斗繞層巒。", "寒暑巖間異，方隅嶺際觀。", "爲霖同海內，倒影壓平阡。", "砂印猿蹤跡，池飄鶴羽翰。", "烟蘿交密蔭，瀑布落飛端。", "磴道莓苔滑，松根霹靂乾。", "石奇疑虎伏，湫險認龍蟠。", "勝好當春賞，幽宜带雪看。", "氣蒸茶蕊嫩，香老菊花殘。", "青擢凌霄幹，紅垂受露蘭。", "禪鄰祖師塔，仙接左慈壇。", "幾客歌維嶽，何人詠考槃。", "元宗曾立廟，武帝亦鳴鸞。", "聖代從何極，靈祠輯未闌。", "青詞馳長吏，法服降中官。", "千古圖經裏，高名定不刊。"]'),
('008a175e-c4fa-4869-9be2-baa7c88a53f2','步虛臺','孫僅','宋','宋诗','song-poetry','','[]','抱懷寧獨固難窮，自與山林逸興同。',64,'全唐诗/poet.song.5000.json','["抱懷寧獨固難窮，自與山林逸興同。", "白馬豈能分辨客，青牛還會識仙翁。", "凝神宅古河聲裏，望氣臺荒野色中。", "試上高原長一嘯，斷蓬衰草掩秋風。"]'),
('32e35c75-4e28-48df-b952-f2744d26a0c8','秋','孫僅','宋','宋诗','song-poetry','','[]','火雲猶未斂奇峰，欹枕初驚一葉風。',32,'全唐诗/poet.song.5000.json','["火雲猶未斂奇峰，欹枕初驚一葉風。", "幾處園林蕭瑟裏，誰家砧杵寂寥中。"]'),
('bf83f465-247f-47fa-b115-4891cbb98c41','詩一首','孫僅','宋','宋诗','song-poetry','','[]','閒如雲鶴散如仙，逸士聲名處處傳。',64,'全唐诗/poet.song.5000.json','["閒如雲鶴散如仙，逸士聲名處處傳。", "詩自會來輕物象，道從高後小林泉。", "謀身只置煎茶鼎，積貨惟收賣藥錢。", "見說新居更幽僻，爲憂徵詔到門前。"]'),
('6c51ad7c-9e96-48b1-89b9-5c475f0aed13','句  其一','孫僅','宋','宋诗','song-poetry','','[]','刑人一旦起幽深，功業煌煌照古今。',16,'全唐诗/poet.song.5000.json','["刑人一旦起幽深，功業煌煌照古今。"]'),
('bbf7b1b1-231c-489c-8c10-0b6323b70b60','句  其二','孫僅','宋','宋诗','song-poetry','','[]','朱衣吏引上驪山。',8,'全唐诗/poet.song.5000.json','["朱衣吏引上驪山。"]'),
('0f502c6c-b0df-4063-bca9-280f4ce62731','句  其三','孫僅','宋','宋诗','song-poetry','','[]','秦帝墓成陳勝起，明皇宮就祿山來。',16,'全唐诗/poet.song.5000.json','["秦帝墓成陳勝起，明皇宮就祿山來。"]'),
('8c38db5f-d825-41d1-96d6-14a49f223e90','句  其四','孫僅','宋','宋诗','song-poetry','','[]','汾水冷光摇畫戟，蒙山秋色鎖層樓。',16,'全唐诗/poet.song.5000.json','["汾水冷光摇畫戟，蒙山秋色鎖層樓。"]'),
('c63398c2-df3d-450d-ada3-1f6422f5a775','句  其五','孫僅','宋','宋诗','song-poetry','','[]','巴陵山水冠南中，送陳生歸岳州詩。',16,'全唐诗/poet.song.5000.json','["巴陵山水冠南中，送陳生歸岳州詩。"]'),
('9a92e340-1a5a-438c-9b27-914947b101c4','句  其六','孫僅','宋','宋诗','song-poetry','','[]','江路北來通漢水，土風南去接荆蠻。',16,'全唐诗/poet.song.5000.json','["江路北來通漢水，土風南去接荆蠻。"]'),
('fc9941cb-818c-4e71-af49-61814b4e9a9b','句  其七','孫僅','宋','宋诗','song-poetry','','[]','春來何事謫蓬瀛。',8,'全唐诗/poet.song.5000.json','["春來何事謫蓬瀛。"]'),
('2aabbafe-28e4-4a9d-9099-1728bffb7393','句  其八','孫僅','宋','宋诗','song-poetry','','[]','僧寺聚觀刊石處，人家傳寫掛牌時。',16,'全唐诗/poet.song.5000.json','["僧寺聚觀刊石處，人家傳寫掛牌時。"]'),
('a5a24df5-7615-4b6a-97cd-cb695c6465af','句  其九','孫僅','宋','宋诗','song-poetry','','[]','轉戰風騷如甲胄，平分才學過權衡。',16,'全唐诗/poet.song.5000.json','["轉戰風騷如甲胄，平分才學過權衡。"]'),
('76368c7f-2ef4-44bf-be0b-82cfb7378648','句  其一○','孫僅','宋','宋诗','song-poetry','','[]','庭梧影薄晨霜落，籬菊香寒晚吹生。',16,'全唐诗/poet.song.5000.json','["庭梧影薄晨霜落，籬菊香寒晚吹生。"]'),
('27b46d85-eaa9-4113-91c8-0fb450c64bd0','句','王逸','宋','宋诗','song-poetry','','[]','他年館閣同遊處，榮路方蹤繼二孫。',16,'全唐诗/poet.song.5000.json','["他年館閣同遊處，榮路方蹤繼二孫。"]'),
('8d69ed29-0039-4493-b4a2-57ed2a38b6fe','送高學士知越','陳知微','宋','宋诗','song-poetry','','[]','會稽新命剖魚符，又向蓬山鎖直廬。',64,'全唐诗/poet.song.5000.json','["會稽新命剖魚符，又向蓬山鎖直廬。", "林壑縈迴多洞府，人煙高下半樓居。", "知音好採柯亭竹，博物應探禹穴書。", "公暇仙舟宜案部，鑑湖晴色照鄉閭。"]'),
('7332bafe-642c-41a5-9265-0e9a3a0f526e','句','陳知微','宋','宋诗','song-poetry','','[]','千重浪裏平安過，百尺竿頭穩下來。',16,'全唐诗/poet.song.5000.json','["千重浪裏平安過，百尺竿頭穩下來。"]'),
('f3e546ba-453d-4fc3-a3f7-2365b735a751','小孤山','陳從易','宋','宋诗','song-poetry','','[]','山稱孤獨字，廟塑女郎形。',24,'全唐诗/poet.song.5000.json','["山稱孤獨字，廟塑女郎形。", "過客雖知誤，行人但乞靈。"]'),
('38c6657a-647d-4597-9ce4-ff0e04211080','題北海','陳從易','宋','宋诗','song-poetry','','[]','聞道荆王廢池館，化爲徐湛好亭臺。',32,'全唐诗/poet.song.5000.json','["聞道荆王廢池館，化爲徐湛好亭臺。", "江山形勝周遭見，花木芬芳次第開。"]'),
('1a2e8935-748d-4b5a-ab61-490516e0fbcb','題華林書院','陳從易','宋','宋诗','song-poetry','','[]','世居江表卧烟霞，致政官資美莫加。',64,'全唐诗/poet.song.5000.json','["世居江表卧烟霞，致政官資美莫加。", "聖代旌門崇孝義，御書堆閣絕生涯。", "衣冠濟濟皆稽古，兒侄熙熙盡克家。", "我忝轉輸巡按暇，因留詩句記榮華。"]'),
('f1d89879-4ad1-4e2b-808b-cfe5d8807ab1','遊靈巖','富言','宋','宋诗','song-poetry','','[]','聞說靈巖境最幽，乘閒艤棹共追遊。',64,'全唐诗/poet.song.5000.json','["聞說靈巖境最幽，乘閒艤棹共追遊。", "飛泉翠滴半空雨，古樹陰連萬壑秋。", "縹緲香煙籠梵榻，嵯峨山勢枕江流。", "登臨眺望關河遠，惹起鄉思戀國愁。"]'),
('6f9e7211-61be-4db9-9565-682979816074','送交代秘丞歸闕','林渭夫','宋','宋诗','song-poetry','','[]','分携何必恨依依，三載無私得意歸。',64,'全唐诗/poet.song.5000.json','["分携何必恨依依，三載無私得意歸。", "煙雨乍隨孤棹去，鴛鴻重入九霄飛。", "舊題詩句刻文石，新創儒宮在翠微。", "後夜月明回首處，汀風蕭颯動行衣。"]'),
('7b453d39-f3d1-43d9-904e-10fb23aa2252','登高','陳絳','宋','宋诗','song-poetry','','[]','勸君莫辭滿酌酒，瑶林瓊木皆良友。',96,'全唐诗/poet.song.5000.json','["勸君莫辭滿酌酒，瑶林瓊木皆良友。", "就中此會難暫忘，一年兩經九月九。", "茱萸含香又滿頭，黄菊飄英再盈手。", "清歡未見玉山頹，高空任待金烏走。", "落帽聲名何足取，孟嘉一會登龍首。", "梅僊耳熱遺我詩，詩筆如椽膽如斗。"]'),
('8ec9accb-3334-4cf0-ac5d-522a4c639106','題董真人','張景','宋','宋诗','song-poetry','','[]','桃花謾說武陵源，誤教劉郎不得仙。',32,'全唐诗/poet.song.5000.json','["桃花謾說武陵源，誤教劉郎不得仙。", "爭似蓮花峰下客，栽成紅杏上青天。"]'),
('928ca8c4-c0a1-4704-813c-a35463f272bb','探梅','張景','宋','宋诗','song-poetry','','[]','跨蹇度溪橋，處處尋春信。',24,'全唐诗/poet.song.5000.json','["跨蹇度溪橋，處處尋春信。", "青枝攤蓓蕾，喚僕頻頻認。"]'),
('a7aebac2-4c46-4317-b752-58fd2d96ea27','詩一首','張景','宋','宋诗','song-poetry','','[]','我非東方兒，不是牛耕土。',24,'全唐诗/poet.song.5000.json','["我非東方兒，不是牛耕土。", "欲識我蹤跡，一氣萬物母。"]'),
('13e47c4e-6062-4b64-8580-4eeb6bef43d2','句  其一','張景','宋','宋诗','song-poetry','','[]','兩岸綠楊遮虎渡，一番青草覆龍洲。',16,'全唐诗/poet.song.5000.json','["兩岸綠楊遮虎渡，一番青草覆龍洲。"]'),
('350cf5e4-7537-48d2-bbb3-d2195f2d5b23','句  其二','張景','宋','宋诗','song-poetry','','[]','新粟米炊魚子飯，嫩冬瓜煮鱉魚裙。',16,'全唐诗/poet.song.5000.json','["新粟米炊魚子飯，嫩冬瓜煮鱉魚裙。"]'),
('f65846fe-7b50-494a-b237-7cdb2c6308ad','句  其三','張景','宋','宋诗','song-poetry','','[]','若以山形比人骨，此池應合似泥洹。',16,'全唐诗/poet.song.5000.json','["若以山形比人骨，此池應合似泥洹。"]'),
('1e24dd2f-000c-421b-ac30-f857e40a1e4c','早梅','劉元載妻','宋','宋诗','song-poetry','','[]','南枝向暖北枝寒，一種春風有兩般。',32,'全唐诗/poet.song.5000.json','["南枝向暖北枝寒，一種春風有兩般。", "憑仗高樓莫吹笛，大家留取倚闌干。"]'),
('d06b58df-5d0d-4ef6-8ddc-97be526acbc6','寄遠','詹茂光妻','宋','宋诗','song-poetry','','[]','錦江江上探春回，銷盡寒冰落盡梅。',32,'全唐诗/poet.song.5000.json','["錦江江上探春回，銷盡寒冰落盡梅。", "爭得兒夫似春色，一年一度一歸來。"]'),
('061cc464-ef96-460b-8be2-1dbd3d475038','惜別','趙晟母','宋','宋诗','song-poetry','','[]','暖有花枝冷有冰，佳人後會却無憑。',32,'全唐诗/poet.song.5000.json','["暖有花枝冷有冰，佳人後會却無憑。", "預愁離別苦相對，挑盡漁陽一夜燈。"]'),
('c42c5ac2-b724-43bc-ba19-11a43117c9a7','仙都山','柳紳','宋','宋诗','song-poetry','','[]','獨出諸峰表，周圍一丈圓。',48,'全唐诗/poet.song.5000.json','["獨出諸峰表，周圍一丈圓。", "千尋雄鎮地，萬仞上擎天。", "湖浪動星際，荷花生日邊。", "終當駕雲鶴，絕頂會神仙。"]'),
('8a4dd2fd-a5ce-4e3e-a0d7-3a48041041d3','五泄山三學院十題 五泄','釋咸潤','宋','宋诗','song-poetry','','[]','飛泉成五級，一級一龍湫。',24,'全唐诗/poet.song.5000.json','["飛泉成五級，一級一龍湫。", "削出萬仞秀，詎讓蓬萊丘。"]'),
('e29ca441-8ccd-4f1d-af5c-4220e49df7d9','五泄山三學院十題 西源','釋咸潤','宋','宋诗','song-poetry','','[]','造化鑿紳維，千巖鬭空碧。',24,'全唐诗/poet.song.5000.json','["造化鑿紳維，千巖鬭空碧。", "有時雲雨開，殘陽落幽石。"]'),
('aa2811a8-ce9a-4ce0-839d-4cd6fcc10de6','五泄山三學院十題 夾巖','釋咸潤','宋','宋诗','song-poetry','','[]','一徑數里間，巉巖鎮幽谷。',24,'全唐诗/poet.song.5000.json','["一徑數里間，巉巖鎮幽谷。", "中夾清溪流，白雲長斷續。"]'),
('358c50ec-3816-44f1-a431-764e6ba2f7e0','五泄山三學院十題 龍井','釋咸潤','宋','宋诗','song-poetry','','[]','寒井深無極，人謂藏虬龍。',24,'全唐诗/poet.song.5000.json','["寒井深無極，人謂藏虬龍。", "嘗聞救炎旱，絲雨灑長空。"]'),
('09425912-4065-4e74-a59b-e972c41ba816','五泄山三學院十題 石鼓','釋咸潤','宋','宋诗','song-poetry','','[]','巨石平如掌，天然狀鼙鼓。',24,'全唐诗/poet.song.5000.json','["巨石平如掌，天然狀鼙鼓。", "擊之還有聲，分明含太古。"]'),
('8231c40d-4f9e-43c2-a5ca-a59a42098e2f','五泄山三學院十題 石門','釋咸潤','宋','宋诗','song-poetry','','[]','雙峰起雲際，髣髴五侯門。',24,'全唐诗/poet.song.5000.json','["雙峰起雲際，髣髴五侯門。", "烟霞鎖不開，曾無車馬奔。"]'),
('68f21ece-26fa-4127-9090-78c2e5eaf4c2','五泄山三學院十題 石屏','釋咸潤','宋','宋诗','song-poetry','','[]','峭石狀危屏，截斷諸峰青。',24,'全唐诗/poet.song.5000.json','["峭石狀危屏，截斷諸峰青。", "白雲觸不飛，仙掌空遺名。"]'),
('72a8b473-8c25-4afd-9cbd-202b43f76e1b','五泄山三學院十題 俱胝巖','釋咸潤','宋','宋诗','song-poetry','','[]','昔人持此咒，巖坐歲寒深。',24,'全唐诗/poet.song.5000.json','["昔人持此咒，巖坐歲寒深。", "梵言不復聞，雅名流至今。"]'),
('191943ec-c9ba-47c8-9ab6-242abc434e82','五泄山三學院十題 禱雨潭','釋咸潤','宋','宋诗','song-poetry','','[]','嘗聞越邑民，禱雨碧巖畔。',24,'全唐诗/poet.song.5000.json','["嘗聞越邑民，禱雨碧巖畔。", "神龍如有期，爲霖通旱暵。"]'),
('52d25e0a-33c1-43ec-9338-40c01f3b025f','五泄山三學院十題 摘星巖','釋咸潤','宋','宋诗','song-poetry','','[]','捫蘿梯峭石，直上青雲端。',24,'全唐诗/poet.song.5000.json','["捫蘿梯峭石，直上青雲端。", "咫尺星斗光，冷射人心寒。"]'),
('04890eb4-24c6-48e4-95a6-ee69f0c984ac','受詔修書述懷感事三十韻','劉筠','宋','宋诗','song-poetry','','[]','良弼論思暇，英才視草餘。',288,'全唐诗/poet.song.5000.json','["良弼論思暇，英才視草餘。", "西清承密旨，東觀類羣書。", "左氏先經日，征南發例初。", "編年終顯德，歷帝自凡蘧。", "一覽無前古，三長豈後予。", "宏綱提要妙，至論絕籧篨。", "訛繆刊三豕，公乎喜衆狙。", "菁英咸采掇，疣贅盡銷除。", "組織千章合，研窮萬象虛。", "胡爲參也魯，亦造仲尼居。", "處末加駢拇，於中或輔車。", "乘軒思衛鶴，努力效劉馿。", "見彈曾求炙，臨川復羨魚。", "孰云貂可續，自愧鶚難如。", "早入希東郭，先知服子輿。", "直非頭似筆，智謝里名樗。", "蝸舍遊從寡，鶉衣禮貌疏。", "寸陰嗟荏苒，十駕敢躊躇。", "天祿楊雄閣，承明嚴助廬。", "時陪折俎宴，頓異带經鋤。", "繫日親函丈，他門絕曳裾。", "卓錐然有地，擔石尚無儲。", "獵犬方勞指，神龜可避漁。", "屠門誇大嚼，鼠壤鄙餘蔬。"]'),
('469a518c-3973-49ba-bfed-58f2447de42d','南朝','劉筠','宋','宋诗','song-poetry','','[]','華林酒滿勸長星，青漆樓高未稱情。',64,'全唐诗/poet.song.5000.json','["華林酒滿勸長星，青漆樓高未稱情。", "麝壁燈迴偏照晝，雀航波漲欲浮城。", "鐘聲但恐嚴粧晚，衣带那知敵國輕。", "千古風流佳麗地，盡供哀思與蘭成。"]'),
('ad7199e6-c0af-4e50-9456-884ff2f3b26f','禁中庭樹','劉筠','宋','宋诗','song-poetry','','[]','羽葉籠盤石，虬枝拂畫堂。',48,'全唐诗/poet.song.5000.json','["羽葉籠盤石，虬枝拂畫堂。", "夜聲含素瑟，曉影逼扶桑。", "好借鸞爲瑞，無容麝損香。", "寧知千載後，祇美召公棠。"]'),
('7bbca60b-0eb5-40ff-88f6-3d5095501685','休沐端居有懷希聖少卿學士','劉筠','宋','宋诗','song-poetry','','[]','䡾䡾風檐乳燕翔，浴蘭衣綌簟流黄。',64,'全唐诗/poet.song.5000.json','["䡾䡾風檐乳燕翔，浴蘭衣綌簟流黄。", "雲容倐變千峰險，草色相沿百带長。", "旋製紫荷供橐筆，暗移神蔡忍搘床。", "思君祇欲傾家釀，待警同誰賦栢梁。"]'),
('31dd3ce8-f666-433b-8a38-3f1ec6a4973b','槿花','劉筠','宋','宋诗','song-poetry','','[]','紫霧函燈檠，彤霞逼綺寮。',48,'全唐诗/poet.song.5000.json','["紫霧函燈檠，彤霞逼綺寮。", "吳宮何薄命，楚夢不終朝。", "半被曾羞問，鄰牆却悔招。", "莫移風雨怨，更囑鵲爲橋。"]'),
('e6ed3f77-2c31-494f-90b7-4302639d1cb2','代意','劉筠','宋','宋诗','song-poetry','','[]','華池阿閣不相容，濁水清塵恨莫窮。',64,'全唐诗/poet.song.5000.json','["華池阿閣不相容，濁水清塵恨莫窮。", "明月自新班女扇，行雲無柰楚王風。", "乳鶑啼曉銷蘭炷，媚蝶傷春失蕙叢。", "縱使多才如子建，祇能援筆賦驚鴻。"]'),
('33af3d90-ef03-4987-8944-57a3b5887298','漢武','劉筠','宋','宋诗','song-poetry','','[]','漢武高臺切絳河，半涵非霧鬰嵯峨。',64,'全唐诗/poet.song.5000.json','["漢武高臺切絳河，半涵非霧鬰嵯峨。", "桑田欲看他年變，瓠子先成此日歌。", "夏鼎幾遷空象物，秦橋未就已沉波。", "相如作賦徒能諷，却助飄飄逸氣多。"]'),
('8db152b0-ec77-4585-b426-52af3093970a','館中新蟬','劉筠','宋','宋诗','song-poetry','','[]','庭中嘉樹發華滋，可要螳螂共此時。',64,'全唐诗/poet.song.5000.json','["庭中嘉樹發華滋，可要螳螂共此時。", "翼薄乍舒宮女鬢，蛻輕全解羽人尸。", "風來玉女烏先轉，露下金莖鶴未知。", "日永聲長兼夜思，肯容潘岳到秋悲。"]'),
('9d33e2cb-dec8-49f5-a864-ed0eab708fe6','夜讌','劉筠','宋','宋诗','song-poetry','','[]','玳押風簾薄，金徒漏箭長。',120,'全唐诗/poet.song.5000.json','["玳押風簾薄，金徒漏箭長。", "食魚齊上客，置醴漢元王。", "蒟醤辛初和，蓱齏冷乍嘗。", "巢笙傳曲沃，摻鼓發漁陽。", "吟燭惟憂盡，杯籌豈易防。", "齒犀融晏雪，袍麝薦荀香。", "笑逐呼盧勝，歌隨解佩狂。", "遺簪兼墮珥，流眄復回腸。", "綵鳳尋仙史，班騅待陸郎。", "主歡殊未已，投轄在銀床。"]'),
('ca5f9a2c-9c5c-47ed-8ed7-b434d949c1dc','鶴','劉筠','宋','宋诗','song-poetry','','[]','碧樹陰濃釦砌平，華亭歸夢曉頻驚。',64,'全唐诗/poet.song.5000.json','["碧樹陰濃釦砌平，華亭歸夢曉頻驚。", "仙經若未標奇相，琴操何因寄恨聲。", "養氣自憐雞善勝，全身却許雁能鳴。", "芝田玉水春雲伴，可得乘軒是所榮。"]'),
('5ad24153-3051-4ba0-8c12-c47ddf70f38c','公子','劉筠','宋','宋诗','song-poetry','','[]','油壁春車隔渭橋，黄山路遠苦相邀。',64,'全唐诗/poet.song.5000.json','["油壁春車隔渭橋，黄山路遠苦相邀。", "行庖爨蠟雕胡熟，永埒鋪金汗血驕。", "別館橫陳張靜婉，期門長揖霍嫖姚。", "注鉤握槊曾無憚，綠桂膏濃曉未銷。"]'),
('3a2d6f6d-29cf-4039-8ca4-65e4410a7458','舊將','劉筠','宋','宋诗','song-poetry','','[]','丈八蛇矛戰血乾，子孫今已列材官。',64,'全唐诗/poet.song.5000.json','["丈八蛇矛戰血乾，子孫今已列材官。", "青烟碧瓦開新第，白草黄雲廢舊壇。", "勞薄可甘先藺舌，爵高還許戴劉冠。", "秋來從獵長楊榭，矍鑠猶能一據鞍。"]'),
('8df24ed3-3f95-4e7a-96a6-654c164c72f1','宣曲二十二韻','劉筠','宋','宋诗','song-poetry','','[]','八月收民算，三千異典章。',288,'全唐诗/poet.song.5000.json','["八月收民算，三千異典章。", "天機從此淺，國艷或非良。", "玉戶銅爲沓，羅幬象作床。", "驪姬初悔泣，飛燕近專房。", "蓮小纔承步，梅新競試粧。", "盡知春可樂，終歎夜何長。", "取酒臨邛遠，吞聲息國亡。", "難銷守宮血，易斷舞鸞腸。", "百草兼花鬭，雙鈎映燭藏。", "金人須手鑄，虎圈更身當。", "步輦回長樂，飛除接未央。", "琳珉飾漢館，藻繡裛周牆。", "厭火雙魚尾，鳴弦小雁行。", "雲甍澄顥氣，綺井激回光。", "路有斯須隔，憂難頃刻忘。", "新聲來樂府，別寢近溫湯。", "虹跨層臺晚，螢飛下苑凉。", "錦帷迎七夕，蓬餌薦重陽。", "九畹蘭承露，三江橘带霜。", "方資裂繒笑，可要蕩舟狂。", "並釣池魚小，重衾穴鳳翔。", "珊瑚分碧樹，火齊列清防。", "背枕多幽怨，登樓更遠傷。", "下陳無自愧，人彘劇豺狼。"]'),
('cfb95a40-faff-4036-8a62-b807c7c61a9e','赤日','劉筠','宋','宋诗','song-poetry','','[]','芒熛盛德正渾儀，休問探湯向小兒。',64,'全唐诗/poet.song.5000.json','["芒熛盛德正渾儀，休問探湯向小兒。", "盡日羽陵開蠹簡，幾人河朔引芳巵。", "堯厨萐莆頻摇處，漢殿相風未轉時。", "爭得琴高借雙鯉，暫遊姑射對冰姿。"]'),
('1729d7c1-f6fe-4392-8cbb-eef7139fcd3d','明皇','劉筠','宋','宋诗','song-poetry','','[]','歲歲南山見壽星，百蠻迴首奉威靈。',64,'全唐诗/poet.song.5000.json','["歲歲南山見壽星，百蠻迴首奉威靈。", "梨園法部兼胡部，玉輦長亭復短亭。", "河鼓暗期隨日轉，馬嵬恨血染塵腥。", "西歸重按凌波舞，故老相看但涕零。"]'),
('5549f165-57c9-474c-9fd4-54a55fe8658e','別墅','劉筠','宋','宋诗','song-poetry','','[]','感概復風流，交通徧五侯。',96,'全唐诗/poet.song.5000.json','["感概復風流，交通徧五侯。", "鳴鐘平樂宴，擊鞠茂陵游。", "狡兔方多穴，蒼鷹始下韝。", "鈴奴藏廣柳，劍騎騁長楸。", "雲際尋橦技，花間笑躄樓。", "害先除白額，夢已應黄頭。", "燕酒惟增氣，秦箏漫送愁。", "鴻毛輕一死，祇待報私讎。"]'),
('d7ad1c93-7b0e-4486-bc67-429056277147','無題三首  其一','劉筠','宋','宋诗','song-poetry','','[]','走馬章臺冒雨歸，後門猶歎滯前期。',64,'全唐诗/poet.song.5000.json','["走馬章臺冒雨歸，後門猶歎滯前期。", "荷心出水終無定，蘿蔓從風莫自持。", "複帳麝輕難辟惡，曲房蠶懶不成絲。", "漸漸壠麥藏鳴雉，更恨如皋一箭遲。"]'),
('acf9266e-5f84-4f27-843c-738c6ed9c744','無題三首  其二','劉筠','宋','宋诗','song-poetry','','[]','簾聲竹影浪多疑，仙穀何能爲解迷。',64,'全唐诗/poet.song.5000.json','["簾聲竹影浪多疑，仙穀何能爲解迷。", "藻井風高蛛壞網，杏梁春晚燕爭泥。", "更看山遠惟凝黛，縱許犀靈祇駭雞。", "枉裂霜繒幾千尺，紅蘭終夕露珠啼。"]'),
('dd79dc01-364c-4389-bb12-d3d38a4d5db8','無題三首  其三','劉筠','宋','宋诗','song-poetry','','[]','麝裂初難和，烏驚每易傷。',72,'全唐诗/poet.song.5000.json','["麝裂初難和，烏驚每易傷。", "蕩舟殊不禁，奔月可能防。", "洛浦多遺翠，秦樓滯采桑。", "飛蛾攢釦燭，綠鴨鬭銀塘。", "夜合花含霧，宜男草带霜。", "琅玕餘舊貫，須要鳳求皇。"]'),
('c289eedd-9371-49c2-b396-07d7cfda0d99','荷花','劉筠','宋','宋诗','song-poetry','','[]','水國開良宴，霞天湛晚暉。',72,'全唐诗/poet.song.5000.json','["水國開良宴，霞天湛晚暉。", "凌波宓妃至，盪槳莫愁歸。", "粧淺休啼臉，香清願襲衣。", "即時聞鼓瑟，他日問支機。", "繡騎翩翩過，珍禽兩兩飛。", "牢收交甫佩，莫遣此心違。"]'),
('8dce93fa-6012-40e0-98c0-a6be8f412fe2','再賦','劉筠','宋','宋诗','song-poetry','','[]','暮雨過湘渚，微凉滿楚宮。',72,'全唐诗/poet.song.5000.json','["暮雨過湘渚，微凉滿楚宮。", "濺裙無限水，障袂幾多風。", "浪跡嫌萍實，塵勞笑菊叢。", "氣清防麝損，信密待魚通。", "游女歌爭發，騷人思未窮。", "休傳江北意，月冷魏池空。"]'),
('a8c8af3a-05c4-4b7f-9b07-f477fcec2677','再賦七言','劉筠','宋','宋诗','song-poetry','','[]','紉蘭爲佩桂爲舟，北渚雲飛發櫂謳。',64,'全唐诗/poet.song.5000.json','["紉蘭爲佩桂爲舟，北渚雲飛發櫂謳。", "已有萬絲能結怨，不須千蓋强障羞。", "金隄勃窣誰同上，翠帟繽紛客自留。", "欲選浣紗傾敵國，越王更起近江樓。"]'),
('f9a9a393-2c08-4e19-acae-85350c9c118a','又贈一絕','劉筠','宋','宋诗','song-poetry','','[]','粉白朱紅翡翠翹，漢宮等級不相饒。',32,'全唐诗/poet.song.5000.json','["粉白朱紅翡翠翹，漢宮等級不相饒。", "風波若未乖前約，一死何辭更抱橋。"]'),
('3a06ced0-18d2-4f6b-b665-7cb43732b6ac','梨','劉筠','宋','宋诗','song-poetry','','[]','玄光仙樹阻丹梯，御宿嘉名近可齊。',64,'全唐诗/poet.song.5000.json','["玄光仙樹阻丹梯，御宿嘉名近可齊。", "真定早寒霜葉薄，樊川初曉露枝低。", "先時櫻熟煩羊酪，遠信梅酸損瓠犀。", "宋玉有情終未識，蔗漿無柰楚魂迷。"]'),
('7f775de2-c8cf-4afd-be31-32a75cc39bb2','淚二首  其一','劉筠','宋','宋诗','song-poetry','','[]','雍門琴罷已浪浪，更上牛山半夕陽。',64,'全唐诗/poet.song.5000.json','["雍門琴罷已浪浪，更上牛山半夕陽。", "楚澤雲迷千里目，薊門歌斷九迴腸。", "寒梅带雨飄離席，尺素停燈作報章。", "湘水乾未終未盡，豈徒萬點寄疏篁。"]'),
('eb3c7258-e2f8-4f80-96c7-3aceb2ea7c09','淚二首  其二','劉筠','宋','宋诗','song-poetry','','[]','含酸茹歎幾傷神，嗚咽交流忽滿巾。',64,'全唐诗/poet.song.5000.json','["含酸茹歎幾傷神，嗚咽交流忽滿巾。", "建業江山非故國，灞陵風雨又殘春。", "虞歌决別知亡楚，宴酒初酣待報秦。", "欲斷青天銷積恨，月娥孀獨更愁人。"]'),
('a9fd0578-f637-4c9b-b4fd-23501d6ea0f9','七夕','劉筠','宋','宋诗','song-poetry','','[]','靈匹迢迢駕七襄，暫陳雲幄對星潢。',64,'全唐诗/poet.song.5000.json','["靈匹迢迢駕七襄，暫陳雲幄對星潢。", "已看素魄過三讓，何用華燈更九光。", "玉腕雙絲輕宛轉，霞衣雜佩暗丁當。", "誰言巧意能勝拙，祇見鳩閑鵲自忙。"]'),
('0d777f62-f6ad-4156-bb25-54a36a971cec','成都','劉筠','宋','宋诗','song-poetry','','[]','鏤膚剽俗恣遊遨，可得蹲鴟號富饒。',64,'全唐诗/poet.song.5000.json','["鏤膚剽俗恣遊遨，可得蹲鴟號富饒。", "井絡共知天與險，蠶叢無柰世興妖。", "杜鵑積恨花如血，諸葛遺靈柏半燒。", "才似文園何足道，一生琴意祇成痟。"]'),
('20d1a718-a6b6-40be-92da-297810d8f590','秋夜對月','劉筠','宋','宋诗','song-poetry','','[]','瑶席留歡友，金波對廣庭。',96,'全唐诗/poet.song.5000.json','["瑶席留歡友，金波對廣庭。", "重簾和霧卷，六幕極天青。", "屬玉東西館，琉璃左右屏。", "梁園休賦雪，隋苑漫飛螢。", "蟾滴全供硯，牛津不見星。", "綺窗分皎皎，苔閣共亭亭。", "已喪應劉魄，誰通鮑謝靈。", "欲銷千里恨，魯酒薄還醒。"]'),
('2b71d2e5-a7bd-4018-b759-0bb97679abd9','前檻十二韻','劉筠','宋','宋诗','song-poetry','','[]','垂柳陰岑院，游絲曠蕩春。',144,'全唐诗/poet.song.5000.json','["垂柳陰岑院，游絲曠蕩春。", "蘅皋誰駐馬，羅襪自生塵。", "四姓良家子，三年賦客鄰。", "折腰行太緩，連瑣語何頻。", "倭墮雲爭媚，便娟月鬭新。", "滅瘢難辨玉，約指不勝銀。", "電笑投壺勝，江澄擣練勻。", "東南勞鶴望，西北限牛津。", "寶唾凝蘭氣，鳴黄咽絳脣。", "籠禽思隴樹，洞犬謝秦人。", "詠絮才無對，聞琴意始真。", "長安足輕薄，慎勿走瓊輪。"]'),
('9b725ed4-8e16-4184-86af-476a86b6d0fe','小園秋夕','劉筠','宋','宋诗','song-poetry','','[]','枳落莎渠急夜蟲，翛然平子四愁中。',64,'全唐诗/poet.song.5000.json','["枳落莎渠急夜蟲，翛然平子四愁中。", "栗林忽感雕陵鵲，雲表初過代嶺鴻。", "阮籍卧惟疏鑒月，馬融橫笛遠含風。", "郎潛吏隠前賢事，猶勝楊岐泣斷蓬。"]'),
('faafcc73-46d5-4a2f-a8c0-a1f792fd8bad','始皇','劉筠','宋','宋诗','song-poetry','','[]','利觜由來得擅場，盡遷豪富入咸陽。',64,'全唐诗/poet.song.5000.json','["利觜由來得擅場，盡遷豪富入咸陽。", "屬車夜出迷雲雨，峻令朝行劇虎狼。", "前殿建旗凌紫極，東門立石見扶桑。", "從臣嘉頌徒虛美，不柰盧生讖國亡。"]'),
('69ab9c36-a7f5-45f8-99b7-819792ee9004','初秋屬疾','劉筠','宋','宋诗','song-poetry','','[]','秋陰凄淡隔重城，一畝居仍近禁營。',64,'全唐诗/poet.song.5000.json','["秋陰凄淡隔重城，一畝居仍近禁營。", "漢苑樓臺沉暮影，謝家鼓吹發新聲。", "烟昏露井殘桃墜，葉下凉波獨鳥驚。", "節物變衰吟更苦，可堪漳浦卧劉楨。"]'),
('95d8fdce-eff1-49f6-9b7c-66a44c11d22e','寄靈仙觀舒職方學士','劉筠','宋','宋诗','song-poetry','','[]','石渠仙署久離羣，抗跡丹臺世絕倫。',64,'全唐诗/poet.song.5000.json','["石渠仙署久離羣，抗跡丹臺世絕倫。", "楊子不甘嘲尚白，漆園終許自全真。", "紫烟深處鸞雙舞，朱髓成來鳥共伸。", "若向雲中見雞犬，可能渾忘姓劉人。"]'),
('deacb244-2a69-4e62-9a60-8977e5ad3faf','宋玉','劉筠','宋','宋诗','song-poetry','','[]','楚國驕荒日已深，山川朝暮劇登臨。',64,'全唐诗/poet.song.5000.json','["楚國驕荒日已深，山川朝暮劇登臨。", "曾傷積毀亡師道，祇託微辭蕩主心。", "江草東西多恨色，峽雲高下結層陰。", "潘郎千載聞遺韻，又說經秋思不任。"]'),
('b22bf136-3d85-4079-9600-382a744f7ef8','送客不及  其一','劉筠','宋','宋诗','song-poetry','','[]','青門祖帳曙烟微，片席乘流鳥共飛。',64,'全唐诗/poet.song.5000.json','["青門祖帳曙烟微，片席乘流鳥共飛。", "曲岸馬嘶風嫋嫋，短亭人散柳依依。", "灞陵目斷猶回望，楚水魂銷爲送歸。", "祇自河梁傳怨曲，洛塵千古化征衣。"]'),
('889cc3f1-c29b-4ed2-b2ef-f12e27508c9e','送客不及  其二','劉筠','宋','宋诗','song-poetry','','[]','日上旗亭第五重，百壺春釀與誰同。',64,'全唐诗/poet.song.5000.json','["日上旗亭第五重，百壺春釀與誰同。", "黄山遠隔奔霽騎，紫塞孤飛避弋鴻。", "湘竹幾時休染淚，楚旌終日自摇風。", "此情不及歌楊柳，一尺魚書萬水中。"]'),
('41307203-1aa1-4df1-894b-e8a2598a45a8','夕陽','劉筠','宋','宋诗','song-poetry','','[]','夕陽堪極目，況復近秋殘。',48,'全唐诗/poet.song.5000.json','["夕陽堪極目，況復近秋殘。", "塞逈橫烟紫，江清照葉丹。", "伍胥嗟路遠，潘子念行難。", "更有蕪城恨，城空逼夜寒。"]'),
('63bc7c75-5ea9-4181-9b1f-0c426c503fb1','樞密王左丞宅新菊','劉筠','宋','宋诗','song-poetry','','[]','東閣留嘉客，寒葩艷晚光。',96,'全唐诗/poet.song.5000.json','["東閣留嘉客，寒葩艷晚光。", "秋風自蕭瑟，台座對熒煌。", "麗奪雙南價，清含九畹香。", "嵰州霜薦味，太液鵠分裳。", "已助蜂成蜜，還隨蟻泛觴。", "俯臨輝艾綬，佩服間萸房。", "節物傳荆俗，詩情掩謝塘。", "更期松偃蓋，永奉太清方。"]'),
('03e19f2a-db1d-479d-8cc9-1e778c7d420f','直夜','劉筠','宋','宋诗','song-poetry','','[]','鷄人肅唱發章溝，漢殿重重虎戟稠。',64,'全唐诗/poet.song.5000.json','["鷄人肅唱發章溝，漢殿重重虎戟稠。", "綷羽欲棲溫室樹，金波先上結麟樓。", "風來太液聞鳴鶴，霧卷銀河見飲牛。", "萬國表章頻奏瑞，手批天語思如流。"]'),
('b569a270-fde2-4b3a-b51a-cd21cb002362','洞戶','劉筠','宋','宋诗','song-poetry','','[]','百尺青樓大道邊，五陵遊騎驍翩翩。',64,'全唐诗/poet.song.5000.json','["百尺青樓大道邊，五陵遊騎驍翩翩。", "不思夜魄過三五，祇問春醪賞十千。", "密鎖香雲深處戶，亂飄梨雪晚來天。", "愁眉豈待歌成慘，咫尺河陽信未傳。"]'),
('e0b917ed-7a8a-4d56-8abe-a7200e8857bd','柳絮','劉筠','宋','宋诗','song-poetry','','[]','半減依依學轉蓬，班騅無柰恣西東。',64,'全唐诗/poet.song.5000.json','["半減依依學轉蓬，班騅無柰恣西東。", "平沙千里經春雪，廣陌三條盡日風。", "北斗城高連蠛蠓，甘泉樹密蔽青葱。", "漢家舊苑眠應足，豈覺黄金萬縷空。"]'),
('14d5fe89-f930-42e6-91ad-16d79b9a3d28','與客啟明','劉筠','宋','宋诗','song-poetry','','[]','秦痔從來易得車，郄枝今比我何如。',64,'全唐诗/poet.song.5000.json','["秦痔從來易得車，郄枝今比我何如。", "垂天借喻齊諧志，握火尋盟越絕書。", "旭日西清雲幄密，朔風南陌葦衣疏。", "故山夜鶴空多怨，金屋人爭誦子虛。"]'),
('41b6b5ba-f09f-426a-a7ec-fdee1b65b0e1','譯經光梵大師','劉筠','宋','宋诗','song-poetry','','[]','漢夢通西域，逍遥廣舊園。',72,'全唐诗/poet.song.5000.json','["漢夢通西域，逍遥廣舊園。", "竺乾方演教，金粟豈忘言。", "硯滴寒蟾吐，臺香瑞獸噴。", "揮毫花滿裓，隠几雪盈門。", "大士清歌發，南宗密印存。", "縱橫十二部，慧日破重昏。"]'),
('791c4dff-a8c4-4df5-96fa-f97b041fe30e','霜月','劉筠','宋','宋诗','song-poetry','','[]','霜曉月仍殘，桐疏鳳更單。',48,'全唐诗/poet.song.5000.json','["霜曉月仍殘，桐疏鳳更單。", "已傷春寂寂，還踏夜漫漫。", "凍合仙槎路，薰餘侍史蘭。", "那知荀奉倩，體薄不勝寒。"]'),
('c8cd66a8-96ab-432e-81bb-07448e6a515a','此夕','劉筠','宋','宋诗','song-poetry','','[]','南州石黛有遺妍，目極危梯月上弦。',64,'全唐诗/poet.song.5000.json','["南州石黛有遺妍，目極危梯月上弦。", "一水相忘空脈脈，雙金何路致拳拳。", "仙源日永桃無援，客館春輕柳未眠。", "欲寫微詞託歸雁，風高嶺闊又經年。"]'),
('55ef82ec-6b5a-488c-8a03-5c316beb5b73','劉校理屬疾','劉筠','宋','宋诗','song-poetry','','[]','撫枕凄然掩北軒，漢庭誰問馬文園。',64,'全唐诗/poet.song.5000.json','["撫枕凄然掩北軒，漢庭誰問馬文園。", "風簷鴟嘯厨烟絕，月樹烏驚藥杵喧。", "戲習五禽成妙術，學虧一簣阻微言。", "不因九奏清塵耳，天露應迷簡子魂。"]'),
('cd15dcd7-25fd-4c86-9205-8f4dc670c87b','勸石集賢飲','劉筠','宋','宋诗','song-poetry','','[]','豪家抱甕擅風流，更燎薰鑪白雪樓。',64,'全唐诗/poet.song.5000.json','["豪家抱甕擅風流，更燎薰鑪白雪樓。", "魯筆休分科斗字，蜀都且換鷫鸘裘。", "仰天拊髀真爲樂，倒載穿腸肯易愁。", "欲鱠長鯨置雕俎，願迴北斗挹東流。"]'),
('d539d304-5dd6-4857-a961-3d8125b2ac5d','即日','劉筠','宋','宋诗','song-poetry','','[]','地僻無車轍，心灰欲坐忘。',48,'全唐诗/poet.song.5000.json','["地僻無車轍，心灰欲坐忘。", "疾雷徒破柱，幽草不迎凉。", "日烈蟬遺蛻，花休蜜滿房。", "覆觴知已久，寧有次公狂。"]'),
('3f6a63b0-2823-4241-9b7c-4e9e1e89b497','燈夕寄獻內翰虢略公','劉筠','宋','宋诗','song-poetry','','[]','千輪佛火照層城，九陌香車擊迅霆。',64,'全唐诗/poet.song.5000.json','["千輪佛火照層城，九陌香車擊迅霆。", "簡子最知天帝樂，孟家惟信紫姑靈。", "金徒抱箭催壺水，玉宇來風滿砌蓂。", "簾卷交疏蓮燭密，通中枕上獨聞鈴。"]'),
('b615909b-49f4-4c77-bb87-ee122defc26e','李舍人獨直','劉筠','宋','宋诗','song-poetry','','[]','卿靄重重覆璧門，獨揮鴻筆坐西垣。',64,'全唐诗/poet.song.5000.json','["卿靄重重覆璧門，獨揮鴻筆坐西垣。", "誠明自有中和氣，潤色還多郁穆言。", "內苑朱櫻兼酪賜，前階紅藥任風翻。", "紫絲新履徊翔地，應笑東方避世喧。"]'),
('bb7e5a2a-ecbd-4c3f-bccf-43cab1b0023a','無題二首  其一','劉筠','宋','宋诗','song-poetry','','[]','曾許千金答浣紗，越溪浪淺不通槎。',64,'全唐诗/poet.song.5000.json','["曾許千金答浣紗，越溪浪淺不通槎。", "曉樓簾卷還凝霧，外院牆低却映花。", "滿目離愁頻駐馬，一春幽夢祇驚鴉。", "柔桑蔽日南城路，懊惱羅敷自有家。"]'),
('f77f1f4e-3d5f-4ac0-83cc-831b0f051e79','無題二首  其二','劉筠','宋','宋诗','song-poetry','','[]','昱爚銀鞍狹路逢，長裙連带任流風。',64,'全唐诗/poet.song.5000.json','["昱爚銀鞍狹路逢，長裙連带任流風。", "身輕近識吳宮燕，目斷還驚洛浦鴻。", "未許香囊安肘後，獨憐丹枕在房中。", "南園蝴蝶飛無限，一一雌隨一一雄。"]'),
('126f6e64-abbe-4daa-ba0c-17203d761b4f','懷舊居','劉筠','宋','宋诗','song-poetry','','[]','毛竹千叢蔽野亭，曉猨驚後亂峰青。',64,'全唐诗/poet.song.5000.json','["毛竹千叢蔽野亭，曉猨驚後亂峰青。", "漢庭已奏三千牘，周室仍繙十二經。", "紫殿深沉頻視草，緇帷寂寞自飛螢。", "振衣本爲蒼生起，肯向荀家祇聚星。"]'),
('413f89f4-3e23-4636-babf-95360de1939c','偶懷','劉筠','宋','宋诗','song-poetry','','[]','不才甘客難，多病豈旬休。',48,'全唐诗/poet.song.5000.json','["不才甘客難，多病豈旬休。", "可待乘軒寵，終慚舐痔求。", "渚蘭薰露夕，江橘富霜秋。", "養拙寧無地，千波一葉舟。"]'),
('40ff1f99-59b6-48ed-b71e-2f48c075a672','許洞歸吳中','劉筠','宋','宋诗','song-poetry','','[]','欲折瑶華向綠疇，風光滿目盡離愁。',64,'全唐诗/poet.song.5000.json','["欲折瑶華向綠疇，風光滿目盡離愁。", "茂林修竹多嘉客，萬壑千巖憶舊遊。", "漢詔已聞求泛駕，禰狂無自屈岑牟。", "荆山待價何憂晚，龜手猶期裂地酬。"]'),
('3e81e1b0-ff49-45ca-b92e-e87110617ddd','上巳玉津園賜宴','劉筠','宋','宋诗','song-poetry','','[]','需雲分渥澤，禊飲恣歡游。',72,'全唐诗/poet.song.5000.json','["需雲分渥澤，禊飲恣歡游。", "緹幕侵晨設，蘭泉對席流。", "蕙肴清萐莆，玉醴湛金甌。", "春服萋萋盛，光風灧灧浮。", "桐華穠競發，鶑語巧相求。", "妙曲新聲合，斜陽醉未休。"]'),
('5c883783-1b08-4ce0-9b96-1f0b1b3ea2ad','致齋太一宮','劉筠','宋','宋诗','song-poetry','','[]','紫館天神貴，綸闈地望清。',120,'全唐诗/poet.song.5000.json','["紫館天神貴，綸闈地望清。", "齋心奉蠲潔，攝事罄誠明。", "殿翼如軒翥，壇垓類削成。", "直官琳札密，太宰繡衣輕。", "薜荔羅芳席，虹蜺曳綵旌。", "星陳五帝佐，體薦一元牲。", "蒼駟回風馭，珍禽驚露聲。", "丹霞升曉氣，若木競新英。", "挹袂寧無友，凌霄自放情。", "受釐宣室對，賈傅異諸生。"]'),
('6b9162f9-94c8-4426-9c74-1e2e8e4a47c9','直夜二首  其一','劉筠','宋','宋诗','song-poetry','','[]','瓊蘂滋晨飲，青縑擁夜衾。',48,'全唐诗/poet.song.5000.json','["瓊蘂滋晨飲，青縑擁夜衾。", "萬年宮省樹，五色帝家禽。", "詔草裁蕂角，薰爐燼水沉。", "浴堂還獨對，鳴佩有清音。"]'),
('276a194a-fe04-4ea2-a0e8-b3a086e10013','直夜二首  其二','劉筠','宋','宋诗','song-poetry','','[]','嘉木清陰接綺窗，謫仙風骨凜冰霜。',64,'全唐诗/poet.song.5000.json','["嘉木清陰接綺窗，謫仙風骨凜冰霜。", "堯厨萐莆分珍膳，漢廟含桃和酪漿。", "磴道神行通碣石，井幹雲構俯瑶光。", "金釭璧月相輝映，獸口時飄侍史香。"]'),
('196e9a82-7b8d-4bbc-9300-c344257dc3e3','櫻桃','劉筠','宋','宋诗','song-poetry','','[]','赤水分珠樹，薰風送麥秋。',72,'全唐诗/poet.song.5000.json','["赤水分珠樹，薰風送麥秋。", "蜀都春氣早，漢苑夏陰稠。", "廟薦清和候，恩頒侍從流。", "楚昭萍已剖，韓嫣彈爭投。", "沆瀣滋芳液，醍醐助品羞。", "玉盤光宛轉，全擬付歌喉。"]'),
('05c82af3-8745-4132-94bd-fcad568e0818','暑詠寄梅集賢','劉筠','宋','宋诗','song-poetry','','[]','石渠岌嶪亙宛虹，玄蔭清流接桂宮。',64,'全唐诗/poet.song.5000.json','["石渠岌嶪亙宛虹，玄蔭清流接桂宮。", "玉女壺欹天未笑，羲和轡緩日方中。", "孝先便腹寧無誚，痀僂承蜩敢衒功。", "蠲渴欲來飛雪散，南昌世胄有仙風。"]'),
('7d7c6f4b-dc7a-466c-b046-ce41f8151aa4','苦熱','劉筠','宋','宋诗','song-poetry','','[]','六幕雲收萬籟沉，結瑶千尺倦登臨。',64,'全唐诗/poet.song.5000.json','["六幕雲收萬籟沉，結瑶千尺倦登臨。", "七盤妙舞頻揮汗，五色嘉瓜冷鎮心。", "極目嶺梅寧止渴，拂波宮柳漫垂陰。", "祇憂火解神仙骨，頼有泉聲發素琴。"]'),
('45c19d0d-8de5-455a-8994-b3c049f89bad','屬疾','劉筠','宋','宋诗','song-poetry','','[]','暫困秦王痔，無疑廣客蛇。',96,'全唐诗/poet.song.5000.json','["暫困秦王痔，無疑廣客蛇。", "職清唐內相，宅僻魯東家。", "行藥虹梁闊，披襟蕙徑斜。", "香凝虛白室，露泫紫微花。", "冰飲何嘗熱，瓊餐益自嘉。", "熊經仙有術，龜息壽無涯。", "珍簟裁湘竹，輕巾覆越紗。", "逍遥成雅詠，屬和肯容巴。"]'),
('cac7a111-1538-4e91-bd80-7512091717f3','清風十韻','劉筠','宋','宋诗','song-poetry','','[]','閶闔重門啟，飛簾別館深。',120,'全唐诗/poet.song.5000.json','["閶闔重門啟，飛簾別館深。", "歊蒸全已却，雅興可能任。", "雲起汾河詠，旌摇楚國心。", "過簫添爽籟，拂野蕩層陰。", "夕勁淮陽桂，晨凄越鄂衾。", "登高從落帽，安寢任吹襟。", "珠網疏難掩，銅鑄冷易侵。", "急翻池上葉，遥送月前砧。", "舞袖更回態，歌梁極緒音。", "最憐鵰鶚意，瞬息度千岑。"]'),
('e8b6ae1f-1b8a-4263-a275-077e4c4e70bd','戊申年七夕五絕  其一','劉筠','宋','宋诗','song-poetry','','[]','伯勞東翥燕西飛，又報黄姑織女期。',32,'全唐诗/poet.song.5000.json','["伯勞東翥燕西飛，又報黄姑織女期。", "天帝聘錢還得否，晉人求富是虛辭。"]'),
('10593994-34d9-4f14-8b74-b504be823251','戊申年七夕五絕  其二','劉筠','宋','宋诗','song-poetry','','[]','華寢星陳夜未央，明河奕奕度神光。',32,'全唐诗/poet.song.5000.json','["華寢星陳夜未央，明河奕奕度神光。", "一年暫得停機杼，不柰秋蟲促織忙。"]'),
('71fbc56c-3810-4dd1-b848-66c21b3bbb04','戊申年七夕五絕  其三','劉筠','宋','宋诗','song-poetry','','[]','吹笙何處伴乘鸞，窺牖誰人見阿環。',32,'全唐诗/poet.song.5000.json','["吹笙何處伴乘鸞，窺牖誰人見阿環。", "便有唐家今夕意，月和風露滿驪山。"]'),
('14ea3eb2-73f6-471c-bbf7-5bac90715cd7','戊申年七夕五絕  其四','劉筠','宋','宋诗','song-poetry','','[]','淅淅風微素月新，鵲橋橫絕飲牛津。',32,'全唐诗/poet.song.5000.json','["淅淅風微素月新，鵲橋橫絕飲牛津。", "豈惟蜀客知蹤跡，更問庭中曬腹人。"]'),
('e6ff5620-1ea7-48b4-b693-9279fd5ebaf8','戊申年七夕五絕  其五','劉筠','宋','宋诗','song-poetry','','[]','琥車芝駕儼清秋，微雨侵宵助涕流。',32,'全唐诗/poet.song.5000.json','["琥車芝駕儼清秋，微雨侵宵助涕流。", "人世莫嗟離恨苦，却應天上更悠悠。"]'),
('b9e432e4-7388-42d9-b72f-36626f565de6','偶作','劉筠','宋','宋诗','song-poetry','','[]','殺青和墨度流年，飽食無功鬢颯然。',64,'全唐诗/poet.song.5000.json','["殺青和墨度流年，飽食無功鬢颯然。", "却憶侯封安邑棗，不能兄事魯褒錢。", "千峰月白猿啼樹，六幕風高鶚在天。", "招隠詩成誰擊節，願傾家釀載漁船。"]'),
('a4b8db84-7682-40b5-86c4-efa84fb65742','螢','劉筠','宋','宋诗','song-poetry','','[]','荒郊多腐草，故苑近清秋。',72,'全唐诗/poet.song.5000.json','["荒郊多腐草，故苑近清秋。", "棘密何勝數，囊輕莫盡收。", "月高疑爝息，天遠認星流。", "紫桂風微急，紅蘭露徧浮。", "已能穿永巷，更欲拂高樓。", "滅燭方無寐，鳴蛩相薦愁。"]'),
('297377d6-b9ab-4f3b-9810-f49e4a34fa7e','淮水暴漲舟中有作','劉筠','宋','宋诗','song-poetry','','[]','行行極目天無柱，渺渺橫流浪有花。',64,'全唐诗/poet.song.5000.json','["行行極目天無柱，渺渺橫流浪有花。", "客子方思舟下碇，陰虬自喜海爲家。", "村遥樹列秦川霽，岸闊牛分觸氏蝸。", "鳶嘯風高良可畏，此情難論坎中蛙。"]'),
('47146af8-01b0-4083-b9ee-817184a42295','題林處士肥上新屋壁','劉筠','宋','宋诗','song-poetry','','[]','久厭侯鯖靜室來，卜居鄰近釣魚臺。',64,'全唐诗/poet.song.5000.json','["久厭侯鯖靜室來，卜居鄰近釣魚臺。", "舊山鶴怨無錢買，新竹僧同借宅栽。", "斗酒誰從楊子學，扁舟空訪戴逵回。", "抽毫有污東陽望，但惜明時老澗才。"]'),
('0efced7e-0eb4-4a7d-a4f9-5938126a0899','赴郡之初尋屬愆亢有議舉舊典取湫水徵巫覡以致禱而涉旬靡應農事方急遣罷去越翊日漸獲優洽','劉筠','宋','宋诗','song-poetry','','[]','優詔將州任，視政纔旬時。',288,'全唐诗/poet.song.5000.json','["優詔將州任，視政纔旬時。", "田畯訴炎暵，坐虞多稼萎。", "雲將掉頭去，波臣涸轍危。", "行部殊未及，隨車杳難期。", "往慚神父化，徒令旱母嗤。", "諸曹白事者，雩典舉舊規。", "郡北岐棘山，上有三湫池。", "衙吏潔齋往，汲水置縹瓷。", "朝服領巫覡，詰旦迓諸岐。", "舁以結綵輿，奉以五龍祠。", "自是率賓介，寅午款于斯。", "紛敷薦楮鏹，浸漬灑楊枝。", "瓦鑪松香髓，匏樽黍酌醨。", "四壁繪神變，正筵塑靈儀。", "悕若葉公牖，怪甚葛仙陂。", "老覡十數輩，勃屑頭如魌。", "童巫及伶倡，貌寢語嘍囇。", "但多甕盎質，曾乏婉孌姿。", "交手操鈴拂，合譟屢僛僛。", "喧塵著蓬髮，穢汗落粉頤。", "一問且一嘔，掩鼻以帨褵。", "朝隮蔚旋敗，成震巽散之。", "巽風暮欲息，竅行呼復來。", "慢黷固已甚，誕妄相憑隨。"]'),
('1b63b139-64ad-4de1-bae0-640d57c94295','召入翰林別同僚','劉筠','宋','宋诗','song-poetry','','[]','一辭鑾署守英蕃，兩見廬峰媚翠罇。',64,'全唐诗/poet.song.5000.json','["一辭鑾署守英蕃，兩見廬峰媚翠罇。", "政懦每憐民若子，歲豐還喜稻成孫。", "離愁且飲閑人酒，密對須求長者言。", "入奉清朝同一德，晨趨豈歎鬢霜繁。"]'),
('6a9feeb6-6392-4086-b24e-51c44cd18b55','送高學士知越','劉筠','宋','宋诗','song-poetry','','[]','浩蕩辭波潤鼠鬚，風流談柄藹栟櫚。',64,'全唐诗/poet.song.5000.json','["浩蕩辭波潤鼠鬚，風流談柄藹栟櫚。", "漢臺厭卧郎官錦，禹穴思探上世書。", "鶴蓋成陰爭出餞，鵾絃促調歎離居。", "由來方任推名輩，藻思江山助起予。"]'),
('082bd472-fca6-4225-ac67-61af130414d3','新年','劉筠','宋','宋诗','song-poetry','','[]','病入新年起甲寅，軻心不動五侯春。',64,'全唐诗/poet.song.5000.json','["病入新年起甲寅，軻心不動五侯春。", "史曹非據慚書法，衮職無虧濫諍臣。", "荏苒未除金馬籍，蹣跚空笑玉樓人。", "窮簷抱影時相吊，一指南禪四大身。"]'),
('36ce496c-5917-4f8c-bac1-28fcec411fb0','奉詔立春日祝太乙宮書事','劉筠','宋','宋诗','song-poetry','','[]','黄圖標清館，紫詔戒鯫臣。',192,'全唐诗/poet.song.5000.json','["黄圖標清館，紫詔戒鯫臣。", "祗祓先三日，精明奉列真。", "緹帷嚴宴室，琅菜盛齏珍。", "鵠浴薰湯潔，龜存踵息勻。", "金胥傳漏箭，雲襡換朝紳。", "霞接浮丘袂，星瞻太乙神。", "九光龍檠密，百和鵲罇新。", "磬度松間籟，歌飄海底塵。", "中天鳴素瑟，五鼓下瓊輪。", "祝冊精衷道，沈榆拜席陳。", "殿趨鳬舄急，廊轉羽旋頻。", "薦幣冰紋滑，升樽玉液醇。", "樓居排逈漢，歘駕返清晨。", "習習靈風遠，欣欣瑞木春。", "祥氛披輦道，遲景上城闉。", "宣室如垂問，鴻禧永庇民。"]'),
('91572830-776f-4629-84cd-0a95e3dc0f2a','上元日','劉筠','宋','宋诗','song-poetry','','[]','漢典久傳祠太乙，竺墳亦說會夫人。',64,'全唐诗/poet.song.5000.json','["漢典久傳祠太乙，竺墳亦說會夫人。", "蟾蜍吐耀祥輪滿，菡萏凝華寶檠新。", "風轉相竽來帝樂，香焚夾道雜車塵。", "承平多慶羣歡洽，益見嚴宸奉紫旻。"]'),
('74467cb3-9995-4f18-9806-e1696e5ba1b8','奉和聖製上元','劉筠','宋','宋诗','song-poetry','','[]','瑞莢盈端月，神燈燦寶輝。',48,'全唐诗/poet.song.5000.json','["瑞莢盈端月，神燈燦寶輝。", "執金停徼騎，坐狄敞朝扉。", "激徵清歌歇，晞陽醉客歸。", "可封家自樂，不獨在輕肥。"]'),
('b13cedab-0545-46e5-a4d1-72c92d65156e','奉和御製中和節','劉筠','宋','宋诗','song-poetry','','[]','載陽臨仲序，初吉協嘉名。',48,'全唐诗/poet.song.5000.json','["載陽臨仲序，初吉協嘉名。", "國授民時正，天資植物榮。", "草薰翔澤雉，風暖度林鶑。", "堯思存稽古，洋洋播頌聲。"]'),
('007fc550-374e-4385-8f40-d55dd15e2812','奉和聖製寒食五七言二首  其一','劉筠','宋','宋诗','song-poetry','','[]','垣禁申嚴日，餘萌盡達初。',48,'全唐诗/poet.song.5000.json','["垣禁申嚴日，餘萌盡達初。", "踏青游騎遠，浮棗禊波舒。", "餳市喧簫吹，雞場隘酒車。", "俗康春更樂，綺榭煥晴虛。"]'),
('2ad200d2-94da-485c-9dc6-eeeafb93c5ff','奉和聖製寒食五七言二首  其二','劉筠','宋','宋诗','song-poetry','','[]','黍盤交薦藏煙日，絲雨微沾解禊辰。',64,'全唐诗/poet.song.5000.json','["黍盤交薦藏煙日，絲雨微沾解禊辰。", "家有鞦韆憐月夕，戶垂楊柳慶芳春。", "波浮素卵祥蘭馥，壟戲名翬瑞麥新。", "千里神畿多勝賞，熙熙胥會可封民。"]'),
('ff339461-2df9-4fe9-ae69-986a8bf7cb6e','立夏奉祀太一宮','劉筠','宋','宋诗','song-poetry','','[]','舜栢森森拂絳霄，薰風瑟瑟動雲璈。',64,'全唐诗/poet.song.5000.json','["舜栢森森拂絳霄，薰風瑟瑟動雲璈。", "琳房遍設沉榆席，金檠齊燃綠桂膏。", "秘冊十行開鳳檢，靈輝三燭駐霓旄。", "香飄員嶠空歌歇，北斗闌干月殿高。"]'),
('322653e7-81e3-45f8-a32f-49d10e646a84','立夏奉祀太一宮五言十韻','劉筠','宋','宋诗','song-poetry','','[]','朱駕開炎序，瓊科舉舊儀。',120,'全唐诗/poet.song.5000.json','["朱駕開炎序，瓊科舉舊儀。", "恭承宣室詔，肅奉列真祠。", "地接蘢葱氣，人多綽約姿。", "珍叢羅寶槭，嘉樹蔭文榱。", "仙饌豐青𩝊，齋房飾紫帷。", "潔誠專在祀，將事竚迎禧。", "谷應空歌韻，神聽祝冊辭。", "蘭蒸芬靜品，桂醑灧華彝。", "煙達徐梵幣，風靈自轉旗。", "雲衣纔半解，鳴鳳遡晨曦。"]'),
('8031caa4-62ba-4805-a671-02c61289a275','天禧戊午歲立夏奉祀太一宮齋宿有感','劉筠','宋','宋诗','song-poetry','','[]','七年綸掖濫敷言，八奉齋祠蔭寶軒。',64,'全唐诗/poet.song.5000.json','["七年綸掖濫敷言，八奉齋祠蔭寶軒。", "上士半同猿鶴老，病身猶與蟪蛄存。", "飯蔬力弱防冠墜，枕杫神寧喜席溫。", "櫻序清和芳意歇，淡然畢竟絕朝喧。"]'),
('e8f1be46-35f6-4809-b30c-367819578f3d','奉和聖製社日七言四韻','劉筠','宋','宋诗','song-poetry','','[]','美服斯勤驗國徑，里民單出慶秋成。',64,'全唐诗/poet.song.5000.json','["美服斯勤驗國徑，里民單出慶秋成。", "時羞饜飫盤中味，神鼓喧闐野水聲。", "爽氣方高疏雨霽，清輝微動遠波平。", "堯章濬發由庚詠，京庾連雲萬億盈。"]'),
('59a526c5-7b42-4118-a30a-ba7359ab308c','中秋館宿','劉筠','宋','宋诗','song-poetry','','[]','餘歡驚社過，獨直奈宵長。',48,'全唐诗/poet.song.5000.json','["餘歡驚社過，獨直奈宵長。", "月向蓬山滿，風來桂殿凉。", "睡輕同警鶴，吟苦伴啼螿。", "耿耿迷遥思，殘星下建章。"]'),
('de77d44a-fb8a-4256-803a-edf699a275ac','九日赴宴不及簡館中同僚','劉筠','宋','宋诗','song-poetry','','[]','野趣風流屬此辰，帝臺高會敞重茵。',64,'全唐诗/poet.song.5000.json','["野趣風流屬此辰，帝臺高會敞重茵。", "絳囊爲佩仙萸密，綠醖飛觴壽菊新。", "兼豆豐盈堯箑饌，雅歌清壯漢營人。", "年來多病歡遊阻，溫玉蒼葭豈易親。"]'),
('9e440a00-80dc-4255-83bf-cbe7a07b6fc7','送張無夢歸天台','劉筠','宋','宋诗','song-poetry','','[]','抗節在叢霄，談玄屢對堯。',48,'全唐诗/poet.song.5000.json','["抗節在叢霄，談玄屢對堯。", "風迴列子馭，霞建赤城標。", "白石泥丹竈，紅泉滌酒瓢。", "天章耀行色，鶴態自逍遥。"]'),
('d3ce7358-e198-4aba-b6fc-bc9938b2c273','送僧歸護國寺','劉筠','宋','宋诗','song-poetry','','[]','暫寄長安寺，時聞寶偈傳。',48,'全唐诗/poet.song.5000.json','["暫寄長安寺，時聞寶偈傳。", "南歸宗派盛，外護帝臣賢。", "桂色陵庵雪，芝腴助茗泉。", "離懷杳何許，鳳剎際霞天。"]'),
('7a1a5dde-e5b4-4489-b5ac-bda101d2509a','奉和真宗御製後苑雜花海棠','劉筠','宋','宋诗','song-poetry','','[]','遲景烘初綻，鮮風惜未飄。',48,'全唐诗/poet.song.5000.json','["遲景烘初綻，鮮風惜未飄。", "蝶魂迷密徑，鶑語近新條。", "芳蕙薰宮錦，丹漿暈海綃。", "惟時奉宸唱，賡奉愧咎繇。"]'),
('29557316-8589-4d79-bd8c-c206665a9c54','題義門胡氏華林書院','劉筠','宋','宋诗','song-poetry','','[]','華林家聲世不渝，雲仍次第秉魚須。',64,'全唐诗/poet.song.5000.json','["華林家聲世不渝，雲仍次第秉魚須。", "烏衣門大容高蓋，蝌蚪書多聚碩儒。", "里巷當今爲甲族，風煙從古是仙都。", "豈惟一榻留徐孺，食客三千兼鱠鱸。"]'),
