('78cf6080-13e4-4902-a3da-31c26718e731','存目  其二○','劉筠','宋','宋诗','song-poetry','','["\u592a\u6e56"]','詩題：重九舟次太湖惜此佳時無菊可以自慰呼兒取綵菊戴之首句：綵花染出鬰金黄。',37,'全唐诗/poet.song.5000.json','["詩題：重九舟次太湖惜此佳時無菊可以自慰呼兒取綵菊戴之首句：綵花染出鬰金黄。"]'),
('e4bf1b99-e717-4933-8d20-6d64830d3b73','存目  其二一','劉筠','宋','宋诗','song-poetry','','[]','詩題：九日與蔡伯世兄弟城上采菊伯世誦居仁九日絕句因用其韻首句：老頭未易見清香。',39,'全唐诗/poet.song.5000.json','["詩題：九日與蔡伯世兄弟城上采菊伯世誦居仁九日絕句因用其韻首句：老頭未易見清香。"]'),
('6b6d0966-7c2b-4d33-a94e-c3348d5ddc79','存目  其二二','劉筠','宋','宋诗','song-poetry','','[]','詩題：宋玉首句：章華清宴重遊陪。',16,'全唐诗/poet.song.5000.json','["詩題：宋玉首句：章華清宴重遊陪。"]'),
('2b96b6ef-7b10-4b78-8f72-96d6df021686','虎丘','方仲荀','宋','宋诗','song-poetry','','[]','海湧起平田，禪扉古木間。',48,'全唐诗/poet.song.5000.json','["海湧起平田，禪扉古木間。", "出城先見塔，入寺始登山。", "堂靜參徒散，巢喧乳鶴還。", "祖龍求寶劍，曾此鑿孱顔。"]'),
('47ac92a4-d85c-4bbf-90c3-f762ecff830f','題靈巖弄月池','方慎言','宋','宋诗','song-poetry','','[]','偶宿天台白石房，夜深清話月移光。',32,'全唐诗/poet.song.5000.json','["偶宿天台白石房，夜深清話月移光。", "宦遊難作重來約，一枕泉聲老不忘。"]'),
('8f09ec5b-2935-458c-a923-cb17b914ed59','句','方慎言','宋','宋诗','song-poetry','','[]','借問城中推妙手，誰能寫得使君心。',16,'全唐诗/poet.song.5000.json','["借問城中推妙手，誰能寫得使君心。"]'),
('0d7d24b1-fcb3-4f2b-9091-fcc254305d51','贈潘閬','許洞','宋','宋诗','song-poetry','','[]','潘逍遥，平生才氣如天高。',65,'全唐诗/poet.song.5000.json','["潘逍遥，平生才氣如天高。", "倚天大笑無所懼，天公嗔汝口呶呶。", "罰教臨老頭補衲，歸中條。", "我願中條山，山神鎮長在。", "驅雷叱電，依前趕出這老怪。"]'),
('de895e13-ba0d-4563-a5fc-50cf4b062aca','嘲林和靖','許洞','宋','宋诗','song-poetry','','[]','寺裏掇齋饑老鼠，林間咳嗽病獼猴。',32,'全唐诗/poet.song.5000.json','["寺裏掇齋饑老鼠，林間咳嗽病獼猴。", "豪民遺物鵝伸頸，好客臨門鱉縮頭。"]'),
('ec386b50-f228-466c-a607-17825560ddc4','詩一首','許洞','宋','宋诗','song-poetry','','[]','金釭焰短風幕斜，棲烏啼月聲鴉鴉。',64,'全唐诗/poet.song.5000.json','["金釭焰短風幕斜，棲烏啼月聲鴉鴉。", "玉人寶瑟掩不弄，背窗紅淚飄蘭花。", "錦機挑字相思意，欲託南風到遼水。", "黄龍夢斷春意勞，渺邈音容隔千里。"]'),
('d1b5b01c-5225-46e3-ac12-2947065a4acd','句  其一','許洞','宋','宋诗','song-poetry','','[]','霜靄清九衢，霞光照雙闕。',12,'全唐诗/poet.song.5000.json','["霜靄清九衢，霞光照雙闕。"]'),
('87b46b8a-c708-430b-905b-da8cd23a4060','句  其二','許洞','宋','宋诗','song-poetry','','[]','梅花開一枝。',6,'全唐诗/poet.song.5000.json','["梅花開一枝。"]'),
('d47377d0-2313-445e-b9f5-2a4a3e375e22','寄洞山聰禪師','許式','宋','宋诗','song-poetry','','[]','語言全不滯，高躡祖師蹤。',48,'全唐诗/poet.song.5000.json','["語言全不滯，高躡祖師蹤。", "夜坐連雲石，春栽带雨松。", "鑑分金殿燭，山答月樓鐘。", "有問西來意，虛堂對遠峰。"]'),
('ba08f6cb-c6ed-461c-b656-e68d5643472b','祥符寺','聶致堯','宋','宋诗','song-poetry','','[]','諸峰回合處，古木抱松林。',48,'全唐诗/poet.song.5000.json','["諸峰回合處，古木抱松林。", "月占秋廊靜，雲侵晝殿陰。", "有泉通石眼，不火沸池心。", "洗浄多生垢，天風更梵音。"]'),
('37eef2e9-7586-4c5b-abe2-f7735a9b8051','秀文樓','聶致孫','宋','宋诗','song-poetry','','[]','講餘衣袂受風輕，來與闌干共晚晴。',64,'全唐诗/poet.song.5000.json','["講餘衣袂受風輕，來與闌干共晚晴。", "山倚南雲屏迤邐，江迎西月錦鮮明。", "道心千古飛鳶接，秋意一樓賓雁橫。", "老栢上頭天尺五，莫歌金石出商聲。"]'),
('68a37dc4-1269-42a7-b624-77d4b82cac91','登碧落堂','聶致孫','宋','宋诗','song-poetry','','[]','渺渺桑田注白波，幽幽花洞憶真多。',64,'全唐诗/poet.song.5000.json','["渺渺桑田注白波，幽幽花洞憶真多。", "丹成已在風烟上，鶴返其如城郭何。", "月下清池明老劍，雲凝碧落聽笙歌。", "五陵王氣龍沙近，儻乞飛霞侍玉珂。"]'),
('b3384a50-2eef-4c7d-8f1d-7d23949d2652','廖仙巖','吳世範','宋','宋诗','song-poetry','','[]','治民因得道，浮世學應難。',48,'全唐诗/poet.song.5000.json','["治民因得道，浮世學應難。", "自是神仙骨，非干龍虎丹。", "松篁排洞罅，樓閣倚雲端。", "此日朝真去，慚爲五品官。"]'),
('c8366492-cee7-44ce-a993-baef3d68093e','白鶴山','吳世範','宋','宋诗','song-poetry','','[]','靈壇古蹟自來誇，四望峰巒錦簇花。',64,'全唐诗/poet.song.5000.json','["靈壇古蹟自來誇，四望峰巒錦簇花。", "白鶴何來歸洞府，青山竟日鎖烟霞。", "言尋庭下燒丹竈，爭羨天邊返斗槎。", "我欲離塵換凡骨，願隨風馭到仙家。"]'),
('50b23f20-d078-4cfe-9d43-3074f455b581','題靈洞天福院','梁頠','宋','宋诗','song-poetry','','[]','門外落將三市隔，此中人是幾生修。',32,'全唐诗/poet.song.5000.json','["門外落將三市隔，此中人是幾生修。", "千尋古木含雲翠，一派寒泉繞檻流。"]'),
('6f6d3de4-b947-4076-aced-ffd3b19b075c','詠紅蕉','胡用莊','宋','宋诗','song-poetry','','[]','謝家池館遇芳菲，破綠抽心一片緋。',32,'全唐诗/poet.song.5000.json','["謝家池館遇芳菲，破綠抽心一片緋。", "恰似九衢三二月，綠羅叢裏著朱衣。"]'),
('5891dc42-0437-48b8-98ed-c4493561425c','金精山','周薰','宋','宋诗','song-poetry','','[]','金精山高絕塵俗，中通洞天石削玉。',64,'全唐诗/poet.song.5000.json','["金精山高絕塵俗，中通洞天石削玉。", "仙家庭院晝不扃，草色迷階秋雨綠。", "香爐峰前青可掬，石鼓壇邊翠如沐。", "道人采藥青牛還，鐵笛聲穿山鬼哭。"]'),
('f6604ffb-03ba-48cf-a8a5-21d2e500c617','朝陽巖二首  其一','王羽','宋','宋诗','song-poetry','','[]','石岸盤危磴，煙和曉日濃。',72,'全唐诗/poet.song.5000.json','["石岸盤危磴，煙和曉日濃。", "長桐應待鳳，占水必藏龍。", "老樹籐多附，層崖路莫從。", "平磯看浪沒，峭壁任苔封。", "簫韻生羣籟，嵐光簇衆峰。", "何時有達士，棲此信疏慵。"]'),
('ec6ea5d4-0b30-4b2b-99d7-cb2bb9207049','朝陽巖二首  其二','王羽','宋','宋诗','song-poetry','','[]','東向水西阿，無時景物和。',48,'全唐诗/poet.song.5000.json','["東向水西阿，無時景物和。", "松陰不映戶，曉日在煙蘿。", "人跡如行少，山禽似語多。", "清高知隠者，塵慮自銷磨。"]'),
('79df350b-e69d-4bda-9d6d-6f28486f074d','題河陽後城平嵩閣','李迪','宋','宋诗','song-poetry','','[]','南指嵩高北太行，大河中出貫靈長。',32,'全唐诗/poet.song.5000.json','["南指嵩高北太行，大河中出貫靈長。", "君王不恃金湯險，自有仁恩結萬方。"]'),
('9ee282c4-7ff8-4eba-a54b-8285a8b9505b','靈巖','李迪','宋','宋诗','song-poetry','','[]','靈巖山勢異，金地景難窮。',192,'全唐诗/poet.song.5000.json','["靈巖山勢異，金地景難窮。", "塔影遮層漢，鐘聲落半空。", "千峰羅雉堞，萬仞聳屏風。", "飛鶴來清竇，刳魚掛古桐。", "名曾參四絕，封合亞三公。", "勢徹河壖遠，形差嶽鎮雄。", "僊閭鄰峻極，日觀伴穹崇。", "邃洞連蓬島，重巒鑿梵宮。", "望應銷俗慮，登喜出塵籠。", "獻壽嵩衡竝，分茅海岱同。", "艮方標出震，午位對升中。", "嵐滴晴煙碧，崖鋪夕照紅。", "巍峨齊太華，奇勝敵崆峒。", "鍊句共詩客，模真怯畫工。", "天孫分怪狀，神化結全功。", "吟賞慵回首，雲泉興愈隆。"]'),
('24a070a0-e2af-47d1-a0a9-8b0c55e790e3','題方干舊隠','刁湛','宋','宋诗','song-poetry','','[]','自別高居二紀餘，今朝重到懶踟躕。',32,'全唐诗/poet.song.5000.json','["自別高居二紀餘，今朝重到懶踟躕。", "山川勝景依然在，屈指交親一半無。"]'),
('c0392135-cff2-488a-bf33-bf4c09c9452f','霍嶽廟','王惟正','宋','宋诗','song-poetry','','[]','聳峻疊寒翠，森森廟木秋。',48,'全唐诗/poet.song.5000.json','["聳峻疊寒翠，森森廟木秋。", "崇功封應聖，褒德鎮中州。", "輔宋來御署，興唐占上游。", "義旗初有力，未足答神休。"]'),
('31da3797-3e7b-42a3-a3af-1ff595289c6a','應禱詩留天聖觀','王惟正','宋','宋诗','song-poetry','','[]','嶺外歸來者，曾爲外計臣。',48,'全唐诗/poet.song.5000.json','["嶺外歸來者，曾爲外計臣。", "無功能報國，抱疾亦憂民。", "乞雨祈諸廟，焚香禱衆真。", "精誠達天地，霶霈果均勻。"]'),
('116378ce-3c63-46b4-b20d-c773388ec3b8','句','王惟正','宋','宋诗','song-poetry','','[]','雲谿水雲鄉。',6,'全唐诗/poet.song.5000.json','["雲谿水雲鄉。"]'),
('b693b640-a499-4850-88af-cecd719b8401','重九席上觀金鈴菊','韓億','宋','宋诗','song-poetry','','[]','黄金綴菊鈴，兖地獨馳名。',48,'全唐诗/poet.song.5000.json','["黄金綴菊鈴，兖地獨馳名。", "細蘂浮杯雅，香筩貯露清。", "風休沈夜警，雨碎入寒聲。", "自此傳仙種，秋芳冠玉京。"]'),
('f8b02a13-e51b-4749-b532-67ac91f70e63','和崔象之紫菊','韓億','宋','宋诗','song-poetry','','[]','紫菊披香碎曉霞，年年霜晚賞奇葩。',64,'全唐诗/poet.song.5000.json','["紫菊披香碎曉霞，年年霜晚賞奇葩。", "嘉名自合開仙府，麗色何妨奪錦砂。", "雨徑蕭疏凌蘚暈，露叢芬馥敵蘭芽。", "孤標只取當筵重，不似尋常泛酒花。"]'),
('36fdc9d6-1f02-48fc-b890-a4ee5ff1a4ed','閣下觀竹笋圖','孔武仲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','我家廬山下，緑竹常陰陰。',168,'全唐诗/poet.song.50000.json','["我家廬山下，緑竹常陰陰。", "春雷迸狂籜，萬點羣玉簮。", "别來經歲時，肌肉塵土侵。", "歘見此圖面，醒然豁煩襟。", "方幅藏萬里，環以青山岑。", "旁飛清泠泉，下有瀟洒林。", "恍惚如夢到，杖笻聽幽禽。", "欲投環堵室，浩渺忽難尋。", "人生諒自苦，一官泳蹄涔。", "搖尾争光華，豈知滄海深。", "虞卿衒白璧，季子夸黄金。", "貪得以忘我，俱非賢達心。", "何如返鄉國，坡塢窮差參。", "茅簷當天風，時聽笙簧音。"]'),
('c0b63975-3200-41b4-90b6-c266801bfad6','伏中作二首  其一','孔武仲','宋','宋诗','song-poetry','','[]','酷暑已旬日，薫炙勢自如。',107,'全唐诗/poet.song.50000.json','["酷暑已旬日，薫炙勢自如。", "昨夜得佳雨，新凉生太虚。", "清風入窗牖，蚊蚋避衾？木末有勁氣，淅淅如秋初。", "稍見清泠池，幽香隨芙蕖。", "三伏已過兩，禦熱沛有餘。", "更得滂沱澤，大患自此除。", "中園有佳果，甕面有浮蛆。", "相過玩華月，北隣寧我疏。"]'),
('e49c308c-9ee0-4fb1-be05-d314582764bb','伏中作二首  其二','孔武仲','宋','宋诗','song-poetry','','[]','去歲復今日，清槐繫扁舟。',120,'全唐诗/poet.song.50000.json','["去歲復今日，清槐繫扁舟。", "手攜笻竹杖，朝上龜山頭。", "百川合爲一，浩渺蟠天流。", "徙倚弄佳音，嘯歌懐舊邱。", "京都偶爲客，歲月復臨秋。", "蓬轉近千里，星回將一周。", "酷暑雖暫解，餘威難速收。", "金火兩相摶，火壯金欲流。", "恐有鬰蒸陳，當代作戈矛。", "且當事紈扇，未可窺狐裘。"]'),
('d58d195e-3cd7-4955-9201-0b458347bbd4','閣下觀峴山圖','孔武仲','宋','宋诗','song-poetry','','[]','峴山巉巉清溪濵，倒影萬丈之奫淪。',192,'全唐诗/poet.song.50000.json','["峴山巉巉清溪濵，倒影萬丈之奫淪。", "往歲嘗有去思吏，熱地尤多高蹈人。", "少年仕宦頗落魄，時登絕頂攀蒼冥。", "幽花美草頗娱目，斷碑刓碣還傷神。", "曉猿夜鶴輕相别，從此奔走十八春。", "舊遊不復齒頰挂，方知到骨俱埃塵。", "麟臺昨日見圖畫，醒若楚客還覉魂。", "方縑一幅論萬里，秋江緑水何粼粼。", "人心與物本無别，正爲利欲相埋湮。", "神功妙手如喚覺，滿座風月來相親。", "騎驢徑去自可到，猶愈飄颻西遊秦。", "剩沽宜城醉其下，日夕倒載望冠巾。"]'),
('33765c8e-f723-4eb9-b0b2-55815718abcd','食冰','孔武仲','宋','宋诗','song-poetry','','[]','冬冰冽冽雖可畏，夏冰皎皎人共喜。',80,'全唐诗/poet.song.50000.json','["冬冰冽冽雖可畏，夏冰皎皎人共喜。", "休論中使押金槃，荷葉裹來深宫裏。", "胸煩肺涸聊一蘇，任爾青蠅相趁死。", "經時不壞已可憐，濟物之功尚如此。", "人言霜雪比小人，我謂堅冰似君子。"]'),
('bba13b40-33f3-4e3e-8e6b-802a3aa6fcb7','愧魚亭','孔武仲','宋','宋诗','song-poetry','','[]','昔聞魚可羨，今見魚可愧。',56,'全唐诗/poet.song.50000.json','["昔聞魚可羨，今見魚可愧。", "邂逅臨池處，瀟洒出塵意。", "秋風八月起江湖，水染紺碧霞綺疏。", "悠然掉尾波間去，須信人生不及魚。"]'),
('bd6eff7c-e212-4402-9c41-b5d23e5ddbcd','劉器之陰山七騎圖','孔武仲','宋','宋诗','song-poetry','','[]','北風颯颯邊雲黄，飛沙曀日天慘蒼。',224,'全唐诗/poet.song.50000.json','["北風颯颯邊雲黄，飛沙曀日天慘蒼。", "駕鵝鳴哀雁不翔，七騎正出陰山傍。", "山傍陰塵歲無陽，鳥飛墮翼人立僵。", "犯寒跨鞍知悍强，以此决戰誰能當。", "面顔雖在姓莫詳，一一胡帽胡衣裳。", "馬蹄澀縮弓不張，但見旗旆隨飛揚。", "鳳瓶倒酒進其王，俯仰意氣驕雪霜。", "横斜道路深淺岡，想見射獲多麏麞。", "時平不復憂邉疆，但見樓蘭馳驌驦。", "仍嗤苦淡無輝光，人生所樂惟故鄉。", "彭城妙本家世藏，託以輕縑盛錦囊。", "持來舒捲臨華堂，環視歎詫幾發狂。", "我生未省到朔方，坐令出塞意慨慷。", "攘歸可敵千金裝，長厚不疑同舍郎。"]'),
('6d31a624-128c-4268-88b2-88bab2ef920d','落葉','孔武仲','宋','宋诗','song-poetry','','[]','落葉不到地，隨風復飄揚。',48,'全唐诗/poet.song.50000.json','["落葉不到地，隨風復飄揚。", "凋殘北窗陰，凌亂日西光。", "時節如未已，烏鳥情亦傷。", "何事千丈松，歲晚仍蒼蒼。"]'),
('858e0b1a-b02d-4e95-8f89-d2e126a56928','入局馬上','孔武仲','宋','宋诗','song-poetry','','[]','愁雲慘慘増寒威，冰鋩砭骨裘不支。',80,'全唐诗/poet.song.50000.json','["愁雲慘慘増寒威，冰鋩砭骨裘不支。", "鳴騶南北困道路，擾擾人趨入省時。", "京師久旱塵土惡，喜有小雨沾鬚眉。", "跨鞍便起江湖興，波明别浦柳半垂。", "卧聽篷聲睡正穏，放船不問歸來遲。"]'),
('83ee7569-d792-436d-ab19-7d7691aac352','芻車吟','孔武仲','宋','宋诗','song-poetry','','[]','京師患無馬，有馬患乏芻。',124,'全唐诗/poet.song.50000.json','["京師患無馬，有馬患乏芻。", "長鞭隨牛牛引車，三冬以來要貯積，十倍之價在須臾。", "都城之物不便美，枯笋宿菜供庖厨。", "况此剉秣豈能足，雜以豌豆調陳麩。", "却思當年在江湖，緑陰冉冉如雲敷，百馬嘶齕皆自如。", "安知入市比金玉，風物陡逐山川殊。", "馬饑且瘠不足怪，壯士猶有釜生魚。"]'),
('1499c0ec-489d-4921-9900-3888526cc081','踏冰入省','孔武仲','宋','宋诗','song-poetry','','[]','匹馬泛冰澤，海濶難經過。',96,'全唐诗/poet.song.50000.json','["匹馬泛冰澤，海濶難經過。", "玉浪來溟溟，雲濤起峨峨。", "投瀧若投岸，避凍如避渦。", "蹄脆復參差，覆舟在中河。", "碎身須臾間，不殊葬黿鼉。", "飄蓬白日東，涉險奈遠何。", "屯雲猶滄溟，何時縱陽和。", "畏途正渺渺，浩然商聲歌。"]'),
('bf33ef88-1ec0-4df7-92c3-01fc48af0ed8','子瞻畫枯木','孔武仲','宋','宋诗','song-poetry','','[]','寒雲行空亂春華，西風凛凛空吹沙。',288,'全唐诗/poet.song.50000.json','["寒雲行空亂春華，西風凛凛空吹沙。", "夫子抱膝若喪魄，誰知巧思中萌芽。", "敗毫淡墨任揮染，蒼莽菌蠢移龍蛇。", "略増點綴已成就，止見枯木成槎枒。", "更無丹青相掩翳，惟有口鼻隨穿呀。", "往年江湖飽觀畫，或在山隈溪水涯。", "腹中空洞夜藏魅，巔頂突兀春無花。", "徑深最宜繫畫舸，日落時復停歸鴉。", "蘇公早與俗子偶，避世欲種東陵瓜。", "窺觀盡得物外趣，移向紙上無毫差。", "醉中遺落不秘惜，往往流傳藏人家。", "趙昌丹青最細膩，直與春色争豪華。", "公今好尚何太癖，曾載木車出岷巴。", "輕肥欲與世爲戒，未許木葉勝枯槎。", "萬物流形若泫露，百歲俄驚眼如車。", "樹猶如此不長久，人以何者堪矜誇。", "悠悠坐見死生境，但隨天機無損加。", "却笑金城對宫柳，泫然流涕空咨嗟。"]'),
('5482bf91-ad5a-4ecd-bcdc-7d869a4b11e1','送王炳之之饒州','孔武仲','宋','宋诗','song-poetry','','[]','衡門喜見過，相與話行色。',96,'全唐诗/poet.song.50000.json','["衡門喜見過，相與話行色。", "江左昔之官，鄱陽飽從役。", "重湖繞官舍，塵不到旌戟。", "緑水平朱欄，青山臨畫鷁。", "魚來城市富，雁下沙汀黑。", "玉楮光動毫，瓊盃香泛席。", "固知足優游，但恐少賓客。", "聚散寧易忘，登臨儻相憶。"]'),
('08034288-16e3-4bf2-a53a-2a5b04b2f95b','送毅父弟使江東','孔武仲','宋','宋诗','song-poetry','','[]','人生何能爲，寄迹夢寐中。',120,'全唐诗/poet.song.50000.json','["人生何能爲，寄迹夢寐中。", "之子又遠去，扁舟逐江風。", "而我獨栖栖，弱羽挂樊籠。", "袖手欲大呼，窘如猿檻窮。", "逼迫褐與被，况以憂患攻。", "坐令形勢隔，出處焉得同。", "又無凌雲翮，翩翩作歸鴻。", "强埽道南舍，竹陰泛簾籠。", "及此光景長，無惜觥船空。", "明發看解纜，渠波劇奔驄。"]'),
('c5fa79cd-275c-49d5-b0d9-d03806ccda65','初秋大熱','孔武仲','宋','宋诗','song-poetry','','[]','金神整霜仗，昨日從西回。',132,'全唐诗/poet.song.50000.json','["金神整霜仗，昨日從西回。", "謂當有爽氣，吹蕩滄溟開。", "誰知祝融軍，執熱䟃𧽼來。", "六龍駐長安，無風動浮埃。", "窗筠氣烜赩，庭鶴羽摧頽。", "向晚蚊聲號，轟轟漸成雷。", "徑思去塵囂，登臨千丈臺。", "披襟迎清颸，俯聽驚鴻哀。", "僕羸不能駕，我馬亦虺隤。", "閉關吟愁雲，履迹亂蒼苔。", "炎凉自交戰，我輩能忘懐。"]'),
('a2c1c407-4b9b-45ee-9333-35106986ad3d','錢穆仲有高麗松扇館中多得者以詩求之','孔武仲','宋','宋诗','song-poetry','','[]','巨鰲昂頭鯨掉尾，東顧滄溟天接水。',176,'全唐诗/poet.song.50000.json','["巨鰲昂頭鯨掉尾，東顧滄溟天接水。", "錢公涉險如通渠，破帆一抹三千里。", "島夷之國遠且偏，歸來逢人語輒喜。", "大荒茫茫最宜松，直從曠野連深宫。", "聽聲卧影已不俗，况作團扇搖清風。", "人情重遠由來事，不貴黄金貴楛矢。", "况有新詩傳四方，羣豪追隨弄薦章。", "我雖相見無所得，坐憶松鶴生微凉。", "錢公治迹壓張趙，偷兒破胆皆摧藏。", "桴鼓不鳴已三月，凛凛霜威破殘熱。", "從公覓扇更覓詩，願報瓊瑤無已時。"]'),
('8ee6f415-aa7a-4d0c-9737-b1e54142e3af','內閤錢公寵惠高麗扇以梅州大紙報之仍賦詩','孔武仲','宋','宋诗','song-poetry','','[]','昨夜秋風來户庭，殘燈閃滅微凉生。',208,'全唐诗/poet.song.50000.json','["昨夜秋風來户庭，殘燈閃滅微凉生。", "得公團扇未及用，挂向空堂神骨清。", "但將遠趣醒耳目，不獨暑月排歊蒸。", "慚當厚意無以報，前詩空說玖與瓊。", "漆箱猶有南中紙，濶似棋枰净如水。", "傳聞造之自梅州，蠻奴赤脚踏溪流。", "銀波滲徹雲蟾髓，入軸萬杵光欲浮。", "收藏終恐非吾物，寶劍銀鈎有時失。", "不如包卷歸文房，錢公家世能文章。", "五日京兆聊爾耳，歸步金鑾上玉堂。", "玉堂不復知吏事，紫槖華簮奉天子。", "鳳閣曾觀思湧泉，謫仙今振辭如綺。", "不似冷官太苦辛，吟哦風月愁山鬼。"]'),
('493b7675-7c95-476c-b72c-66c842a84407','秋夜對月','孔武仲','宋','宋诗','song-poetry','','[]','月行青天入重雲，金波洩洩穿魚鱗。',224,'全唐诗/poet.song.50000.json','["月行青天入重雲，金波洩洩穿魚鱗。", "須臾雲收境亦静，虚空表裏無纎塵。", "寒光正與人相射，碧琉璃中低玉盆。", "微風更入北窗竹，餘聲颯洒清心魂。", "頗疑碧落在步履，廣寒清都相與鄰。", "乘槎去後事寂寞，至今織室臨河津。", "却思白日走城郭，浮埃馬足何紛紛。", "勞之以晝逸以夜，天意儻欲甘苦均。", "人生南北無定所，浪自轉徙隨燕秦。", "關河渺邈鄉井異，惟有明月來相親。", "﨑嶇萬里如咫尺，圓缺帷有年年新。", "如兹久要乃可喜，相對可不羅壺樽。", "黄金如不付酒媪，雖富不如長賤貧。", "重城沉沉桂魄下，蘿永愧山中人觀。"]'),
('9fbd0785-8b31-4a61-9d7a-116a79d8476e','鍾離中散草書帖','孔武仲','宋','宋诗','song-poetry','','[]','兒童不識草書法，但見滿紙鰌蛇結。',176,'全唐诗/poet.song.50000.json','["兒童不識草書法，但見滿紙鰌蛇結。", "安知筆法追古初，睨視衆體稱雄傑。", "事忙往往無暇冩，属思幽窗乃奇絕。", "鍾離昂昂散人後，寄迹一官今白首。", "潜心妙趣百事忘，興來書空不停手。", "當年飄泊重湖外，翰墨已有時流愛。", "風波頓挫格逾遒，羽翮翩翩入吾輩。", "一時已聞紙價高，千古定有書名在。", "何當灑埽竹洞邊，雲醅滿酌黄金船。", "萬事峥嶸置毫末，三盃縱逸如張顛。", "相知本不誇勢力，休論脫帽王公前。"]'),
('c0f5f263-32ec-4104-8104-4ea06eb7b9bb','憶九江呈李端叔','孔武仲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','家園大江東，清湓映匡廬。',240,'全唐诗/poet.song.50000.json','["家園大江東，清湓映匡廬。", "波光搖空濶，嵐翠隨捲舒。", "廓然形影消，所見惟清虚。", "此是列仙宅，當年來不居。", "一官老南北，十年棄樵漁。", "諒無飛昇骨，宜與煙霞疏。", "子亦喜登臨，持氣爲舟車。", "乘馬搴虹蜺，俯澗窺蟾蜍。", "賦詩不計篇，飲酒動斗餘。", "一爲簮纓縳，屢感歲月除。", "西征臨瀚海，東使騎鯨魚。", "歸來顔已蒼，相見兩勤渠。", "話及少年事，慨然咏歸與。", "富貴非所期，朝衣裹猿狙。", "鼎食多憂煎，未若羮園蔬。", "何當永卜鄰，之子同耕耡。", "清風卧醉石，落日登籃輿。", "道逢酒家旆，聊復爲躊躇。", "白首入石城，君心竟何如。", "不然因便道，鳴騶時訪余。"]'),
('5aafd652-603f-46d3-89e8-ee08995e5d76','五鼓','孔武仲','宋','宋诗','song-poetry','','[]','夜枕回遠夢，北窗覺微明。',168,'全唐诗/poet.song.50000.json','["夜枕回遠夢，北窗覺微明。", "遙知扶桑曲，萬頃搖光晶。", "江海已瀺灂，魚龍俱震驚。", "大哉陽德敏，頃刻周四溟。", "天星黯餘照，林飈颯先聲。", "栖鳥不安巢，世務新營營。", "陽德固主動，與物皆流行。", "君子法天時，燕居嘗夙興。", "流火感隙駒，翰音伺雞鳴。", "焚香奉真祠，篝衣尋六經。", "夜氣猶未曉，神觀則愈清。", "力省功或倍，心虚思彌精。", "道要處戒定，自伐如刀兵。", "書紳以自勸，因之遺友生。"]'),
('00ff67bd-43c4-48c7-b4cc-66b14135cfaa','戊辰雪  其一','孔武仲','宋','宋诗','song-poetry','','[]','初臘氣亦佳，窮冬雪還虐。',48,'全唐诗/poet.song.50000.json','["初臘氣亦佳，窮冬雪還虐。", "晚風淅瀝響，暮勢聯翩作。", "餘寒逼觥斚，遠景明池閣。", "想像山陰人，扁舟在寥廓。"]'),
('dab6dda5-8ac4-4a6e-ab29-bab756cadea8','戊辰雪  其二','孔武仲','宋','宋诗','song-poetry','','[]','歲日雪亦好，今日差可憂。',48,'全唐诗/poet.song.50000.json','["歲日雪亦好，今日差可憂。", "盈尺望已足，太多民始愁。", "穀價起如涌，城郭饑者稠。", "後期無乃遲，春郊多麥麰。"]'),
('4131213d-d286-4a0a-a3d9-529947ea96e5','館中竹影','孔武仲','宋','宋诗','song-poetry','','[]','緑竹带斜暉，猗猗有餘態。',48,'全唐诗/poet.song.50000.json','["緑竹带斜暉，猗猗有餘態。", "微風到簾櫳，舞影入圖繪。", "更無餘聲雜，直與妙意會。", "掩卷罷吟哦，誰同此三昧。"]'),
('124fe24c-5f35-4693-8316-3453620979b9','早起趁朝','孔武仲','宋','宋诗','song-poetry','','[]','山房客夢驚，槐廳雨清絕。',48,'全唐诗/poet.song.50000.json','["山房客夢驚，槐廳雨清絕。", "蕙爐香寂寞，半挂北窗月。", "重城車馬動，起坐候明發。", "華蓋望宸居，煙飛隔雙闕。"]'),
('d1f0d149-6fd6-4a7f-bf0c-65fab886f558','閤下會食贈張文潜','孔武仲','宋','宋诗','song-poetry','','[]','錦带貂裘亦不惡，宿酒移春入顔角。',88,'全唐诗/poet.song.50000.json','["錦带貂裘亦不惡，宿酒移春入顔角。", "人憐枳棘棲鳳凰，誰許青山入雲閣。", "爲我坐誦離騷篇，森羅屈宋俱眼前。", "却歸北齋枕書眠，夢乘紫雲飛上天。", "覺來斜日催野鞭，隨車擲果長安市，不信潘郎風骨仙。"]'),
('e8de2618-8fc9-44f9-ba1c-e251f03a609c','館宿','孔武仲','宋','宋诗','song-poetry','','[]','啾啾簷間雀，側翅相悲鳴。',72,'全唐诗/poet.song.50000.json','["啾啾簷間雀，側翅相悲鳴。", "歲晏寒雖壯，雲稀雪未成。", "同舍布路歸，禁扃斷人行。", "敗箕摧殘葉，傴僂一老兵。", "念非太瀟洒，安得耳目清。", "爐焰久更高，宵鼓動嚴城。"]'),
('e167a329-b4f9-4207-a348-3c0039b82845','送吴叔揚通判代州','孔武仲','宋','宋诗','song-poetry','','[]','雁門襟喉地，北瞰單于城。',120,'全唐诗/poet.song.50000.json','["雁門襟喉地，北瞰單于城。", "漢騎罷深入，塞垣春草生。", "題輿當遠去，磴道歴峥嶸。", "載路壺漿饋，出郭幡旗迎。", "公堂足奉養，美酹與犀兵。", "漏刻閒愈永，衣裘寒更輕。", "五臺聚仙聖，事迹衆所欽。", "新篇時冥邈，萬怪登幽情。", "政成早歸來，銀章對承明。", "未遂遊邊志，羨君爲此行。"]'),
('53ab3bc0-0e77-48a0-9c64-be238febe7a5','和黄魯直送茶二首  其一','孔武仲','宋','宋诗','song-poetry','','[]','喜君屢致雲溪茗，值我正校琅函書。',64,'全唐诗/poet.song.50000.json','["喜君屢致雲溪茗，值我正校琅函書。", "飲罷清風生肘腋，吟成碧海登明珠。", "誰能墦間享膏腴，只意林泉身自如。", "他年遠别歸賀監，乞取茶山比鏡湖。"]'),
('b5b0e710-2ad4-48e3-9843-bcbb571d88ef','和黄魯直送茶二首  其二','孔武仲','宋','宋诗','song-poetry','','[]','君茶勇勇睡魔鬥，但恐濕我腹中書。',64,'全唐诗/poet.song.50000.json','["君茶勇勇睡魔鬥，但恐濕我腹中書。", "欲酬黄金臺上意，愧乏夜光明月珠。", "□□□□□□□，□□□□□□如。", "多君藻思比華腴，新詩妙墨更如湖。"]'),
('3440e9f2-cf16-4978-9f18-6f97b6b230ef','送邵彦瞻通判濠州','孔武仲','宋','宋诗','song-poetry','','[]','民情極簡易，闗决未應勞。',24,'全唐诗/poet.song.50000.json','["民情極簡易，闗决未應勞。", "佳句寧我知，爲君屈揮毫。"]'),
('20000f11-75a6-4f9f-955d-df380ca7c774','送徐成之通判永寧軍','孔武仲','宋','宋诗','song-poetry','','[]','少年意氣横寥廓，淬拭龍泉出鋒鍔。',96,'全唐诗/poet.song.50000.json','["少年意氣横寥廓，淬拭龍泉出鋒鍔。", "人情俱欲向長安，天語新令倅河朔。", "霜風冽冽吹邊州，青驄駿馬錦貂裘。", "也知未足稱才用，猶勝當年爲薄遊。", "故人白髪今憔悴，别來慇懃儻相記。", "塞雁高飛不可馮，寄聲亦有南歸使。"]'),
('b3aea820-8886-481e-99c7-8ec04839834e','晁無咎張文潜同校名臣事迹因贈','孔武仲','宋','宋诗','song-poetry','','[]','畫省深沉天上居，道貌日與塵客踈。',96,'全唐诗/poet.song.50000.json','["畫省深沉天上居，道貌日與塵客踈。", "天公恐我太寂寞，更遣兩仙同校書。", "名臣已去騎箕尾，尚有規模在新史。", "浩然初若泛滄溟，目眩形勞安得止。", "興亡治亂略可知，兩公少壯方施爲。", "齋房比鄰數相說，聽公清談勝欲酒。"]'),
('e0c43b8b-2f92-4214-898d-1c97d4d6cdcf','高樓行','孔武仲','宋','宋诗','song-poetry','','[]','天悠悠，雲冪冪，半夜微聞奏笙笛。',92,'全唐诗/poet.song.50000.json','["天悠悠，雲冪冪，半夜微聞奏笙笛。", "爛彩蹙飛仙，鵷鶵戢其翼。", "高樓百尋當大途，東臨紫垣望青都。", "中山黄封傾百壺，五陵豪少來歡娱。", "夷門帝家盛遊樂，奔走環觀溢城郭。", "如今官吏横索錢，縱飲誰愁家寂寞。"]'),
('133348c5-77bb-4889-8cac-0f226f89d3f9','丁卯春雪呈同僚','孔武仲','宋','宋诗','song-poetry','','[]','經時無甘澤，帝爲元元憂。',168,'全唐诗/poet.song.50000.json','["經時無甘澤，帝爲元元憂。", "新正得一雪，尚可期有秋。", "狂風東北來，浩浩舉山丘。", "飛霰爲先驅，繁英已綢繆。", "堆深地欲蟄，舞急川争流。", "沉沉西崦暮，落勢漫不收。", "盡移白玉京，來爲帝王州。", "癘鬼窘相泣，凄凉苦罷休。", "旱魃亦失氣，耿耿空自囚。", "從兹民其康，終歲飽麥麰。", "端門盛佳氣，策府多英遊。", "諒多贊時瑞，豈獨吟空愁。", "金樽發清揚，思湧如雲浮。", "請歌豐年占，以代擊壌謳。"]'),
('99b5b001-94f9-4582-a725-a698fbe1e2bf','大風入朝','孔武仲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','風從何落來何處，百馬盤空正號怒。',64,'全唐诗/poet.song.50000.json','["風從何落來何處，百馬盤空正號怒。", "閉户猶恐丘山頽，誰人放舟江海去。", "廬山之南白雲翁，冠带强遊京邑中。", "狐裘包纒不煖體，却羨爰居能避風。"]'),
('c0f8807f-a86f-4cb4-9323-eb87f713ddbb','送晁無咎之官塞上','孔武仲','宋','宋诗','song-poetry','','[]','人生苦南北，相見出偶爾。',84,'全唐诗/poet.song.50000.json','["人生苦南北，相見出偶爾。", "喧闐都市中，乃復遇之子。", "東萊遽别後，故人今有幾。", "詵詵塾與序，進學亦可喜。", "語闌行色動，輕裘有知已。", "去去何當回，山川正芳暉。", "邊州剩厨傳，應不典春衣。"]'),
('d679153e-eccd-4a98-9a99-e1f470a3716b','蠟梅二絕黄魯直云王都尉有之邀同賦  其一','孔武仲','宋','宋诗','song-poetry','','[]','蠟梅直何如，但聞鄭家說。',24,'全唐诗/poet.song.50000.json','["蠟梅直何如，但聞鄭家說。", "淡日明晨霜，凉酥點春雪。"]'),
('0647761f-27c9-4d8d-97b2-44ef29796b08','蠟梅二絕黄魯直云王都尉有之邀同賦  其二','孔武仲','宋','宋诗','song-poetry','','[]','清嫌冰麝俗，淡學池鵝黄。',24,'全唐诗/poet.song.50000.json','["清嫌冰麝俗，淡學池鵝黄。", "情知不是蠟，風定有餘香。"]'),
('a3972f0a-3fb4-4af6-93b4-4106d3126eed','道傍樹','孔武仲','宋','宋诗','song-poetry','','[]','蟠根官道傍，生飽禁城霜。',60,'全唐诗/poet.song.50000.json','["蟠根官道傍，生飽禁城霜。", "春風功力微，磥砢百尺長。", "肌膚凝金鐡，大雪凍不僵。", "度歲亦辛苦，成材必堅强。", "他時擎大厦，白蟻胡能傷。"]'),
('6463c793-a280-4934-ae0d-6e9adf28e1b7','遊城北李氏園池','孔武仲','宋','宋诗','song-poetry','','[]','池塘春色歸，波水已極目。',156,'全唐诗/poet.song.50000.json','["池塘春色歸，波水已極目。", "鳬雁稍下來，垂楊舞新緑。", "登臨不憚遠，枉徑入重復。", "已見數種花，參差隔脩竹。", "非特野興長，彩翠動華屋。", "沁園天下名，魯館當年築。", "百年猶盛麗，風景冠輦轂。", "當時手種植，仰視皆喬木。", "主人况仁賢，客至初不速。", "躋攀脚力盡，更酌以？渌。", "左右列圖書，南北置殽簌。", "夕陽整歸驂，尚謂夜可卜。", "明日憶勝游，長歌寄金谷。"]'),
('d10f930b-4df3-4312-9ed9-7dcd70954be0','瓊花畫軸','孔武仲','宋','宋诗','song-poetry','','[]','我欲遊廣陵，江湖浩難涉。',132,'全唐诗/poet.song.50000.json','["我欲遊廣陵，江湖浩難涉。", "喜有瓊花枝，相隨在巾篋。", "北人初不識，謂是玉蝴蝶。", "天妃絕世艷，乃以方妓妾。", "古祠惟一株，他種不欲接。", "春風亂百草，紅紫鬭紛煜。", "皓然姑射姿，豈少朱粉頰。", "鐡幹已峥嶸，雲朶正稠叠。", "書林日清閒，萬慮坐收攝。", "悠然對妙筆，頗與幽興愜。", "彷彿未易得，吟思舌徒囁。"]'),
('52fb7969-f106-4279-a557-a1a413f42486','京塵','孔武仲','宋','宋诗','song-poetry','','[]','蜚塵冥冥逐馬尻，轔轔牛車何太勞。',144,'全唐诗/poet.song.50000.json','["蜚塵冥冥逐馬尻，轔轔牛車何太勞。", "春霜十日似妥帖，稍晴仍復起波濤。", "非徒漸漬襟領黑，復且侵凌宫殿高。", "吁嗟性地本安静，何乃紛擾争雄豪。", "祗憂飛盡到坤軸，萬怪菌蠢難藏韜。", "願回河淮作溝瀆，貫穿城郭還周遭。", "分衢洒掃萬丁力，常遣瑩定無秋毫。", "身微願大恐難副，有如畫釣搴鯨鼇。", "彈冠振衣但隨俗，寄身此境何由逃。"]'),
('7d348e1d-5985-4eb0-9793-009461e25b5d','賦得九華松管筆','孔武仲','宋','宋诗','song-poetry','','[]','松枝爲管京邑無，山翁持贈最勤渠。',64,'全唐诗/poet.song.50000.json','["松枝爲管京邑無，山翁持贈最勤渠。", "千年自飽幽澗雪，一日忽快南窗書。", "但知來處已瀟洒，况復毫端精有餘。", "茅齋舉眼有真率，象齒琅玕渾不如。"]'),
('2ead5a93-d84b-4450-9d6d-c69f5041a2f7','移花','孔武仲','宋','宋诗','song-poetry','','[]','春光不徘徊，忽過如插羽。',144,'全唐诗/poet.song.50000.json','["春光不徘徊，忽過如插羽。", "怱怱陌上兒，移花急風雨。", "山波爛襭繡，平日誰指數。", "到此俱可憐，輕妍若時女。", "我家王城西，披風立環堵。", "坐思清興添，不可佳時負。", "晨朝市桃李，百錢得三五。", "□□□□□，□□□□□。", "□□□□□，□□□□□。", "□□□□□，□□若不暇。", "□□□□晤，語□□□□。", "□□□夜對，青藜方草玄。"]'),
('efce29ff-e8c1-4594-8778-b464d32dbac7','晁無咎大硯','孔武仲','宋','宋诗','song-poetry','','[]','玄玉琢爲池，潭潭可容尺。',88,'全唐诗/poet.song.50000.json','["玄玉琢爲池，潭潭可容尺。", "圓侵震澤璞，潤带端溪色。", "麟臺讐書御史孫，揮毫應敵妙語言。", "滔滔百丈洪河翻，助寶以泓還駿奔。", "君王側席明光殿，直言儻有公卿薦。", "區區邊計不須陳，亦論皇王繼家傳。"]'),
('5c9f92b0-01cb-4dd0-a359-cb5c447e3321','答蘇子由留贈','孔武仲','宋','宋诗','song-poetry','','[]','西垣有古人，磔磔氣貌古。',132,'全唐诗/poet.song.50000.json','["西垣有古人，磔磔氣貌古。", "落筆成文章，無可加損處。", "策蹇得過門，殷勤相勞苦。", "湛然神觀全，秀粹充眉宇。", "語我春已闌，斯民望時雨。", "宿麥正滿野，驕暘惡如虎。", "雲師未灑澤，赤子將誰乳。", "侍臣當憂國，密計應禆補。", "又云好著書，安得一州去。", "知公趣操異，不爲夸腰組。", "衣錦若還鄉，亦當從幕府。"]'),
('337fc8b5-1f24-4963-be5f-4d0bc639023a','再用韻和子瞻','孔武仲','宋','宋诗','song-poetry','','[]','堂堂司寇公，族姓原自古。',144,'全唐诗/poet.song.50000.json','["堂堂司寇公，族姓原自古。", "支流入漢唐，浩渺無尋處。", "子瞻得家法，自少不勤苦。", "戲劇入塲屋，名聲振寰宇。", "凝思膚寸雲，落筆萬點雨。", "中間觸機阱，窘若带箭虎。", "坎軻連交游，凍饑及穉乳。", "歸來直玉堂，得失亦相補。", "頋我縻一官，未即江海去。", "裳衣裹窮猿，繫以三尺組。", "知公心胸中，坦不置城府。", "漫刺猶可持，還當謁文舉。"]'),
('d7ba52d9-e373-4bf6-9800-9aa604de00cb','休日與李端叔出城西','孔武仲','宋','宋诗','song-poetry','','[]','荷葉欲漠漠，柳絮已飛飛。',60,'全唐诗/poet.song.50000.json','["荷葉欲漠漠，柳絮已飛飛。", "東風如車輪，日夜挽春暉。", "天郊多名園，曷不事鞍鞿。", "休日不暇沐，權門亞冠衣。", "嘉與之子游，浩歌夕忘歸。"]'),
('b79bcaf3-7d06-4985-9d0b-bd1e101c2435','次韻蘇翰林西山詩','孔武仲','宋','宋诗','song-poetry','','[]','黄州水米宜新醅，東坡好花公自栽。',224,'全唐诗/poet.song.50000.json','["黄州水米宜新醅，東坡好花公自栽。", "折花倒酒送流景，不念春風飄落梅。", "醉投青山上九曲，吴王故宫壓崔嵬。", "寒潭已無昔光景，凉殿歘變今樓臺。", "南陽翰林當此日，力探奇險祛塵埃。", "西江雪浪接溪國，巨石森起繁如堆。", "手披荒榛得突兀，中有窊處成樽罍。", "漫疑蹤跡塵埃暗，從此出躍樊山隈。", "大賢坎軻終必用，古劍雙蟄生莓苔。", "忽抛光芒萬丈去，星斗辟易青天開。", "欃槍枉矢莫妄動，以湯滴雪誰先摧。", "披奇振淹自明主，區區識寶非張雷。", "陽春一奏衆争和，咸韶蕩黙羣仙來。", "雖然此亦外物爾，豈繫兩公樂與哀。"]'),
('ddf998bb-3571-41b3-8631-896bfbd696e3','春晚作','孔武仲','宋','宋诗','song-poetry','','[]','年華工密移，回首已春暮。',96,'全唐诗/poet.song.50000.json','["年華工密移，回首已春暮。", "雨掠夭桃空，風折牡丹去。", "芍藥殿花陣，披靡不能住。", "惟有酴醿開，仙葩照行路。", "清香飄夜月，淡態挹晨露。", "得酒便孤斟，遠駕耽徐步。", "我如車上人，醉逐四時鷺。", "浩蕩無所之，誰能問徒御。"]'),
('53f2fae1-77b2-4785-9c2d-71fd439376e6','三舍人題名於後省皆賦詩因寄呈劉貢父','孔武仲','宋','宋诗','song-poetry','','[]','西垣寂寞今已久，三賢文章鳳池手。',88,'全唐诗/poet.song.50000.json','["西垣寂寞今已久，三賢文章鳳池手。", "朝來不復戀山中，後至儻誰居客右。", "華堂刻石映今古，秀句連章動星斗。", "鴒原棣蕚俱相望，龍吟虎嘯生輝光。", "就中貢父我故鄉，况有小阮争翺翔，翩翩亦試中書堂。"]'),
('edfba186-55ae-4e84-aa82-554f7ccd66e2','曾子開示詩再用前韻','孔武仲','宋','宋诗','song-poetry','','[]','川滔海積歲月久，書秃十毫未停手。',88,'全唐诗/poet.song.50000.json','["川滔海積歲月久，書秃十毫未停手。", "昔人四十夸專城，公佩黄金來帝右。", "當年逸足起江西，時輩共喜星之斗。", "榮華未滿衆所望，天啟叔季侍清光。", "莫言晝錦歸故鄉，莫對秋雁思南翔，且登金門上玉堂。"]'),
('e7b51897-963d-4452-a960-cd9d5fc150f3','蘇子由示詩再用前韻','孔武仲','宋','宋诗','song-poetry','','[]','公家兩賢涉世久，六馬從容轡在手。',88,'全唐诗/poet.song.50000.json','["公家兩賢涉世久，六馬從容轡在手。", "驅馳有節心有常，進退不隨人左右。", "十年挫抑心不回，方知有膽大如斗。", "鸞坡鳳閣蔚相望，燦燦奎璧連晶光。", "我家辛勤出寒鄉，斥鷃未易追翺翔，莫將滄溟比坳堂。"]'),
('ff5d5b83-f1cd-4632-8c43-f828938a98a0','慧林遇蒲傳正吕子進閒談','孔武仲','宋','宋诗','song-poetry','','[]','粲粲西臺彦，恂恂華省郎。',48,'全唐诗/poet.song.50000.json','["粲粲西臺彦，恂恂華省郎。", "相過金城静，縱語春晝長。", "逍遙喜莊生，傲誕尤稽康。", "紈扇不須搖，窗間襟袖凉。"]'),
('b42f5114-be7c-4b79-9fac-7628d1e08b1a','平陽歎','孔武仲','宋','宋诗','song-poetry','','[]','壞雲如山壓齊壘，六軍顔色如灰死。',112,'全唐诗/poet.song.50000.json','["壞雲如山壓齊壘，六軍顔色如灰死。", "高郎元自觧琵琶，萬歲無愁作天子。", "伯升何曾上青天，濺血遺痕芳草間。", "長城萬里自推仆，駿馬只馱馮小憐。", "姦臣百計爲蟊賊，不但妖娥解傾國。", "熊羆哮鬬蹙平陽，馮妃對鏡嬌櫳粧。", "死生契濶不相棄，雙雙刎頸長安市。"]'),
('dd7ebbf0-c8d5-40d0-aed2-a7bf91724e06','次韵和文潜休日不出  其一','孔武仲','宋','宋诗','song-poetry','','[]','清風入北窗，幽曠諧我心。',48,'全唐诗/poet.song.50000.json','["清風入北窗，幽曠諧我心。", "之子亦宴坐，焚香齋閣深。", "平時仙道家，蓬蒿倚瑤林。", "願言枉相過，小駟馳駸駸。"]'),
('8462f78c-155c-421f-a776-7bfda7f10acd','次韵和文潜休日不出  其二','孔武仲','宋','宋诗','song-poetry','','[]','文潜真可人，壯歲有老心。',48,'全唐诗/poet.song.50000.json','["文潜真可人，壯歲有老心。", "塵境暫來寄，天機元自深。", "鸞鳳翥赤靈，亦有鶴在林。", "冲天期一飛，載驟謝駸駸。"]'),
('20cae36a-41dc-46a0-ac6c-800ce8bd6367','尉氏道中','孔武仲','宋','宋诗','song-poetry','','[]','江縣花已繁，天畿草初茁。',48,'全唐诗/poet.song.50000.json','["江縣花已繁，天畿草初茁。", "春風動地來，萬鼓相應發。", "長郊不敢進，環坐借藁秸。", "前村應稍近，時有駝鳴𡇼。"]'),
('43933987-c621-4533-ba11-38209f423575','歸舍吟','孔武仲','宋','宋诗','song-poetry','','[]','長堤夾天溝，浩蕩東南流。',120,'全唐诗/poet.song.50000.json','["長堤夾天溝，浩蕩東南流。", "上有騎馬客，枯髯清兩眸。", "馬後無飛蓋，馬前無鳴騶。", "進無趦趄謁，退無輕俠遊。", "攜金入市賣，十舖不一售。", "包裹却歸舍，置之床一頭。", "半夜光滿屋，潜知是精鏐。", "貴物莫賤貨，不如深巷收。", "一旦遇知者，堆斗價可求。", "寄謝路傍子，神珠難闇投。"]'),
('231d6b83-4032-46e0-ac2f-33887f152756','秘閣觀唐法帖呈同舍諸公','孔武仲','宋','宋诗','song-poetry','','[]','雍熙真人金丹成，騎龍逍遙上太清。',200,'全唐诗/poet.song.50000.json','["雍熙真人金丹成，騎龍逍遙上太清。", "一時文物甚炳煥，至今高閣留峥嶸。", "道山不爲人間設，千秋長鎮白玉京。", "蓬萊諸仙當閒暇，相邀初作升天行。", "宫殿相望金碧動，觚稜半引霄漢明。", "鏘金寶鑰端門闢，四坐光芒炫奎壁。", "换鵝何處得遺踪，臨水當年應盡墨。", "波瀾入唐仍浩瀚，追躡餘塵猶十百。", "味入噉蔗真漸佳，力未半途多自畫。", "萬物莫如觀所聚，我生强半初相識。", "相期更乘飛雲來，琪花爲盤霞爲盃，嚥味沆瀣臨丹臺。", "興盡翩然欲歸去，從此心骨無塵埃。"]'),
('30f81cc5-8383-4de9-b7cb-84547af543b3','渡江','孔武仲','宋','宋诗','song-poetry','','[]','扁舟臨朝陽，匹馬渡江北。',48,'全唐诗/poet.song.50000.json','["扁舟臨朝陽，匹馬渡江北。", "志士豈懐居，征夫樂行役。", "東風吹高原，生意密如織。", "早晚卸塵鞍，皇州正春色。"]'),
('7e98fd4f-b702-4227-b3f0-4c28e201bb0c','家居三首  其一','孔武仲','宋','宋诗','song-poetry','','[]','毁譽平千載，窮通譬一毛。',24,'全唐诗/poet.song.50000.json','["毁譽平千載，窮通譬一毛。", "虹蜺千丈氣，豈便伏蓬蒿。"]'),
('fb37dd7c-1f60-4683-8dc1-90e6536f4747','家居三首  其二','孔武仲','宋','宋诗','song-poetry','','[]','曉色奪燈焰，秋寒侵薄帷。',48,'全唐诗/poet.song.50000.json','["曉色奪燈焰，秋寒侵薄帷。", "漏衝吟思斷，風從魂夢歸。", "萬慮不嬰抱，一心初息機。", "都忘塵土上，裘馬鬬輕肥。"]'),
('54e36ec7-b735-40de-b0cc-60559cd4897e','家居三首  其三','孔武仲','宋','宋诗','song-poetry','','[]','邑居不見江山景，去馬來車喧萬井。',64,'全唐诗/poet.song.50000.json','["邑居不見江山景，去馬來車喧萬井。", "冷落重簾日影西，蕭條四壁人初静。", "輕飈卷空雲冪冪，水影天光同一色。", "滿樽濁酒愁不醒，悵憶松江萬里行。"]'),
('5dd76448-3c4c-41c9-bf35-6b3aafae527b','偶書','孔武仲','宋','宋诗','song-poetry','','[]','暮上高樓聽村笛，清風寥寥吹澤國。',48,'全唐诗/poet.song.50000.json','["暮上高樓聽村笛，清風寥寥吹澤國。", "蒼山莽野百戰地，美木陰林四時色。", "浩蕩坤乾萬里中，風光盡属漁樵客。"]'),
('1e32b55a-165f-4d72-802f-f99f3670f43a','江上','孔武仲','宋','宋诗','song-poetry','','[]','秋空杳杳豁四顧，葛衣藜杖尋堤去。',48,'全唐诗/poet.song.50000.json','["秋空杳杳豁四顧，葛衣藜杖尋堤去。", "雙鳬拍波天外來，一棹凌風鏡中渡。", "静中榮辱興蕭條，指點蓬萊作歸路。"]'),
('64906374-3cc9-4605-96d4-1d6183f81cd7','龜石','孔武仲','宋','宋诗','song-poetry','','[]','平川洶洶經南國，匹練横拖半天碧。',384,'全唐诗/poet.song.50000.json','["平川洶洶經南國，匹練横拖半天碧。", "洪瀾巨浪之中央，忽見頽嵬太古石。", "此石由來幾許時，混元一氣初開闢。", "神功割破混沌胎，劃落半空隨霹靂。", "非黿非鼇不可辨，有若神龜見蹤跡。", "精剛不待媧皇錬，渾樸寧從巨靈擘。", "我知神物本天性，推移運轉非人力。", "當時大禹走天下，驅至九江爲納錫。", "萬牛攅車載不動，鐡軸峥嶸自堆積。", "秦皇鞭山移四海，怒視不能移咫尺。", "至今獨立猶驚人，地志山經不能測。", "千靈萬狀誰復知，一片堅頑粗可識。", "昂頭突出翠濤中，跪足横蹯九泉脈。", "勁殻縱横竇穴穿，當心一搭莓苔黑。", "淵潜不見曵尾狀，日爍猶驚負圖色。", "青髯剥落向何處，秋草綏綏晨露滴。", "勁徤曾支玉女床，斕斑似點乖龍額。", "漁翁未網先自駭，靈蓍欲伏安可得。", "黿鼉縮首不敢近，蝦蟇巡行夜戰惕。", "歲冬大寒百聖伏，圜圜勁勢無欹側。", "風磨霜錬無日休，髪鬢皴痕成兆坼。", "負才不免刳腸累，至珍惟藉天公惜。", "灼以炎皇之火精，釁以少昊之金液。", "神鑚鬼卜不見形，陰陽造化無遺策。"]'),
('94f059c3-d7f1-4c42-8d9d-8d5a6b08eb5e','雁翅夾作','孔武仲','宋','宋诗','song-poetry','','[]','川險固可畏，順風胡不行。',132,'全唐诗/poet.song.50000.json','["川險固可畏，順風胡不行。", "維舟雁翅浦，安此水一泓。", "宗慤萬里意，謝安江海情。", "子何獨惴惴，不慕天地鵬。", "傳聞此洲外，飛廉正豪横。", "萬馬拖縞練，千山雪飜崩。", "舟師亦無苦，老子悲震驚。", "此語真不遷，我懐諒難勝。", "從容把巵酒，坐對離騷經。", "起見皖山曲，沉沉夕煙生。", "開簾待明月，穏聽波瀾聲。"]'),
('38115f2f-1b46-4083-ab17-4db9fce4a301','松下','孔武仲','宋','宋诗','song-poetry','','[]','兀兀皆禪刹，亭亭歴蒿坡。',48,'全唐诗/poet.song.50000.json','["兀兀皆禪刹，亭亭歴蒿坡。", "蟬聲引我思，得蔭亦浩歌。", "蕭瑟美風日，顧瞻愛松蘿。", "收得物外趣，悠然養天和。"]'),
('c2c21148-8e0e-4a26-b633-d7e7ae8caf02','蜂兒','孔武仲','宋','宋诗','song-poetry','','[]','吴蠶爲人織，烹蛹以充腸。',48,'全唐诗/poet.song.50000.json','["吴蠶爲人織，烹蛹以充腸。", "况爾止工螫，焚巢何足傷。", "幸與衆果俱，得陳君子堂。", "咀嚼任所宜，故毒難自防。"]'),
('a7eea0ba-eae4-46cb-a8f5-2488de227236','加禄道中','孔武仲','宋','宋诗','song-poetry','','[]','僕夫疲躓復小休，晴雲澹澹更悠悠。',64,'全唐诗/poet.song.50000.json','["僕夫疲躓復小休，晴雲澹澹更悠悠。", "村陂無人鳥聲樂，澗草不動春風柔。", "長道此去星斗近，後期南來桑柘稠。", "懐哉吾祖不温席，老矣長卿今倦游。"]'),
('82f2214d-5345-4093-9066-1cc86907d711','發潯陽','孔武仲','宋','宋诗','song-poetry','','[]','西遊不敢避殘年，兄弟分攜楚水邊。',64,'全唐诗/poet.song.50000.json','["西遊不敢避殘年，兄弟分攜楚水邊。", "浩蕩東風回草木，曚曈曉色滿山川。", "却穿梅徑花争落，久憩郵亭日未偏。", "安佚竟非儒者事，虺隤我馬亦須鞭。"]'),
('7917abba-d6fa-47c8-9c11-d41ffcfb1a4d','至白湖驛寄四弟','孔武仲','宋','宋诗','song-poetry','','[]','江頭言别頗匆匆，暮止荒陂破屋中。',64,'全唐诗/poet.song.50000.json','["江頭言别頗匆匆，暮止荒陂破屋中。", "散盡烟雲無夜雨，喚驚鳬雁有春風。", "却思僧舍一少會，坐卷香醪百盞空。", "薄祿牽人非得己，相望秋思浩無窮。"]'),
('602f76bf-b239-4cf3-a701-5bc64672f37e','廣濟道中  其一','孔武仲','宋','宋诗','song-poetry','','[]','犖确山坡瘦馬行，年朝春色未分明。',64,'全唐诗/poet.song.50000.json','["犖确山坡瘦馬行，年朝春色未分明。", "蔫黄猶是舊時葉，格磔稍聞新歲聲。", "强涉遠涂非我好，亦逢佳景得心平。", "寒威斗起終豪横，更取村酤獨自傾。"]'),
('8130674f-519b-411c-834f-c9cac28d756b','廣濟道中  其二','孔武仲','宋','宋诗','song-poetry','','[]','南北驅馳不少休，人生何處足優游。',32,'全唐诗/poet.song.50000.json','["南北驅馳不少休，人生何處足優游。", "去年立馬龜峰道，亦是春泉繞舍流。"]'),
('1f8f58e3-9217-43db-af38-54b1f26e03b2','蘄春聽琵琶五首  其一','孔武仲','宋','宋诗','song-poetry','','[]','銀燭交光桂醸清，親朋相見苦多情。',32,'全唐诗/poet.song.50000.json','["銀燭交光桂醸清，親朋相見苦多情。", "春宵萬籟俱澄絕，初試鵾絃驟雨聲。"]'),
('c407d387-bc78-4b95-ae8b-f300446db1b9','蘄春聽琵琶五首  其二','孔武仲','宋','宋诗','song-poetry','','[]','新自潯陽江上來，雖聞此曲不悲哀。',32,'全唐诗/poet.song.50000.json','["新自潯陽江上來，雖聞此曲不悲哀。", "輕攏細撚俱清絕，指法何慚二善才。"]'),
('87e7ec0a-fd7b-41b6-8ed8-113a095a6be1','蘄春聽琵琶五首  其三','孔武仲','宋','宋诗','song-poetry','','[]','北踏胡霜漢馬驕，千秋琴調思嬌嬈。',32,'全唐诗/poet.song.50000.json','["北踏胡霜漢馬驕，千秋琴調思嬌嬈。", "華堂夜飲燈如晝，共聽新聲不寂寥。"]'),
('d6dd8ddd-1ca1-479e-b88f-8ba84a5f35e1','蘄春聽琵琶五首  其四','孔武仲','宋','宋诗','song-poetry','','[]','百轉干縈住復移，渾如啄木在高枝。',32,'全唐诗/poet.song.50000.json','["百轉干縈住復移，渾如啄木在高枝。", "春郊極目快晴後，峭絕一聲飛去時。"]'),
('92a63f3b-467b-4d44-906a-66e25740cc54','蘄春聽琵琶五首  其五','孔武仲','宋','宋诗','song-poetry','','[]','夜如何其夜未央，山城斗轉星煌煌。',32,'全唐诗/poet.song.50000.json','["夜如何其夜未央，山城斗轉星煌煌。", "收琴插撥各無語，酒美不知春漏長。"]'),
('c9a8e21d-9456-4bde-9483-77ef5e6d1807','過巴河寄經父','孔武仲','宋','宋诗','song-poetry','','[]','當時聯蓋入東都，回首推遷二紀餘。',64,'全唐诗/poet.song.50000.json','["當時聯蓋入東都，回首推遷二紀餘。", "此地山川終不改，浮生光景半成虚。", "清談劇飲夢寐隔，斷羽沉鱗音信踈。", "誰道豐城雙寶劍，紫煙長繞斗牛墟。"]'),
('510dc870-1770-4e7b-89ec-e5a942d27442','黄岡道中','孔武仲','宋','宋诗','song-poetry','','[]','悠悠驅馬歴山川，石火光中又度年。',64,'全唐诗/poet.song.50000.json','["悠悠驅馬歴山川，石火光中又度年。", "狼籍冷梅初著地，玲瓏幽澗已通泉。", "静思客子萬里道，那及山人一覺眠。", "香飯可添茶可試，回頭鄉國兩茫然。"]'),
('f4c759b4-b5cf-4fa9-a4c2-45e69d521113','故縣遇風二首  其一','孔武仲','宋','宋诗','song-poetry','','[]','狂風奔屋似輣車，旅枕清寒一倍加。',32,'全唐诗/poet.song.50000.json','["狂風奔屋似輣車，旅枕清寒一倍加。", "半夜雨聲収拾盡，曉來飛雪不成花。"]'),
('595a349c-a295-4000-b90c-dad683c2eabe','故縣遇風二首  其二','孔武仲','宋','宋诗','song-poetry','','[]','積雨成湖客路長，春風掀攪意何狂。',32,'全唐诗/poet.song.50000.json','["積雨成湖客路長，春風掀攪意何狂。", "殘雲吹盡真天力，乞我晴明入帝鄉。"]'),
('ce9d2ed5-f65f-4339-b598-943eccab57a1','闗山路三首  其一','孔武仲','宋','宋诗','song-poetry','','[]','朝來晴色頗鮮妍，最愛羣峰雪皓然。',32,'全唐诗/poet.song.50000.json','["朝來晴色頗鮮妍，最愛羣峰雪皓然。", "駐馬折梅看皎潔，臨流照影弄潺湲。"]'),
('1f9c5d3f-efba-4df1-a8ab-22dd34b71ed7','闗山路三首  其二','孔武仲','宋','宋诗','song-poetry','','[]','晨朝馬匹涉﨑嶇，映水梅花尚一株。',32,'全唐诗/poet.song.50000.json','["晨朝馬匹涉﨑嶇，映水梅花尚一株。", "旬日山川歴千里，江南雪蘂己全無。"]'),
('e2a173e5-7e5d-4624-a452-69e5a3d3c18c','闗山路三首  其三','孔武仲','宋','宋诗','song-poetry','','[]','馬力虺隤苦不禁，僕夫流汗亦沾襟。',32,'全唐诗/poet.song.50000.json','["馬力虺隤苦不禁，僕夫流汗亦沾襟。", "抱琴來冩非無意，愛此山高澗水深。"]'),
('5be83822-c2f0-4b58-bd12-8c76c12131ce','七里驛遇葉振卿秘校南歸三首  其一','孔武仲','宋','宋诗','song-poetry','','[]','繫馬郵亭寂寞中，遠沙喬木暮號風。',32,'全唐诗/poet.song.50000.json','["繫馬郵亭寂寞中，遠沙喬木暮號風。", "今宵不作江南夢，賴有之人笑語同。"]'),
('514ec729-37d6-4ab3-a04c-4dfcccce601d','七里驛遇葉振卿秘校南歸三首  其二','孔武仲','宋','宋诗','song-poetry','','[]','雪霰飄燈春夜長，相逢旅瑣莫悲傷。',32,'全唐诗/poet.song.50000.json','["雪霰飄燈春夜長，相逢旅瑣莫悲傷。", "朱顔緑髪輸君少，正好驅車上太行。"]'),
('68d652cd-d3cd-4b11-97d8-47ddd103f708','七里驛遇葉振卿秘校南歸三首  其三','孔武仲','宋','宋诗','song-poetry','','[]','湘水秦山此路分，更持盃酒勸行人。',32,'全唐诗/poet.song.50000.json','["湘水秦山此路分，更持盃酒勸行人。", "馬頭便作天涯别，好到江南看早春。"]'),
('da4406a7-a7a3-4bdc-b42f-0194282ceef9','題光山驛壁','孔武仲','宋','宋诗','song-poetry','','[]','跨縣連州幾疊山，爲君題作小潼闗。',64,'全唐诗/poet.song.50000.json','["跨縣連州幾疊山，爲君題作小潼闗。", "江湖不得長耕釣，塵土胡爲屢往還。", "漸入長郊趨坦蕩，却從平地望孱顔。", "何當輕騎重登險，指點湓城夕照間。"]'),
('b704494c-c7b6-4c74-b75d-2348640b941a','暖轎','孔武仲','宋','宋诗','song-poetry','','[]','垂簾爲户竹爲輿，千里征行似宴居。',32,'全唐诗/poet.song.50000.json','["垂簾爲户竹爲輿，千里征行似宴居。", "達摩無心惟穏坐，倪寛已老更耽書。"]'),
('3116be3b-bafb-4930-a7bc-dee1caf65c60','發加禄','孔武仲','宋','宋诗','song-poetry','','[]','白草蕭蕭漾早暉，籃輿輕穏去如飛。',32,'全唐诗/poet.song.50000.json','["白草蕭蕭漾早暉，籃輿輕穏去如飛。", "淮天軟暖多成雨，喜有輕寒犯客衣。"]'),
('c60de1d9-8871-4fe0-8684-45708019a843','至新息寄信州王守','孔武仲','宋','宋诗','song-poetry','','[]','熙熙樂國似登臺，北圃南亭春事催。',32,'全唐诗/poet.song.50000.json','["熙熙樂國似登臺，北圃南亭春事催。", "惆悵音塵難再會，瑞香應已遶簷開。"]'),
('41d73ec7-03e1-4cb5-a1d3-7d52a4a9cb05','渡淮','孔武仲','宋','宋诗','song-poetry','','[]','扁舟次淮浦，利涉得春風。',96,'全唐诗/poet.song.50000.json','["扁舟次淮浦，利涉得春風。", "脫險黿鼉畔，問津桑柘中。", "俯窺清奪魄，回望渺吞空。", "委注雖天力，經綸是禹功。", "縈紆數州接，浩蕩百源通。", "世久無昏墊，川今有會同。", "冷煙猶漠漠，暖渌己融融。", "暫得觀形勝，翛然慰轉蓬。"]'),
('14e1401e-acc4-480c-90ee-a725710a7004','發王務二首  其一','孔武仲','宋','宋诗','song-poetry','','[]','曉隨燈火背千家，落盡踈星見遠霞。',64,'全唐诗/poet.song.50000.json','["曉隨燈火背千家，落盡踈星見遠霞。", "一餉春聲回宿鳥，半天寒色在啼鴉。", "臨陂弱柳猶藏葉，當路殘梅已盡花。", "賴值時光正妍潤，穏看風物到京華。"]'),
('84800bd9-0e9e-41c6-af6e-e180b1d2b59c','發王務二首  其二','孔武仲','宋','宋诗','song-poetry','','[]','春水溝塍緑漸回，喧闐鳬雁作羣來。',64,'全唐诗/poet.song.50000.json','["春水溝塍緑漸回，喧闐鳬雁作羣來。", "新年風物動人意，薄宦驅馳豈自媒。", "未解驂龍追渺莽，何妨乘蹇歴崔嵬。", "田間亦有人閒逸，門掩柴荆晝未開。"]'),
('e99c97f4-9fa6-49c4-a074-0cbf57712cc7','從太守黄公登西湖待月臺','孔武仲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','星斗垂天月淡明，九衢歌鼓樂昇平。',32,'全唐诗/poet.song.50000.json','["星斗垂天月淡明，九衢歌鼓樂昇平。", "當時常侍傳呼處，只有荒陂鳬雁聲。"]'),
('295f5317-e949-4229-a638-69cdde83b65d','發蔡州','孔武仲','宋','宋诗','song-poetry','','[]','悠悠清曉歴長陂，楊柳溝塍雁鶩池。',64,'全唐诗/poet.song.50000.json','["悠悠清曉歴長陂，楊柳溝塍雁鶩池。", "風色著人寒料峭，日光生野暖融怡。", "鶴歸雲海心空在，雁度湖天力己疲。", "客路馳驅元不定，西遊應有再來時。"]'),
('3e3fc4ec-aead-49ca-a02b-dc7d04eebe01','題上蔡驛','孔武仲','宋','宋诗','song-poetry','','[]','駐馬東門己夕陽，淡雲衰草意何長。',64,'全唐诗/poet.song.50000.json','["駐馬東門己夕陽，淡雲衰草意何長。", "當年公子牽黄犬，此地春風吹白楊。", "千歲只疑經旦暮，一城猶可鑒興亡。", "我來不獨嗟行役，覧古依然爲閔傷。"]'),
('f154683a-34ba-4a10-98b8-90592ce88f50','書懐','孔武仲','宋','宋诗','song-poetry','','[]','昨寄家書道苦長，南州山迥水茫茫。',32,'全唐诗/poet.song.50000.json','["昨寄家書道苦長，南州山迥水茫茫。", "細將驛堠從頭數，凖擬今朝到故鄉。"]'),
('24255fa0-38e9-4c17-a2ca-1588fcc188ea','書事二首  其一','孔武仲','宋','宋诗','song-poetry','','[]','路逢行客向江州，勒馬荒郊爲少留。',32,'全唐诗/poet.song.50000.json','["路逢行客向江州，勒馬荒郊爲少留。", "家事滿懐無紙寫，好將言語付蒼頭。"]'),
('d74b85f3-ace3-46c8-8a05-14c9f07f487e','書事二首  其二','孔武仲','宋','宋诗','song-poetry','','[]','北來煙爨苦凄凉，金竈峥嶸突尾長。',32,'全唐诗/poet.song.50000.json','["北來煙爨苦凄凉，金竈峥嶸突尾長。", "滿篋香秔無處用，郵亭一飽待桄榔。"]'),
('cfff1e2a-5a7e-4126-a6fb-57ca7280f2cb','鳳凰陂','孔武仲','宋','宋诗','song-poetry','','[]','長陂寂寞斷鴟鴉，浩浩春風馬鬛斜。',32,'全唐诗/poet.song.50000.json','["長陂寂寞斷鴟鴉，浩浩春風馬鬛斜。", "待得春霖添水滿，只應從此却還家。"]'),
('3dfc3325-ce22-400a-9273-78da599968f9','入鄢陵界','孔武仲','宋','宋诗','song-poetry','','[]','馬蹄騰踏去如流，雨止車塵凝不浮。',32,'全唐诗/poet.song.50000.json','["馬蹄騰踏去如流，雨止車塵凝不浮。", "驛道夷平桑柘美，人言從此屬皇州。"]'),
('397364b6-e110-4648-9c86-bd15a122d67a','寄張端父','孔武仲','宋','宋诗','song-poetry','','[]','與君生世共飄蓬，會面荒陂寂寞中。',64,'全唐诗/poet.song.50000.json','["與君生世共飄蓬，會面荒陂寂寞中。", "芳酒一罇留夜語，旅程千里倦春風。", "追思薦鶚門闌舊，黙感跳丸歲月空。", "聞道束書遊帝闕，偷閒應肯訪衰翁。"]'),
('c42b8e2c-bb60-4b41-a871-7b9e549b96c6','折縣道中二首  其一','孔武仲','宋','宋诗','song-poetry','','[]','柳堤桃塢未怡融，浣濯新梢上淺紅。',32,'全唐诗/poet.song.50000.json','["柳堤桃塢未怡融，浣濯新梢上淺紅。", "一段春光來逼眼，棗騮嘶入柏林中。"]'),
('3b9261e1-0b63-4ccc-b540-be6f93ddea94','折縣道中二首  其二','孔武仲','宋','宋诗','song-poetry','','[]','紫沙隨馬細如篩，虎阜龍岡盡此馳。',32,'全唐诗/poet.song.50000.json','["紫沙隨馬細如篩，虎阜龍岡盡此馳。", "正望長安不回首，行人休賦灞陵詩。"]'),
('d81f4025-695d-47fd-a760-9d5c379ac9c6','過紫極宫感道士卓玘遺跡因賦詩以續諸公哀辭之後','孔武仲','宋','宋诗','song-poetry','','[]','武庫精兵接混茫，揮犀餘論意何長。',64,'全唐诗/poet.song.50000.json','["武庫精兵接混茫，揮犀餘論意何長。", "丹臺此日歸仙籍，紫極他年記道塲。", "暫别鬢毛渾老大，再來風月愈凄凉。", "不須隕涕悲鄰笛，亦對松筠爲感傷。"]'),
('64d2be2e-b246-4d62-bbbc-3fc310044e06','淮西道中','孔武仲','宋','宋诗','song-poetry','','[]','曾歴光黄嶺百尋，悲傷僕馬在嶇嶔。',64,'全唐诗/poet.song.50000.json','["曾歴光黄嶺百尋，悲傷僕馬在嶇嶔。", "却思前日山行苦，未比今朝車轍深。", "恐轉春風成猛雨，喜逢寒色閣輕陰。", "荒陂杳杳無人語，坐擁華貂只苦吟。"]'),
('a4210cf1-4049-4b46-b637-a6d43e31f751','暖轎二首  其一','孔武仲','宋','宋诗','song-poetry','','[]','雙袖深籠兩脚垂，朝寒乘快度荒陂。',32,'全唐诗/poet.song.50000.json','["雙袖深籠兩脚垂，朝寒乘快度荒陂。", "春風浩浩無邊際，似駕烏雲過海時。"]'),
('fd32fb6d-8728-4d2f-8438-9aac5421347f','暖轎二首  其二','孔武仲','宋','宋诗','song-poetry','','[]','淮山萬點雨晴初，日日寒帷望太虚。',32,'全唐诗/poet.song.50000.json','["淮山萬點雨晴初，日日寒帷望太虚。", "野濶天低今可壓，閉簾無事只看書。"]'),
('716d740e-d6f4-488f-9eb8-93dcf560589b','蔡州  其一','孔武仲','宋','宋诗','song-poetry','','[]','亭下湖光凝不流，銀燈玉斚綴綢繆。',32,'全唐诗/poet.song.50000.json','["亭下湖光凝不流，銀燈玉斚綴綢繆。", "主人今是真黄覇，民譽仍推郭細侯。"]'),
('e3ff4432-e410-409f-9034-e2af6dc5af40','蔡州  其二','孔武仲','宋','宋诗','song-poetry','','[]','憶曾醉看仙翁樹，騎馬重來二十年。',32,'全唐诗/poet.song.50000.json','["憶曾醉看仙翁樹，騎馬重來二十年。", "百尺湖臺蘸春渌，月華依舊到樽前。"]'),
('52e70bb7-f9b6-498e-af28-3950b156559c','寄信守王子明  其一','孔武仲','宋','宋诗','song-poetry','','[]','清香一炷道家儀，貝葉雲籖自誦持。',32,'全唐诗/poet.song.50000.json','["清香一炷道家儀，貝葉雲籖自誦持。", "盡是鈴齋瀟洒趣，紅塵奔走爾爲誰。"]'),
('9d9e4bf8-69e9-482d-9424-93ac5b798613','寄信守王子明  其二','孔武仲','宋','宋诗','song-poetry','','[]','年來江上苦多風，匹馬關山重復重。',32,'全唐诗/poet.song.50000.json','["年來江上苦多風，匹馬關山重復重。", "須信心閑爲樂地，主人窗檻有仙峰。"]'),
('d006b46f-6303-40f2-bf98-ea892027e9dc','答元珍見贈','孔武仲','宋','宋诗','song-poetry','','[]','汴柳毿毿緑蔽河，春城旅舍數相過。',64,'全唐诗/poet.song.50000.json','["汴柳毿毿緑蔽河，春城旅舍數相過。", "一聞高論煩襟豁，更捧新詩雅貺多。", "清鑒欲回荆玉價，蕪音難斷郢人歌。", "儒林志業期千古，舊事慚君話决科。"]'),
('b44c310e-4d61-4ad6-bec7-7ba1bf4d2481','和竹元珍夜雨','孔武仲','宋','宋诗','song-poetry','','[]','帝城塵土熱如湯，喜有殘宵雨送凉。',64,'全唐诗/poet.song.50000.json','["帝城塵土熱如湯，喜有殘宵雨送凉。", "旅枕夢雲縈宋玉，空階詩思感何郎。", "香迷舊徑煙初斷，燈倚輕寒焰不長。", "明日御溝應更好，一番晴色弄垂楊。"]'),
('7fdfe8c5-e868-4213-a458-7d403a341a73','和竹元珍寒食次韻','孔武仲','宋','宋诗','song-poetry','','[]','覉旅看春色，清明客帝鄉。',48,'全唐诗/poet.song.50000.json','["覉旅看春色，清明客帝鄉。", "花開禁苑密，柳嫋御溝長。", "玉勒無餘地，鈿車有剩香。", "塵埃不可久，歸夢楚山傍。"]'),
('3cbf83d9-6345-404b-b0f5-cbaef6eb4c12','旅枕','孔武仲','宋','宋诗','song-poetry','','[]','旅枕春風底，翛然一夢驚。',48,'全唐诗/poet.song.50000.json','["旅枕春風底，翛然一夢驚。", "漏移清禁遠，天入小窗明。", "桂玉梁園費，山椒楚客情。", "蕭條過百五，猶有賣花聲。"]'),
('53883214-acf9-4251-a14b-5d0a8c68b2a1','上已與江梅叔遊城西','孔武仲','宋','宋诗','song-poetry','','[]','禁園靈沼釀風光，恩許遊人入醉鄉。',64,'全唐诗/poet.song.50000.json','["禁園靈沼釀風光，恩許遊人入醉鄉。", "天上仙葩迷閬苑，月中清氣瀉銀潢。", "觴浮曲水青春暮，人在瀛洲白日長。", "却望宜秋指歸路，觚稜金碧正斜陽。"]'),
('56251e85-04cf-49f6-bd1d-ccb814ad1068','和竹元珍僧舍牡丹次韻','孔武仲','宋','宋诗','song-poetry','','[]','知到東隣賞牡丹，高僧防客頗艱難。',64,'全唐诗/poet.song.50000.json','["知到東隣賞牡丹，高僧防客頗艱難。", "鮮妍自是天花種，僻静應無俗眼看。", "葉似蟠桃相隠覆，蘂隨飛蝶漸凋殘。", "新詩清苦如郊島，肯羨侯家一醉歡。"]'),
('2da22a75-ba59-4833-9821-4f22e02f3268','送鄭無欲改官知合江縣二首  其一','孔武仲','宋','宋诗','song-poetry','','[]','曉闢未央宫，千袍擁赭紅。',48,'全唐诗/poet.song.50000.json','["曉闢未央宫，千袍擁赭紅。", "分班百寮底，得邑萬山中。", "麗筆元摛錦，新章更綰銅。", "定應隨驛召，不久滯巴東。"]'),
('b000c9ac-6d39-43b4-aa90-a544659c6f09','送鄭無欲改官知合江縣二首  其二','孔武仲','宋','宋诗','song-poetry','','[]','馬踏榆陰出漢關，邦人欣見錦衣還。',64,'全唐诗/poet.song.50000.json','["馬踏榆陰出漢關，邦人欣見錦衣還。", "東川却指舊遊處，北闕猶縈旅夢間。", "神女斷雲低楚峽，子規啼月慘巴山。", "知君利刃曾磨試，囹圄應從到日閒。"]'),
('ad2ebd4c-4862-423a-a116-754a618e8c73','呈竹元珍','孔武仲','宋','宋诗','song-poetry','','[]','一室蕭然傍禁城，塵埃不到旅懐清。',64,'全唐诗/poet.song.50000.json','["一室蕭然傍禁城，塵埃不到旅懐清。", "水流紅片知花落，雨浥蒼苔見笋生。", "感物己憐春寂寞，辭家憶是歲峥嶸。", "知君亦有淹留歎，歸夢西隨杜宇聲。"]'),
('b63bc974-306b-4996-bfeb-b8918b25c2de','榴花分題','孔武仲','宋','宋诗','song-poetry','','[]','東京石榴好，幾處照樓臺。',48,'全唐诗/poet.song.50000.json','["東京石榴好，幾處照樓臺。", "秀色裙難學，幽香蝶不來。", "連枝成幄幕，著子盡瓊瑰。", "乞取當窗種，年年四季開。"]'),
('2b2cdafb-132e-407c-9c23-a68a5b95fc71','經父云自到京止得一書頗懐憂想因寄','孔武仲','宋','宋诗','song-poetry','','[]','萬事峥嶸不自由，年來書信最綢繆。',64,'全唐诗/poet.song.50000.json','["萬事峥嶸不自由，年來書信最綢繆。", "雁飛玉塞無多地，人望神都正倚樓。", "祗恐邉風多浩蕩，故令音驛每遲留。", "何如欵段相隨出，鄉曲長爲馬少遊。"]'),
('e3965524-4c9e-4d00-8c26-667eacf98e4e','同賦京塵','孔武仲','宋','宋诗','song-poetry','','[]','白日臨黄道，紅塵滿玉京。',72,'全唐诗/poet.song.50000.json','["白日臨黄道，紅塵滿玉京。", "長風吹不盡，驟雨灑還清。", "不放虚空快，應同世界生。", "隨時勢用壯，度隙體能輕。", "舞榭凝添恨，歌梁堕趁聲。", "滄浪歸有計，行矣濯吾纓。"]'),
('e5941673-6598-4521-aee0-9408140d3589','同賦虎幀','孔武仲','宋','宋诗','song-poetry','','[]','何事斑然虎，來依静者堂。',96,'全唐诗/poet.song.50000.json','["何事斑然虎，來依静者堂。", "英姿猶讋物，畫手必殊常。", "快筆揮如雨，新縑洗似霜。", "淺山迎暮黯，叢葦得秋黄。", "炳煥霞紋縟，晶熒鏡目光。", "前趨疑摶取，却顧尚摧藏。", "仙子休騎去，將軍莫射傷。", "相隨千里客，更欲卷還鄉。"]'),
('292d279b-22d0-4ea3-ba2c-83057008fdd9','贈程瓌','孔武仲','宋','宋诗','song-poetry','','[]','識盡公卿更食貧，蒼髯瘦骨走京塵。',64,'全唐诗/poet.song.50000.json','["識盡公卿更食貧，蒼髯瘦骨走京塵。", "高談亦與時多忤，屢中方知術有神。", "前會渺茫渾不記，遠游蕭索復相親。", "疑公别得壺中趣，回首人間二十春。"]'),
('87676d2d-5fa4-4141-ade7-633cfadb51c5','筠州張氏追遠堂','孔武仲','宋','宋诗','song-poetry','','[]','慘淡佳城側，穹隆百尺堂。',48,'全唐诗/poet.song.50000.json','["慘淡佳城側，穹隆百尺堂。", "歲時如過隙，松柏已成行。", "玉笋登盤美，瓊醅入奠香。", "英靈似明月，時到此山傍。"]'),
('be207d64-23e3-4dfe-8a4f-1c4efba51ccf','同賦蚊','孔武仲','宋','宋诗','song-poetry','','[]','生長雖微細，翾飛逐盛陽。',96,'全唐诗/poet.song.50000.json','["生長雖微細，翾飛逐盛陽。", "吾身非鐡石，爾觜太銛剛。", "戢戢朝藏壁，喧喧暮滿房。", "燈前已環繞，簷角尚悠揚。", "紗眼能緣過，冰膚亦噬傷。", "用心均貨殖，損物亞螟蝗。", "栖宿麽蟲巧，追擒蝙蝠忙。", "秋風動天地，爾輩更凄凉。"]'),
('317590c9-54e6-4f96-900a-bb707e2a2729','同賦李夢符酒斗','孔武仲','宋','宋诗','song-poetry','','[]','酒斗公家物，規摹取自然。',48,'全唐诗/poet.song.50000.json','["酒斗公家物，規摹取自然。", "無時挹香酎，有象掛高天。", "緑玉燒爲撇，黄金打作船。", "何如學嘉量，深注瓦樽前。"]'),
('f54c8ebd-069d-4f3e-8eee-14bfaaa915e5','留别真戒講師','孔武仲','宋','宋诗','song-poetry','','[]','假山砌叠真相似，雙竹澆培畫不如。',64,'全唐诗/poet.song.50000.json','["假山砌叠真相似，雙竹澆培畫不如。", "萬屋塵囂無間斷，一軒氣象自清虚。", "持齋欲趁龍華會，升座能繙貝葉書。", "官罷亦將辭北闕，攜笻先訪故人居。"]'),
('2b2f21e1-30c1-4a71-8fe6-719ffe64ea67','次韻和歐勉甫見送','孔武仲','宋','宋诗','song-poetry','','[]','抱關委吏可忘年，而况吾徒志聖賢。',64,'全唐诗/poet.song.50000.json','["抱關委吏可忘年，而况吾徒志聖賢。", "策馬漸隨南去雁，寄聲應有北歸船。", "無情尺水猶能鍳，有志精金尚可鐫。", "願以此心推一邑，他時不負贈行篇。"]'),
('931b034b-1cfe-46b3-a068-4b45fe082dad','題報慈寺花藥園','孔武仲','宋','宋诗','song-poetry','','[]','少時隨衆蹂京塵，曾倚朱欄看晚春。',32,'全唐诗/poet.song.50000.json','["少時隨衆蹂京塵，曾倚朱欄看晚春。", "二十年間頭半白，方知花木觧磨人。"]'),
('d9305511-24a8-4a05-9b87-94f336390b72','勝師堂雙竹','孔武仲','宋','宋诗','song-poetry','','[]','累石爲峰太謹嚴，故排雙竹闢修纎。',32,'全唐诗/poet.song.50000.json','["累石爲峰太謹嚴，故排雙竹闢修纎。", "天風似亦喜清净，時嫋枝梢爲埽簷。"]'),
('58988fdd-3b2b-4717-8252-1a3805fd9565','驟雨','孔武仲','宋','宋诗','song-poetry','','[]','驟雨隨風入漢關，傾都驩喜破愁顔。',32,'全唐诗/poet.song.50000.json','["驟雨隨風入漢關，傾都驩喜破愁顔。", "電光猶恐龍潜伏，閃爍餘輝遶壁間。"]'),
('193729ac-7553-4f58-939a-f111a292b332','出京','孔武仲','宋','宋诗','song-poetry','','[]','整頓歸裝夜不眠，籃輿出趁早涼天。',32,'全唐诗/poet.song.50000.json','["整頓歸裝夜不眠，籃輿出趁早涼天。", "東南爽氣來相逼，葉底初聞一片蟬。"]'),
('253b2afa-ea8c-4365-a73d-3fc073eb02db','早食鐡佛寺','孔武仲','宋','宋诗','song-poetry','','[]','破壁題名滿，往還如置郵。',48,'全唐诗/poet.song.50000.json','["破壁題名滿，往還如置郵。", "山河萬里道，車馬片時休。", "白日初騰曉，凉蟬已喚秋。", "便添山野興，咫尺帝王州。"]'),
('5577ca30-6619-4a74-a25b-265378d55ab5','寄林次中','孔武仲','宋','宋诗','song-poetry','','[]','曉踏朱仙月，還思昨日詩。',48,'全唐诗/poet.song.50000.json','["曉踏朱仙月，還思昨日詩。", "尚攜漫刺謁，不爽故人期。", "宫闕觚稜失，山河向背移。", "悠悠芳草路，恰似别家時。"]'),
('35e9bf21-7a3a-4228-8bab-2a1510b64a12','鄢陵界中','孔武仲','宋','宋诗','song-poetry','','[]','古縣居人少，歸軒喜氣多。',48,'全唐诗/poet.song.50000.json','["古縣居人少，歸軒喜氣多。", "連天皆秫黍，蓋水有蓮荷。", "宿雨雲容薄，微風日氣和。", "征行不辭遠，所得是吟哦。"]'),
('6fccfb56-9fd4-4680-ad05-a12442001152','侯塘渡','孔武仲','宋','宋诗','song-poetry','','[]','空山宿雨漲前溪，芳草連雲欲渡時。',32,'全唐诗/poet.song.50000.json','["空山宿雨漲前溪，芳草連雲欲渡時。", "落日人心急星火，招招舟子更來遲。"]'),
('6ea2ef18-6589-46b6-9726-acd3143fe572','田間','孔武仲','宋','宋诗','song-poetry','','[]','百頃陂田過雨清，新秧漠漠似苔生。',32,'全唐诗/poet.song.50000.json','["百頃陂田過雨清，新秧漠漠似苔生。", "津梁只欲憑忠信，南去無心問耦耕。"]'),
('2076af0a-9249-465d-a349-5b371c50f4db','羅港','孔武仲','宋','宋诗','song-poetry','','[]','八節灘頭駐馬蹄，淙淙流水日沉西。',64,'全唐诗/poet.song.50000.json','["八節灘頭駐馬蹄，淙淙流水日沉西。", "歲時久己成陳迹，風景全然似此溪。", "蘭棹倚洲人競過，籃輿索筆我閒題。", "桃源仙境今何在，懊惱嬌鸎向暮啼。"]'),
('390118c7-604f-4604-8225-fa815d4672d4','遇行人','孔武仲','宋','宋诗','song-poetry','','[]','我託南車去，君挐北轡還。',24,'全唐诗/poet.song.50000.json','["我託南車去，君挐北轡還。", "相看一夢裏，好入畫圖間。"]'),
('ef35ca84-eaaf-40b6-8ec3-d3700c9b7796','晚行','孔武仲','宋','宋诗','song-poetry','','[]','客子念家意，遠行投驛心。',48,'全唐诗/poet.song.50000.json','["客子念家意，遠行投驛心。", "亂鴉争噪晚，宿鳥已歸林。", "漸覺殘陽盡，更憂前港深。", "雲師頗知足，久久困狂霖。"]'),
('6f9f4ec2-c028-4cc7-a636-2ffc157a5654','過淮','孔武仲','宋','宋诗','song-poetry','','[]','積雨雖收霽，清淮更渺茫。',48,'全唐诗/poet.song.50000.json','["積雨雖收霽，清淮更渺茫。", "地形真水府，波面似錢塘。", "雲日侵衣淡，天風入袖凉。", "輕輿過南岸，轉覺近家鄉。"]'),
('3ccd20e9-5af3-4109-9f51-6a8c4682e362','關山五首  其一','孔武仲','宋','宋诗','song-poetry','','[]','曉上春風第一楂，豁然披眼盡天涯。',32,'全唐诗/poet.song.50000.json','["曉上春風第一楂，豁然披眼盡天涯。", "原田極望人稀少，掩映茅篁數十家。"]'),
('655a7b79-6bc8-4301-ad3a-60fabd13ba3b','關山五首  其二','孔武仲','宋','宋诗','song-poetry','','[]','嶺盡還臨水，溪窮又有山。',24,'全唐诗/poet.song.50000.json','["嶺盡還臨水，溪窮又有山。", "人遊明鏡裏，鳥語白雲間。"]'),
('d6a9309b-663d-4e5d-ac80-5dfad438655f','關山五首  其三','孔武仲','宋','宋诗','song-poetry','','[]','少婦織新絲，人來不下機。',24,'全唐诗/poet.song.50000.json','["少婦織新絲，人來不下機。", "斜陽過茅屋，郎亦採樵歸。"]'),
('a09e6877-539c-481e-af96-40a3dde843bd','關山五首  其四','孔武仲','宋','宋诗','song-poetry','','[]','北地樵蘇寸草空，不如燒炭此山中。',32,'全唐诗/poet.song.50000.json','["北地樵蘇寸草空，不如燒炭此山中。", "良材合抱隨斤斧，豈顧區區櫟與楓。"]'),
('7c137a57-814d-4715-b1ef-a2c22138d6e5','關山五首  其五','孔武仲','宋','宋诗','song-poetry','','[]','山溪百轉水泠泠，栽插新秧次第成。',32,'全唐诗/poet.song.50000.json','["山溪百轉水泠泠，栽插新秧次第成。", "風趕緑茸無斷處，他時粒粒是香秔。"]'),
('b42bb385-7bab-4d26-842d-1c3d8623599a','萬松亭','孔武仲','宋','宋诗','song-poetry','','[]','鬱鬱青山夾路松，行人笑語緑陰中。',64,'全唐诗/poet.song.50000.json','["鬱鬱青山夾路松，行人笑語緑陰中。", "排雲架壑無餘地，洒面侵襟有好風。", "一日勞心非欲速，千年流惠亦何窮。", "我來俯仰尋遺愛，更喜清虚萬慮空。"]'),
('2fe69c53-038c-4bfe-97ff-b0fe3a23ade0','聽蟬','孔武仲','宋','宋诗','song-poetry','','[]','畏日流金不斷聲，松風澗水助泠泠。',32,'全唐诗/poet.song.50000.json','["畏日流金不斷聲，松風澗水助泠泠。", "我來蕭散無餘事，得倚籃輿細細聽。"]'),
('97fe49cb-c39a-436a-838c-b2da0944af3e','過馬鞍山','孔武仲','宋','宋诗','song-poetry','','[]','足歴黄州百叠山，更無平地只岡巒。',64,'全唐诗/poet.song.50000.json','["足歴黄州百叠山，更無平地只岡巒。", "物皆枯槁非人世，石最崔嵬是馬鞍。", "畏日流金紅艷艷，亂沙堆雪白漫漫。", "﨑嶇出盡聊休息，喜有松聲六月寒。"]'),
('c06508a7-47a2-4127-9a4d-9a1f8892082b','喜至亭','孔武仲','宋','宋诗','song-poetry','','[]','嶺路蟠蟠石似龍，亭軒更在最高峰。',64,'全唐诗/poet.song.50000.json','["嶺路蟠蟠石似龍，亭軒更在最高峰。", "九江山水吾家近，四祖煙霞晚色濃。", "吟興不惟誇美景，行人當爲破愁容。", "前村有酒青帘遠，强飲岩間水一鍾。"]'),
('ec45e7a4-c9b6-4c66-8491-b5edd4f5fc8f','陶子駿佚老堂','孔武仲','宋','宋诗','song-poetry','','[]','不逐漁商不問農，悠然今作鹿皮翁。',64,'全唐诗/poet.song.50000.json','["不逐漁商不問農，悠然今作鹿皮翁。", "地臨白傅荒臺畔，人在華胥樂國中。", "一榻遠分廬阜月，兩軒平揖廣寒風。", "杖藜亦欲頻還往，肯使清閒併屬公。"]'),
('82f02bab-68c4-430a-aa41-f63e3b996d4c','謁張文思於湖西不見','孔武仲','宋','宋诗','song-poetry','','[]','綠竹陰深屋數間，籃輿來傍古溪邊。',64,'全唐诗/poet.song.50000.json','["綠竹陰深屋數間，籃輿來傍古溪邊。", "垂楊芳草迷三徑，斜日新秋媚一川。", "澎湃直連湓口浪，逍遙如泛剡中船。", "山陰不見戴安道，回首西風亦浩然。"]'),
('9f3ffe51-cc9c-4006-a4ca-e13029ba9fcd','君表自西林還城中以詩二首爲别  其一','孔武仲','宋','宋诗','song-poetry','','[]','天上優游侍從臣，還鄉晝錦坐生春。',64,'全唐诗/poet.song.50000.json','["天上優游侍從臣，還鄉晝錦坐生春。", "不矜富貴知餘事，同訪溪山有故人。", "方外笑談無畛域，雨餘泉石長精神。", "西林路口嗟輕别，善護青雲萬里身。"]'),
('b6cf27eb-de3c-44d2-a382-803cbb808935','君表自西林還城中以詩二首爲别  其二','孔武仲','宋','宋诗','song-poetry','','[]','巉巉廬阜秀侵天，有意登臨己十年。',64,'全唐诗/poet.song.50000.json','["巉巉廬阜秀侵天，有意登臨己十年。", "美味君纔嘗一臠，明珠我欲探重淵。", "他時白首須歸隐，此去青雲更著鞭。", "扶杖爲公尋好處，往來同逕得參禪。"]'),
('e2a07891-db41-4c86-bcb3-d554d7d267cb','入山三首  其一','孔武仲','宋','宋诗','song-poetry','','[]','冠蓋成陰中路迴，獨攜蓮社道人來。',32,'全唐诗/poet.song.50000.json','["冠蓋成陰中路迴，獨攜蓮社道人來。", "千巖萬壑初相識，分付晴嵐面面開。"]'),
('a48bfd3e-c7c4-4e8d-8cba-0a7301e17234','入山三首  其二','孔武仲','宋','宋诗','song-poetry','','[]','路出西林興倍長，輕衫短蓋入秋陽。',64,'全唐诗/poet.song.50000.json','["路出西林興倍長，輕衫短蓋入秋陽。", "層崖蔽日多清影，深谷迷人有異香。", "訪古不辭穿絕磴，參禪直爲遍諸方。", "此身似是遼東鶴，偶逐飛雲到故鄉。"]'),
('da9f32a5-42d1-4472-8145-b6362f37c021','入山三首  其三','孔武仲','宋','宋诗','song-poetry','','[]','十歲不出還可嗟，經旬遍走梵王家。',32,'全唐诗/poet.song.50000.json','["十歲不出還可嗟，經旬遍走梵王家。", "羣仙拍手向人笑，方朔今來何晚耶。"]'),
('a855cf8e-1d26-447a-9bd4-efbfd020a0e5','山間三首  其一','孔武仲','宋','宋诗','song-poetry','','[]','江城八月苦炎暉，瀟洒山間挾纊時。',32,'全唐诗/poet.song.50000.json','["江城八月苦炎暉，瀟洒山間挾纊時。", "峰頂寶林俱勝絕，籃輿從此上天池。"]'),
('d789e7ad-0155-4b7c-a678-3e6d2aad2038','山間三首  其二','孔武仲','宋','宋诗','song-poetry','','[]','絕壁藤蘿喜可攀，更無平地只青山。',32,'全唐诗/poet.song.50000.json','["絕壁藤蘿喜可攀，更無平地只青山。", "路回亦有虚明處，江北江南指掌間。"]'),
('7a221e2f-f2df-44dc-a099-1068ce2b7d38','山間三首  其三','孔武仲','宋','宋诗','song-poetry','','[]','柔條細葉謾成叢，亦有懸崖出小紅。',32,'全唐诗/poet.song.50000.json','["柔條細葉謾成叢，亦有懸崖出小紅。", "欲試金丹求不死，靈苖應在此山中。"]'),
('dcc13cde-c70e-4e21-9fcb-33f1c7e15732','峰頂','孔武仲','宋','宋诗','song-poetry','','[]','苦霰悲風作斧斤，千秋松竹損精神。',32,'全唐诗/poet.song.50000.json','["苦霰悲風作斧斤，千秋松竹損精神。", "似聞犬吠白雲外，猶有秦時避世人。"]'),
('4ee2de08-83c1-45f5-8de4-b7d893a0e6a1','錦繡谷二首  其一','孔武仲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','江城已月芳菲盡，殘紫深緋到谷中。',32,'全唐诗/poet.song.50000.json','["江城已月芳菲盡，殘紫深緋到谷中。", "最是廬山佳麗處，我來蕭颯已秋風。"]'),
('0a89cd58-c1bc-47f8-99bf-db90e8338436','錦繡谷二首  其二','孔武仲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','帝憶廬山萬玉妃，狂風浩蕩喚春歸。',32,'全唐诗/poet.song.50000.json','["帝憶廬山萬玉妃，狂風浩蕩喚春歸。", "繁華過眼一朝盡，惟有珍禽無數飛。"]'),
('9961ddf9-cc66-4ac1-a9db-76c2b962fa28','歸宗寺','孔武仲','宋','宋诗','song-poetry','','[]','海會寮中略問禪，高僧剛道語難傳。',32,'全唐诗/poet.song.50000.json','["海會寮中略問禪，高僧剛道語難傳。", "却詢耶舍羅那事，俯仰人間七百年。"]'),
('06736a05-cb7f-4842-b667-597b0c8f558a','自歸宗入靈溪觀  其一','孔武仲','宋','宋诗','song-poetry','','[]','紫霄峰下有禪林，瓦結青瑤地布金。',32,'全唐诗/poet.song.50000.json','["紫霄峰下有禪林，瓦結青瑤地布金。", "聞道靈溪纔咫尺，攜笻不覺後山深。"]'),
('9aed1dee-b340-4bd6-8486-2e20f85d5b2e','自歸宗入靈溪觀  其二','孔武仲','宋','宋诗','song-poetry','','[]','石橋横路水濺濺，百尺琳宫館列仙。',32,'全唐诗/poet.song.50000.json','["石橋横路水濺濺，百尺琳宫館列仙。", "聞有秦人來避世，至今修竹上參天。"]'),
('75c1e526-c87a-4d19-a9f3-d1535e92b713','瀑布六首  其一','孔武仲','宋','宋诗','song-poetry','','[]','懸崖傾注自成川，六月溪風爲肅然。',32,'全唐诗/poet.song.50000.json','["懸崖傾注自成川，六月溪風爲肅然。", "不是化工移用巧，尾閭應亦有窮年。"]'),
('addd6562-e58e-4d14-b027-42050cecbae2','瀑布六首  其二','孔武仲','宋','宋诗','song-poetry','','[]','山頭飛瀑海中潮，此理誰能問泬寥。',32,'全唐诗/poet.song.50000.json','["山頭飛瀑海中潮，此理誰能問泬寥。", "秪恐分流從月窟，桂香無限到西橋。"]'),
('d6b6f153-c0dd-4e77-bac4-61d1cde0777e','瀑布六首  其三','孔武仲','宋','宋诗','song-poetry','','[]','晴天如練雨成雷，飛洒青空亦快哉。',32,'全唐诗/poet.song.50000.json','["晴天如練雨成雷，飛洒青空亦快哉。", "推倒西峰一百丈，試觀河漢所從來。"]'),
('9312edfa-5cac-4a7f-9b15-a82a441f321e','瀑布六首  其四','孔武仲','宋','宋诗','song-poetry','','[]','沉浮又似綴汀鷗，石齒横斜咽復流。',32,'全唐诗/poet.song.50000.json','["沉浮又似綴汀鷗，石齒横斜咽復流。", "莫放陰雲遮洞府，最宜明月挂高秋。"]'),
('3f90796d-c560-4308-b97c-d7ee38743253','瀑布六首  其五','孔武仲','宋','宋诗','song-poetry','','[]','接石爲槽遶畫簷，清風爽氣坐來添。',32,'全唐诗/poet.song.50000.json','["接石爲槽遶畫簷，清風爽氣坐來添。", "恰從天外爲飛瀑，又向人間作水簾。"]'),
('0226ec9a-548a-4e0f-8aaa-893612ceb44b','瀑布六首  其六','孔武仲','宋','宋诗','song-poetry','','[]','窈窕東注壑，舒徐南入江。',24,'全唐诗/poet.song.50000.json','["窈窕東注壑，舒徐南入江。", "寄聲滄海若，高潔此難雙。"]'),
('5d78e1c0-be6b-4130-a543-a9954b8eae6b','玉淵亭龍潭','孔武仲','宋','宋诗','song-poetry','','[]','清潭千古照懸崖，崖上飛流動地來。',32,'全唐诗/poet.song.50000.json','["清潭千古照懸崖，崖上飛流動地來。", "咫尺語言聞不得，夕陽佳景更徘徊。"]'),
('73a5f059-23ab-4cd6-9bb5-03d3dc9cad4d','晚坐三峽橋','孔武仲','宋','宋诗','song-poetry','','[]','雨施雷音動十方，檀那奔走助津梁。',64,'全唐诗/poet.song.50000.json','["雨施雷音動十方，檀那奔走助津梁。", "泉舂石竇千秋白，風掃松橋六月凉。", "潑潑小魚生處樂，濺濺餘瀨静中忙。", "塵襟正欲留瀟灑，坐聽清音到夕陽。"]'),
('fafac858-6084-43b6-a09b-028e87df5592','雜題二首  其一','孔武仲','宋','宋诗','song-poetry','','[]','青青矗矗水縈回，散入溪田媚復哀。',32,'全唐诗/poet.song.50000.json','["青青矗矗水縈回，散入溪田媚復哀。", "天上清音難猝記，兹遊悔不負琴來。"]'),
('6a1376e0-00f9-4e89-90bc-04c6abd10637','雜題二首  其二','孔武仲','宋','宋诗','song-poetry','','[]','曲澗低泉左右鳴，步虚宫殿響琚珩。',32,'全唐诗/poet.song.50000.json','["曲澗低泉左右鳴，步虚宫殿響琚珩。", "清風杳不知來處，散入松間作鳳笙。"]'),
('8babadb4-2d8c-4e48-9d62-8c84355e8b2f','至新息寄四弟','孔武仲','宋','宋诗','song-poetry','','[]','江上分飛已隔年，春風初轉月初圓。',32,'全唐诗/poet.song.50000.json','["江上分飛已隔年，春風初轉月初圓。", "今宵相望長淮北，只有星河共一天。"]'),
('c72519fa-6e25-482a-accf-06f34a9c29f1','送殷父弟知衡州','孔武仲','宋','宋诗','song-poetry','','[]','浮雲富貴本無情，出守衡陽地望清。',64,'全唐诗/poet.song.50000.json','["浮雲富貴本無情，出守衡陽地望清。", "隴畝良田多樂歲，江山秀氣入重城。", "鈴齋宴衎茶罇佚，棠蔭優游獄訟平。", "應念區區大梁客，朝衣顛倒趁雞鳴。"]'),
('d2503131-3040-4b19-80cd-1f8a734a516a','李公擇山房  其一','孔武仲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','碧落仙官侍玉除，至今遺迹在匡廬。',32,'全唐诗/poet.song.50000.json','["碧落仙官侍玉除，至今遺迹在匡廬。", "當時兄弟俱年少，他日歸榮比二疏。"]'),
('c3bdd366-c5bf-495f-9c6a-2290a89197b6','李公擇山房  其二','孔武仲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','松篁入路水濺濺，自是廬山小洞天。',32,'全唐诗/poet.song.50000.json','["松篁入路水濺濺，自是廬山小洞天。", "盡道秀才心好静，誰知風骨是真仙。"]'),
('42b34fa0-e152-4fba-8a3e-debd39a9002a','陳翰林遊天池約相會于栖賢久之不至','孔武仲','宋','宋诗','song-poetry','','[]','廬阜西頭是謫仙，籃輿正欲上青天。',32,'全唐诗/poet.song.50000.json','["廬阜西頭是謫仙，籃輿正欲上青天。", "霓旌羽蓋何時返，悵望洪崖阻拍肩。"]'),
('1b356c6c-1697-4002-81ba-ff4d0d953859','寄南康徐大夫','孔武仲','宋','宋诗','song-poetry','','[]','山南泉石有餘清，幾日籃輿天上行。',32,'全唐诗/poet.song.50000.json','["山南泉石有餘清，幾日籃輿天上行。", "亦欲西園伴飛蓋，龎公不慣入州城。"]'),
('89ead67f-3591-4d38-bd6c-4a37453df3f2','白鶴觀','孔武仲','宋','宋诗','song-poetry','','[]','洞天人遠矣，琳館有遺蹤。',24,'全唐诗/poet.song.50000.json','["洞天人遠矣，琳館有遺蹤。", "願棄人間事，優游慕赤松。"]'),
('8e85b18a-0971-44a0-aab9-3b7346be347b','慧日寺  其一','孔武仲','宋','宋诗','song-poetry','','[]','山外歸來酒半酣，衣襟翠色貯煙嵐。',32,'全唐诗/poet.song.50000.json','["山外歸來酒半酣，衣襟翠色貯煙嵐。", "泉聲自是小三峽，林色可名東萬杉。"]'),
('c79a1f87-df1c-44e5-a562-8014588eb9a9','慧日寺  其二','孔武仲','宋','宋诗','song-poetry','','[]','江面深沉带地流，清風爽氣入層樓。',32,'全唐诗/poet.song.50000.json','["江面深沉带地流，清風爽氣入層樓。", "倚欄却認登浮玉，平看滄溟萬里秋。"]'),
('8be0970e-d6c7-4d96-8787-6672d50e9e44','答李景文見寄','孔武仲','宋','宋诗','song-poetry','','[]','金沙會面慰飄蓬，況得連朝笑語同。',64,'全唐诗/poet.song.50000.json','["金沙會面慰飄蓬，況得連朝笑語同。", "縱飲不知明月墮，納凉尤愛小軒東。", "郵亭送别凄凉後，江郭凭欄悵望中。", "兩幅新詩尤俊邁，泠然醒我以清風。"]'),
('15cafc89-6513-4d85-a9fd-859ba2e27a28','維那觀師以偈示余求詩爲贈因成兩絕句  其一','孔武仲','宋','宋诗','song-poetry','','[]','擾擾長途策馬回，柴門寂寞晝慵開。',32,'全唐诗/poet.song.50000.json','["擾擾長途策馬回，柴門寂寞晝慵開。", "清香一炷茶一啜，賴有高人數往來。"]'),
('554191c2-f9b5-4345-9ed3-2d1781367118','維那觀師以偈示余求詩爲贈因成兩絕句  其二','孔武仲','宋','宋诗','song-poetry','','[]','夾路長松緑蔭繁，送君從此入幽關。',32,'全唐诗/poet.song.50000.json','["夾路長松緑蔭繁，送君從此入幽關。", "銅缾錫杖無拘繫，正好窺尋瀑水源。"]'),
('ca4c3179-5df3-423b-bc58-e8df99462278','黄州夜泊聽水聲因爲絕句以廣歐陽公詩話','孔武仲','宋','宋诗','song-poetry','','[]','泠然非徴亦非商，夜久清音入夢長。',32,'全唐诗/poet.song.50000.json','["泠然非徴亦非商，夜久清音入夢長。", "人道官蛙成鼓吹，我知風水是霓裳。"]'),
('a0f9d2c6-2f27-47d0-a856-43acb5c8c359','黄州二首  其一','孔武仲','宋','宋诗','song-poetry','','[]','客路深秋一轉蓬，淮天牢落此將窮。',64,'全唐诗/poet.song.50000.json','["客路深秋一轉蓬，淮天牢落此將窮。", "城開雲水蒼茫處，人在茅篁掩映中。", "對岸武昌風月近，千年赤壁是非空。", "悠悠陳迹慵開口，謾把筠竿伴釣翁。"]'),
('8e8ebca9-11a7-49e8-be71-f6bc6b16ff47','黄州二首  其二','孔武仲','宋','宋诗','song-poetry','','[]','山上泉聲風雨來，門前峰色畫屏開。',32,'全唐诗/poet.song.50000.json','["山上泉聲風雨來，門前峰色畫屏開。", "仙居洞裏桃花古，不是劉郎去後栽。"]'),
('b60b9014-98d7-4600-8b28-d8d16b1e96b5','吴章嶺作','孔武仲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山北轉是吴章，岩草紛紛静有香。',32,'全唐诗/poet.song.50000.json','["廬山北轉是吴章，岩草紛紛静有香。", "洞口流泉似相送，人間天上莫相忘。"]'),
('ce55df9e-cd8f-45bc-b597-f57163ec4543','送僧惠芝歸東林','孔武仲','宋','宋诗','song-poetry','','[]','東林開士解談禪，共住千岩萬壑前。',32,'全唐诗/poet.song.50000.json','["東林開士解談禪，共住千岩萬壑前。", "回首歸雲不知處，林間相遇是何年。"]'),
('2be3f443-469b-408a-87f8-de6aeccf5481','成化縣二首  其一','孔武仲','宋','宋诗','song-poetry','','[]','化成真化出，絕險起朱欄。',24,'全唐诗/poet.song.50000.json','["化成真化出，絕險起朱欄。", "直下臨無處，江城一掬看。"]'),
('3b7950c2-c8af-45c8-b8ea-f796f791c3f1','成化縣二首  其二','孔武仲','宋','宋诗','song-poetry','','[]','登覽多清興，衣襟有白雲。',24,'全唐诗/poet.song.50000.json','["登覽多清興，衣襟有白雲。", "松風不知際，仙籟坐中聞。"]'),
('5c3643b9-7908-42c3-b42c-237a78f327e1','五老峰','孔武仲','宋','宋诗','song-poetry','','[]','峻叠起青峰，森然五老翁。',72,'全唐诗/poet.song.50000.json','["峻叠起青峰，森然五老翁。", "雲將色共古，天與壽無窮。", "突兀巔崖峭，駢羅面勢雄。", "三光同孕育，四岳是兒童。", "傑立層霄際，曾經壞刼中。", "夢齡應可錫，圖寫獻堯宫。"]'),
('d9922094-752a-45f2-8d3d-8b8f76554a00','次韻答李子約見贈','孔武仲','宋','宋诗','song-poetry','','[]','江縣山奇水亦清，古今賢宰繼聲名。',64,'全唐诗/poet.song.50000.json','["江縣山奇水亦清，古今賢宰繼聲名。", "施爲豈厭地閒僻，學行久推君老成。", "桂籍掇科論世契，錦囊留句荷交情。", "當年入洛多英俊，文彩誰如陸士衡。"]'),
('264fcb24-ef31-453a-891f-cf4d773aafcf','晚登庾樓','孔武仲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','却從江漢望匡廬，湓口風波日愈疏。',64,'全唐诗/poet.song.50000.json','["却從江漢望匡廬，湓口風波日愈疏。", "滿甕尚留桑落酒，登盤今有武昌魚。", "斜陽柳色明碕岸，纎月波光濕太虚。", "鸚鵡洲前弔豪士，重將詞賦爲君書。"]'),
('df539d36-a7b6-41f1-a835-1a50f5f62325','順風發江夏','孔武仲','宋','宋诗','song-poetry','','[]','西江風浪夜喧豗，清曉猶聞萬籟哀。',64,'全唐诗/poet.song.50000.json','["西江風浪夜喧豗，清曉猶聞萬籟哀。", "水驛正隨衡雁去，雲帆初學海鵬開。", "山横别浦跳丸度，席對長瀾陣馬來。", "快意須防太豪横，斜陽荒港少徘徊。"]'),
('ccbcf722-1c10-4a62-a76e-e47e49d6b839','嘉魚界中作','孔武仲','宋','宋诗','song-poetry','','[]','楚澤秋窮未有霜，飄然如雁去隨陽。',64,'全唐诗/poet.song.50000.json','["楚澤秋窮未有霜，飄然如雁去隨陽。", "連空積藹湖天闇，極目無人水國荒。", "破浪不須論萬里，佩蘭聊欲寄三湘。", "駝裘更作春暉暖，嬴得瞢騰晝夢長。"]'),
('dd053ec2-0160-4352-8e22-f48a9a9ee24f','巴陵界中作  其一','孔武仲','宋','宋诗','song-poetry','','[]','曲曲秋江灧灔波，直疑乘興到銀河。',32,'全唐诗/poet.song.50000.json','["曲曲秋江灧灔波，直疑乘興到銀河。", "逢人欲問支機石，此去星橋路幾多。"]'),
('8c1add10-ffc9-4fa4-9cc2-5d5d202bd593','巴陵界中作  其二','孔武仲','宋','宋诗','song-poetry','','[]','一别湖湘二十秋，飄然覉旅復萍浮。',64,'全唐诗/poet.song.50000.json','["一别湖湘二十秋，飄然覉旅復萍浮。", "冰霜入鬢殊非壯，星斗羅胸却似愁。", "濁酒放歌朝拊髀，青燈苦學夜懸頭。", "惟應此樂無窮已，滚滚滄波盡即休。"]'),
('3fcbc5c5-7e9e-4662-a024-2a417e0c3c39','留贈上官常用','孔武仲','宋','宋诗','song-poetry','','[]','河梁欲上手重攜，冷語南湖百尺隄。',64,'全唐诗/poet.song.50000.json','["河梁欲上手重攜，冷語南湖百尺隄。", "看即青雲開羽翼，莫羞黄綬走塵泥。", "文章炳蔚元摛鳳，鋩刃縱横暫割雞。", "欲識長官清浄意，高堂雙宇掲曹蹊。"]'),
('1350fce8-2a5a-4d44-828b-db180557d8c3','蘇子瞻雪堂','孔武仲','宋','宋诗','song-poetry','','[]','古縣東邊仄徑開，先生曾此劚蒿萊。',64,'全唐诗/poet.song.50000.json','["古縣東邊仄徑開，先生曾此劚蒿萊。", "鸞凰一去應不返，花柳當年皆自栽。", "畫壁蒼茫留水墨，朱欄剥落長莓苔。", "鄰翁笑我來何暮，檢點風煙興盡回。"]'),
('9d191ac9-1db8-49d9-9c6a-be5f78b50fb1','罾魚','孔武仲','宋','宋诗','song-poetry','','[]','野色星輝半有無，曲江舟子夜罾魚。',32,'全唐诗/poet.song.50000.json','["野色星輝半有無，曲江舟子夜罾魚。", "紅鱗躍網無錢買，惆悵天涯尺素書。"]'),
('84f281ad-a56c-4f6f-a812-8cb1b2182825','陽羅磯','孔武仲','宋','宋诗','song-poetry','','[]','石壯山獰不可干，傾江波浪作驚湍。',32,'全唐诗/poet.song.50000.json','["石壯山獰不可干，傾江波浪作驚湍。", "殘霞一抺吴天晚，正苦扁舟不上灘。"]'),
('3059c7a8-a443-4f51-9a70-c0419d2a4571','寓目','孔武仲','宋','宋诗','song-poetry','','[]','清灣氣象暮潭潭，漁客車罾似引帆。',32,'全唐诗/poet.song.50000.json','["清灣氣象暮潭潭，漁客車罾似引帆。", "三尺鯉魚投密網，西江雖廣爾何堪。"]'),
('aa031111-b37c-4ac2-8a2a-71f16dcc0d23','西江','孔武仲','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','灧灧西江水，朝朝伴我行。',48,'全唐诗/poet.song.50000.json','["灧灧西江水，朝朝伴我行。", "雲天初散豁，秋色正分明。", "魚逝應相得，鷗來故不驚。", "煙波聊寄適，南北久忘情。"]'),
('4c80d302-46ce-4787-96b8-487e01c2843e','鄂州','孔武仲','宋','宋诗','song-poetry','','[]','緑柳陰陰蔽武昌，汀洲如畫引帆檣。',64,'全唐诗/poet.song.50000.json','["緑柳陰陰蔽武昌，汀洲如畫引帆檣。", "一江見底自秋色，千里無風正夕陽。", "暫别勝遊渾老大，追思前事只凄凉。", "賢豪况有遺蹤在，欲買溪山作漫郎。"]'),
('c63a443d-19a9-4635-b749-156f577bc91e','巴陵官舍二題 瀟灑堂','孔武仲','宋','宋诗','song-poetry','','[]','旅平凹處剪荆榛，畫棟明窗學隐身。',64,'全唐诗/poet.song.50000.json','["旅平凹處剪荆榛，畫棟明窗學隐身。", "政簡琴書聊度日，地閒花木爲留春。", "一盃濁酒迷今古，五字清吟泣鬼神。", "暫伴登臨對佳景，衣襟渾覺减埃塵。"]'),
('c33eb79e-0b2a-42ed-89a4-31d3fb306ba8','巴陵官舍二題 湖山亭','孔武仲','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','縣山峻絕有新亭，公退時來看洞庭。',64,'全唐诗/poet.song.50000.json','["縣山峻絕有新亭，公退時來看洞庭。", "天外微茫二湖合，波心縹緲一峰青。", "非時爽氣生雲雨，永夜寒光浸斗星。", "千古登臨増健筆，投文猶可弔湘靈。"]'),
('8a4d345d-0608-47d8-acdf-f68e3e17a8b9','五鼓乘風過洞庭湖日高已至廟下作詩三篇  其一','孔武仲','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','半掩船篷天淡明，飛帆已背岳陽城。',32,'全唐诗/poet.song.50000.json','["半掩船篷天淡明，飛帆已背岳陽城。", "飄然一葉乘空度，卧聽銀潢瀉月聲。"]'),
('6d966502-818d-432b-8410-2b75b4bf8c0a','五鼓乘風過洞庭湖日高已至廟下作詩三篇  其二','孔武仲','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','北風投曉漸雄豪，椎鼓車帆十丈高。',32,'全唐诗/poet.song.50000.json','["北風投曉漸雄豪，椎鼓車帆十丈高。", "枕底洞庭三百里，卧聽天樂響叢嘈。"]'),
('0f88a15a-bbe9-4713-8861-8053105eb283','五鼓乘風過洞庭湖日高已至廟下作詩三篇  其三','孔武仲','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','南津瀺灂夜風微，投曉湖靈更發機。',64,'全唐诗/poet.song.50000.json','["南津瀺灂夜風微，投曉湖靈更發機。", "想像虚空聞帝樂，逡巡波浪匝天圍。", "三湘路指平蕪轉，兩舸帆争白鳥飛。", "却上叢祠薦牲酒，荆雲隠隠尚朝暉。"]'),
('36f95cce-857e-4df0-9cf1-38c177167585','何君表留大舟于潯陽不敢乘既至湘陰寄絕句謝之','孔武仲','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭秋水接天流，萬斛樓航不易収。',32,'全唐诗/poet.song.50000.json','["洞庭秋水接天流，萬斛樓航不易収。", "才力似君方稱副，此身只合載漁舟。"]'),
('087f4b95-dcd0-4def-9670-76db23aeb6b0','將至巴陵','孔武仲','宋','宋诗','song-poetry','','[]','南行應不歎途窮，水驛連翩遇好風。',64,'全唐诗/poet.song.50000.json','["南行應不歎途窮，水驛連翩遇好風。", "遠浪飛來千白鷺，輕帆相逐兩冥鴻。", "殘雲日挂蒼茫外，平野天垂曠濶中。", "湘浦舊遊思一訪，肯因蓴膾憶江東。"]'),
('837aa1f2-8406-4af7-9b05-0956590228ec','入湘江二絕句  其一','孔武仲','宋','宋诗','song-poetry','','[]','清川曲岸進遲遲，採得菊花三兩枝。',32,'全唐诗/poet.song.50000.json','["清川曲岸進遲遲，採得菊花三兩枝。", "撚弄秋香斜日下，有懐江國去年時。"]'),
('b9976c6c-3b80-480f-8af6-5fc9ea3fae74','入湘江二絕句  其二','孔武仲','宋','宋诗','song-poetry','','[]','平沙襯水竹藏雲，自古多招薄命人。',32,'全唐诗/poet.song.50000.json','["平沙襯水竹藏雲，自古多招薄命人。", "我獨遠來追所好，是中魚美緑醅醇。"]'),
('78896f99-c654-4c9e-9e06-08d5b826cf51','寄四舍弟','孔武仲','宋','宋诗','song-poetry','','[]','贛水南邊北勢回，層城中起鬱孤臺。',64,'全唐诗/poet.song.50000.json','["贛水南邊北勢回，層城中起鬱孤臺。", "憶初二陸同登此，喜有阿連相繼來。", "舊事前遊休感歎，清風佳景且徘徊。", "天涯未有從囗日，百里區區亦象雷。"]'),
('a71b42dd-75af-4103-a5cb-9fd290750a39','縣圃有小城環之北面有邱阜聳出喬木蔽其上盖古戰棚也到縣之三月得荒徑攀援而上視其形勢可以爲亭北望平野乃增築之度爲四楹公事之隙休息其間','孔武仲','宋','宋诗','song-poetry','','[]','堆案盈庭勢未休，灰心聊此作天遊。',64,'全唐诗/poet.song.50000.json','["堆案盈庭勢未休，灰心聊此作天遊。", "剪除榛莽成幽徑，支架茅篁接古丘。", "葉密風多能庇暑，雲開山出更宜秋。", "西園日涉從今始，誰信民官得自由。"]'),
('fea4ed18-c24d-455a-b907-a39e44b5d5b1','城上亭二首闕  其一','孔武仲','宋','宋诗','song-poetry','','[]','更無人跡逐攀躋，廬岳烏藤手自攜。',64,'全唐诗/poet.song.50000.json','["更無人跡逐攀躋，廬岳烏藤手自攜。", "滄海誰論六月息，茂林今得一枝栖。", "幽芳滿徑春難老，翠樾連雲日易西。", "况有北郊宜曠望，公餘聊此發醯雞。"]'),
('5ede5953-69b7-4e59-98e0-a1badd4f7dab','城上亭二首闕  其二','孔武仲','宋','宋诗','song-poetry','','[]','湘潭之酒今稍薄，粉白水清亦不惡。',64,'全唐诗/poet.song.50000.json','["湘潭之酒今稍薄，粉白水清亦不惡。", "百錢换得一斗歸，復此悠然縱杯酌。", "醉中衡華皆秋毫，肯復刺眼事錐刀。", "層林密葉風力豪，鈞天震響春臺高。"]'),
('4c9e4d9e-5bcc-4cc5-afb0-f67174d149c8','登城','孔武仲','宋','宋诗','song-poetry','','[]','應俗雖勞甚，登高即曠然。',48,'全唐诗/poet.song.50000.json','["應俗雖勞甚，登高即曠然。", "日濃花覆地，春静草連天。", "竹塢連山遠，湖光带郭偏。", "斯官本閒佚，吾政愧烹鮮。"]'),
('6a9ba353-419a-4b10-92c1-7fcd01c85758','城上喬木','孔武仲','宋','宋诗','song-poetry','','[]','城上蒼虬困不醒，春陽己半未回青。',32,'全唐诗/poet.song.50000.json','["城上蒼虬困不醒，春陽己半未回青。", "只應一夜新雷震，漸放繁枝擁日星。"]'),
('bd73787f-517b-4518-a66e-9084348f7dc0','西園獨步二首  其一','孔武仲','宋','宋诗','song-poetry','','[]','茂林新幄翠重重，猶有殘花掩映紅。',32,'全唐诗/poet.song.50000.json','["茂林新幄翠重重，猶有殘花掩映紅。", "庭館漸虚容散涉，時攀園果作狙公。"]'),
('e54913f5-71b9-4a27-ab22-520cfce9494c','西園獨步二首  其二','孔武仲','宋','宋诗','song-poetry','','[]','官居何以滌冥煩，喜有廳西北涉園。',64,'全唐诗/poet.song.50000.json','["官居何以滌冥煩，喜有廳西北涉園。", "白日漸長公事少，紅英己盡葉陰繁。", "渌波似鏡池能照，巧舌如簧鳥解言。", "風景只隨人意好，昔賢何事厭湘沅。"]'),
('0fddd31a-e0ff-4057-915c-d2232adf49db','逍遙亭獨遊','孔武仲','宋','宋诗','song-poetry','','[]','城上飛簷出百尋，回環古木自成陰。',64,'全唐诗/poet.song.50000.json','["城上飛簷出百尋，回環古木自成陰。", "凉生白晝收團扇，影入斜陽剪碎金。", "茂密却遮西望眼，逍遙未有北歸心。", "淵明盛說家園趣，誰信吾園趣更深。"]'),
('0b3f995a-cc47-4b4c-9c3a-f0e682ebd854','縣齋偶書','孔武仲','宋','宋诗','song-poetry','','[]','誤恩爲邑楚江潯，黽勉初疑力不任。',64,'全唐诗/poet.song.50000.json','["誤恩爲邑楚江潯，黽勉初疑力不任。", "吏事妄窺如管豹，歸心難過是籠禽。", "低回未遂箕山志，慷慨猶希梁甫吟。", "案牘埽空庭院静，只將趺坐當鳴琴。"]'),
('90f1a2df-74d7-439e-9cef-f5e32f033064','軺車館','孔武仲','宋','宋诗','song-poetry','','[]','野濶天長入望青，眼中虚豁到鴻冥。',64,'全唐诗/poet.song.50000.json','["野濶天長入望青，眼中虚豁到鴻冥。", "偶從楚俗來同樂，下視湘江笑獨醒。", "風緊水光時蹙練，日斜山影半迴屏。", "扁舟過此方年少，老矣重來鬢漸星。"]'),
('6af9320c-7e4d-4c2f-b33d-1220d8da3f90','次韻和楊公濟見贈三首  其一','孔武仲','宋','宋诗','song-poetry','','[]','虢略先生不諱窮，詠歌堯舜與時逢。',64,'全唐诗/poet.song.50000.json','["虢略先生不諱窮，詠歌堯舜與時逢。", "傳呼滿道今爲使，斂板登門亦見容。", "南浦清波輝玉樹，西齋新釀入金鍾。", "臨分警戒言尤切，似欲驅馳叔夜慵。"]'),
('4d746622-4053-434c-99e6-8d30a44aeea5','次韻和楊公濟見贈三首  其二','孔武仲','宋','宋诗','song-poetry','','[]','魯國鮿生與俗同，何嘗孤訐慕龍逢。',64,'全唐诗/poet.song.50000.json','["魯國鮿生與俗同，何嘗孤訐慕龍逢。", "邑佳不及陶彭澤，官小差肩邴曼容。", "故國安栖無一瓦，高堂失養感千鍾。", "賢豪見顧何恢廓，自冩新詩慰病慵。"]'),
('6c43b920-a92f-49e8-8b5b-d6647667b749','次韻和楊公濟見贈三首  其三','孔武仲','宋','宋诗','song-poetry','','[]','清談衮衮思無窮，渾似饒陽邑下逢。',64,'全唐诗/poet.song.50000.json','["清談衮衮思無窮，渾似饒陽邑下逢。", "霜重湖天初凛冽，夜長樽酒更從容。", "新編自富詩千首，巖邑今饒畝一鍾。", "兀坐江城隨五斗，肯憂紫囗囗衣慵。"]'),
('9f1ee3a0-9f95-4efe-8444-c1291f7f43e8','韓公祠堂','孔武仲','宋','宋诗','song-poetry','','[]','曾持金節撫淮壖，磊落英姿正少年。',64,'全唐诗/poet.song.50000.json','["曾持金節撫淮壖，磊落英姿正少年。", "萬里風鴻看振翼，一時毫素冠凌煙。", "新祠更慰舟人望，遺像仍從幕客傳。", "精爽威容俱不冺，今騎箕尾在青天。"]'),
('9eac296a-fe3c-4b68-ae0e-6c5f26af4e0d','送十二兄還江西','孔武仲','宋','宋诗','song-poetry','','[]','匣有青萍笥有書，西風隻影渡江湖。',32,'全唐诗/poet.song.50000.json','["匣有青萍笥有書，西風隻影渡江湖。", "剩收岳麓春前景，冩入新詩勝畫圖。"]'),
('ff7bb2f5-16f7-494b-8895-ae8884ccce2e','湘潭二首  其一','孔武仲','宋','宋诗','song-poetry','','[]','禄仕飄然寄楚鄉，才能苦短志方强。',64,'全唐诗/poet.song.50000.json','["禄仕飄然寄楚鄉，才能苦短志方强。", "已栽緑柳如彭澤，况有黄金似櫟陽。", "風颭湘波天影動，雲來衡岳雨聲長。", "尚疑卑濕難安處，更起西邊百尺堂。"]'),
('cd049db8-f68a-404c-abfd-37bad17ba35c','湘潭二首  其二','孔武仲','宋','宋诗','song-poetry','','[]','縣街重復俯驚湍，正與湘江咫尺間。',64,'全唐诗/poet.song.50000.json','["縣街重復俯驚湍，正與湘江咫尺間。", "侵齧最憂東滙水，蔽遮惟有北來山。", "清流倒影樓臺壯，白瓦連雲市井間。", "捍患持危功不小，亭亭千古鎮荒灣。"]'),
('ccedc9b5-cd6e-4c1c-9060-746c0f9f4eed','九月十四日小會','孔武仲','宋','宋诗','song-poetry','','[]','带露葵花貯漆盤，周遭仍簇小雞冠。',32,'全唐诗/poet.song.50000.json','["带露葵花貯漆盤，周遭仍簇小雞冠。", "人生愛賞無時足，但作姚黄魏紫看。"]'),
('baf976e5-031a-4545-b048-38a9bf86fce7','寄范清老二絕  其一','孔武仲','宋','宋诗','song-poetry','','[]','高平處士節尤孤，門掩江邊徑欲蕪。',32,'全唐诗/poet.song.50000.json','["高平處士節尤孤，門掩江邊徑欲蕪。", "詩好未窺新歲集，酒醇猶憶去年壺。"]'),
('dacff020-3b80-477d-93e1-45397b8307bb','寄范清老二絕  其二','孔武仲','宋','宋诗','song-poetry','','[]','一别潯陽已隔年，官居應接謾紛然。',32,'全唐诗/poet.song.50000.json','["一别潯陽已隔年，官居應接謾紛然。", "南來瀑水傾江海，夢挈塵肝先洗湔。"]'),
('bd4b0d54-c16d-4025-8b2c-e1c34c2120aa','九月廿二日西館雨中作','孔武仲','宋','宋诗','song-poetry','','[]','西館蕭然擁罽裘，渾無桃李似潘侯。',64,'全唐诗/poet.song.50000.json','["西館蕭然擁罽裘，渾無桃李似潘侯。", "路多緑竹遮欄雨，池有殘荷掩映秋。", "蠻獠謳歌逢樂歲，江湖風景憶扁舟。", "衣冠到底爲身累，秪慕逍遙寄一丘。"]'),
('f35f86fd-a063-4ee8-9ee5-70e8c9261165','晚興','孔武仲','宋','宋诗','song-poetry','','[]','吏退公門静，蕭然似宴居。',48,'全唐诗/poet.song.50000.json','["吏退公門静，蕭然似宴居。", "秋聲來簟枕，晚色被庭除。", "仄徑窺栖鳥，荒池聽躍魚。", "黄花惱陶令，搔首賦歸歟。"]'),
('9b592326-c82d-4148-b283-4a6524fde1b0','寶豐倉秋納三首  其一','孔武仲','宋','宋诗','song-poetry','','[]','次竹編蓬學缺垣，中門以外蟻回旋。',64,'全唐诗/poet.song.50000.json','["次竹編蓬學缺垣，中門以外蟻回旋。", "羣呼直欲争風疾，快走渾疑踏地穿。", "朱墨亂揮雲落手，塵氛横集雪侵顛。", "新年幸有民輸樂，心口相期更勉旃。"]'),
('db724186-0b18-40f8-849c-0308e49454f5','寶豐倉秋納三首  其二','孔武仲','宋','宋诗','song-poetry','','[]','彩籌森列羽門兵，衮衮招呼不斷聲。',64,'全唐诗/poet.song.50000.json','["彩籌森列羽門兵，衮衮招呼不斷聲。", "歲計自當平斗甬，年豐今况有坻京。", "争先雜沓人何冗，應物逍遙我自清。", "白日漸斜亭廡静，却臨湘水笑塵纓。"]'),
('fa20524d-083a-4580-97e8-4f5818eeb1e4','寶豐倉秋納三首  其三','孔武仲','宋','宋诗','song-poetry','','[]','縣濶人饒稼，秋成衆樂租。',48,'全唐诗/poet.song.50000.json','["縣濶人饒稼，秋成衆樂租。", "精粗騐丹白，億萬起錙銖。", "足趼誰先到，尻高或妄呼。", "何當寄軍令，供億黑山隅。"]'),
('36a59623-5c05-41a6-a311-d4fc0e02f2c5','寄范清老','孔武仲','宋','宋诗','song-poetry','','[]','日挂西南有薄輝，稜稜霜氣犯寒衣。',64,'全唐诗/poet.song.50000.json','["日挂西南有薄輝，稜稜霜氣犯寒衣。", "不愁斗柄隨春轉，秪怕梅花學雪飛。", "湘浦波光頻送别，湓城山色屢思歸。", "高人只在南坡住，好共留錢買釣磯。"]'),
('755ed7e3-9a9d-424d-8ab8-81a20dad8d18','湘上二首  其一','孔武仲','宋','宋诗','song-poetry','','[]','滿眼青湘浸緑苔，誰家籬援坼寒梅。',32,'全唐诗/poet.song.50000.json','["滿眼青湘浸緑苔，誰家籬援坼寒梅。", "天容婉美霜雲薄，己逗春光入望來。"]'),
('84d19e26-8b65-441e-9fb8-20f94682e321','湘上二首  其二','孔武仲','宋','宋诗','song-poetry','','[]','南歸曾泛碧湘船，擊伏臨流似浩然。',64,'全唐诗/poet.song.50000.json','["南歸曾泛碧湘船，擊伏臨流似浩然。", "平野幾枯殘歲草，渌波猶浸舊時天。", "簿書倥偬嗟巖邑，樽酒歡娱憶少年。", "尺水片雲今我有，亦當風月爲留連。"]'),
('c7baa407-34c0-4183-b5d8-127780b04c7d','寄劉貢甫','孔武仲','宋','宋诗','song-poetry','','[]','秀水先生今傑才，﨑嶇山徑滯蓬萊。',64,'全唐诗/poet.song.50000.json','["秀水先生今傑才，﨑嶇山徑滯蓬萊。", "飛牋岳麓吟秋草，把酒襄陽醉臈梅。", "東郡政聲無豈弟，南樓風月且徘徊。", "朝廷選用多英俊，早晚劉郎即到來。"]'),
('90aa6b82-7ec4-4dfb-81d6-de884349c585','梅徑','孔武仲','宋','宋诗','song-poetry','','[]','一徑皎無塵，濃酥點爛銀。',48,'全唐诗/poet.song.50000.json','["一徑皎無塵，濃酥點爛銀。", "園池晴後雪，風景臘中春。", "採蜜蜂時背，偷香蝶命屯。", "都將瀟洒格，分付與詩人。"]'),
('ddf45244-8025-4c47-b414-02d8dedf1222','自寶豐倉歸','孔武仲','宋','宋诗','song-poetry','','[]','岳雲成凍把春寒，十里﨑嶇倦往還。',64,'全唐诗/poet.song.50000.json','["岳雲成凍把春寒，十里﨑嶇倦往還。", "馬上朔風回繫带，雪中微酒見開顔。", "含黄欲坼江邊柳，蘸緑相重水上山。", "抛掉一官如糞壌，好隨魚舸此中閒。"]'),
('cd3b9c15-81a6-4443-baf9-cf002a14a226','與同寮遊甘泉苦竹二寺','孔武仲','宋','宋诗','song-poetry','','[]','兩寺藏山曲，登臨恨阻修。',48,'全唐诗/poet.song.50000.json','["兩寺藏山曲，登臨恨阻修。", "平時極目處，今日探春遊。", "苦竹經霜老，甘泉带雪流。", "醇醪煖肌骨，歸路卸輕裘。"]'),
('751c3461-1985-4304-b21d-1c145e4ea602','與陳董二君相會于真州經月甚樂詩寄陳董二君兼感存没','孔武仲','宋','宋诗','song-poetry','','[]','平生交友半成塵，想見當年樂會文。',64,'全唐诗/poet.song.50000.json','["平生交友半成塵，想見當年樂會文。", "别淚茫茫添海水，愁懐黯黯塞江雲。", "青衫脫去誰同老，白首追随尚有君。", "官暇更將棋子學，他時籌局當功勲。"]'),
('1889eca9-e161-40fa-b523-79e772a4c6fe','讀王逢原文奇其才擇甚精者録爲一編','孔武仲','宋','宋诗','song-poetry','','[]','人喜相知自昔然，况君埋玉未多年。',64,'全唐诗/poet.song.50000.json','["人喜相知自昔然，况君埋玉未多年。", "雄文一讀千行淚，青眼相期萬古傳。", "已掇條枚收美實，更披沙石貯清泉。", "東齋倒掩無人語，火煖燈明手自編。"]'),
('32660cb6-3201-46ce-88fb-863f7e9288bf','詩答李時發見賀書省除命渠雲嘗言矣','孔武仲','宋','宋诗','song-poetry','','[]','傾蓋相期自有人，贈言先許出埃塵。',64,'全唐诗/poet.song.50000.json','["傾蓋相期自有人，贈言先許出埃塵。", "若非清議曾推輓，安得公朝有選掄。", "州縣徒勞雖己厭，置郵傳命或非真。", "期公莫算人間事，共醉湘江爛漫春。"]'),
('27213cfb-bb78-4a04-836a-5d8901e1a569','次韻和張芸老阻風見寄','孔武仲','宋','宋诗','song-poetry','','[]','聞道征帆却滯留，蕭條湘岸正南頭。',64,'全唐诗/poet.song.50000.json','["聞道征帆却滯留，蕭條湘岸正南頭。", "春光雖有將歸意，野色仍供不盡愁。", "破浪心期元萬里，揚帆目送已千舟。", "山齋亦欲君重訪，逆水如今是順流。"]'),
('34cd556d-34d6-446b-a711-03c2aac315a3','送劉明復知鳯翔二首  其一','孔武仲','宋','宋诗','song-poetry','','[]','舊國安黄覇，新邦識細侯。',48,'全唐诗/poet.song.50000.json','["舊國安黄覇，新邦識細侯。", "皇慈借鄉便，輿誦欲公留。", "曉雪驪駒宴，春風畫鷁舟。", "皇都朝謁早，天路看鳴騶。"]'),
('880538e8-5872-4114-bbe9-ee821688b2db','送劉明復知鳯翔二首  其二','孔武仲','宋','宋诗','song-poetry','','[]','先帝開三省，今皇重老成。',48,'全唐诗/poet.song.50000.json','["先帝開三省，今皇重老成。", "山林招隠逸，巷陌起公卿。", "自古時難遇，吾侯道正行。", "岐山莫望鳳，金閣遲飛鳴。"]'),
('c4613c59-fbb8-4d6a-a60d-781eb9989971','落日','孔武仲','宋','宋诗','song-poetry','','[]','光彩沉沉萬木西，青空圍出釀燕脂。',32,'全唐诗/poet.song.50000.json','["光彩沉沉萬木西，青空圍出釀燕脂。", "家園正對荒陂望，恰似騰波出海時。"]'),
('dd427d57-e91e-4505-839e-1917c7c470de','次韻和鄧慎思謝劉明復畫道林秋景二首  其一','孔武仲','宋','宋诗','song-poetry','','[]','鈴齋清話未更端，一埽禪林景趣完。',64,'全唐诗/poet.song.50000.json','["鈴齋清話未更端，一埽禪林景趣完。", "縹緲已裝新殿塔，縈紆仍引外峰巒。", "冷風有意生空濶，密雪無聲下廣寒。", "平昔所遊今在眼，凄凉疑是夢中看。"]'),
('84752f70-7b5c-4d5e-ae54-bef09ab1fa60','次韻和鄧慎思謝劉明復畫道林秋景二首  其二','孔武仲','宋','宋诗','song-poetry','','[]','以詩博畫雖不費，要秋得冬如未完。',64,'全唐诗/poet.song.50000.json','["以詩博畫雖不費，要秋得冬如未完。", "恍疑霰雪滿天地，慘若暮氣迷峰巒。", "夜堂高張醉魂醒，暑館偶窺吟魄寒。", "筆端直與造化會，莫作人間毫素看。"]'),
('9afdd3f0-08f1-45a0-8804-b2359abc58e0','留題徐成之和軒','孔武仲','宋','宋诗','song-poetry','','[]','生人情誼貴和光，俸薄官閒寄楚鄉。',64,'全唐诗/poet.song.50000.json','["生人情誼貴和光，俸薄官閒寄楚鄉。", "雜遝賓朋四方會，優游風月一軒凉。", "盃傾琥珀催人飲，羮煖駝蹄勸客嘗。", "景趣己佳心未愜，更栽花竹滿池塘。"]'),
('11f18c13-e7bf-4bac-9c2e-c0ad0cc406fb','寄題丁子厚二亭 睦亭','孔武仲','宋','宋诗','song-poetry','','[]','撫族無如睦，開亭意可知。',48,'全唐诗/poet.song.50000.json','["撫族無如睦，開亭意可知。", "庭階盡蘭玉，兄弟即塤箎。", "食有分甘樂，歌諧伐木詩。", "歡心己如此，風景况相宜。"]'),
('e48a4a4f-e616-44d7-a64e-66fd8de58c08','寄題丁子厚二亭 朋來亭','孔武仲','宋','宋诗','song-poetry','','[]','學有青衿聚，亭當緑野開。',48,'全唐诗/poet.song.50000.json','["學有青衿聚，亭當緑野開。", "山川二湖曲，賓友四方來。", "鄉行求如禹，師門欲望回。", "無輕十室小，長養即高才。"]'),
('eb32d68f-5c82-412a-96be-58e0d2ba8e83','次韻和鄧憤思與太守同登清湘樓','孔武仲','宋','宋诗','song-poetry','','[]','郡樓邀會樂豐年，極目山川思浩然。',64,'全唐诗/poet.song.50000.json','["郡樓邀會樂豐年，極目山川思浩然。", "才子登臨嗟昔别，使君藩屏值新遷。", "前峰緑霧藏丹葉，别浦平沙襯碧漣。", "不但醉吟湘與麓，魯歌崧漢美周宣。"]'),
('0bb81898-0391-4072-9add-895b33346ec1','余嘗謂北人不知江湖如南人不習邊塞時張芸老在坐中因問','孔武仲','宋','宋诗','song-poetry','','[]','張子胸中瑩不疑，江湖邊地總曾知。',64,'全唐诗/poet.song.50000.json','["張子胸中瑩不疑，江湖邊地總曾知。", "波瀾沃日漾舟起，霰雪埋空出塞時。", "挂席何妨拾明月，據鞍仍解賦新詩。", "悠然無復拘南北，陣馬風檣取次宜。"]'),
('9a2a0901-a5d4-4776-b7d4-f52c76591dd7','次韻和王敏仲望祝融峰四首  其一','孔武仲','宋','宋诗','song-poetry','','[]','獨立千秋渾不倚，排虚直上似無根。',32,'全唐诗/poet.song.50000.json','["獨立千秋渾不倚，排虚直上似無根。", "履穿尚恐高難及，磴滑猶應險可捫。"]'),
('a3ab3eba-0c2c-4dd9-ae98-30f152ef381f','次韻和王敏仲望祝融峰四首  其二','孔武仲','宋','宋诗','song-poetry','','[]','斗柄峥嶸宜有概，星榆爛漫豈無根。',32,'全唐诗/poet.song.50000.json','["斗柄峥嶸宜有概，星榆爛漫豈無根。", "祝融直上應窺見，閶闔雖重亦可捫。"]'),
('bed530a9-5b71-4c4d-8ee3-5d56cce391d3','次韻和王敏仲望祝融峰四首  其三','孔武仲','宋','宋诗','song-poetry','','[]','南帝尊嚴勑六丁，剜湘爲硯嶽爲屏。',32,'全唐诗/poet.song.50000.json','["南帝尊嚴勑六丁，剜湘爲硯嶽爲屏。", "照青疊秀俱來會，惟有中峰在杳冥。"]'),
('23142f89-6ac2-4536-abd4-9eb21220c27f','次韻和王敏仲望祝融峰四首  其四','孔武仲','宋','宋诗','song-poetry','','[]','僧居曉看一峰青，迥絕纎塵點畫屏。',32,'全唐诗/poet.song.50000.json','["僧居曉看一峰青，迥絕纎塵點畫屏。", "會有片雲來觸石，江湖三日雨冥冥。"]'),
('6cb6378a-75ab-4ac6-b6fe-35253d0dbfa9','思南嶽呈運判承議','孔武仲','宋','宋诗','song-poetry','','["\u8861\u5c71"]','曾逐籃輿訪嬾殘，樓臺縈轉在峰巒。',64,'全唐诗/poet.song.50000.json','["曾逐籃輿訪嬾殘，樓臺縈轉在峰巒。", "銀燈夜向猊床拜，别殿晨披貝葉看。", "選勝危梯經嶻嵲，登高餘思凭欄干。", "歸來認是游仙夢，過盡春風料峭寒。"]'),
('2c299d0b-d554-46ce-8e25-c21dede06768','和李時發春日見寄','孔武仲','宋','宋诗','song-poetry','','[]','聞道重湖路未通，悠然身在碧湘中。',64,'全唐诗/poet.song.50000.json','["聞道重湖路未通，悠然身在碧湘中。", "﨑嶇水國猶千里，牢落春花已半空。", "江浪濺寒侵小睡，岳雲篩雨響疏篷。", "君詩亦說清幽趣，便覺年來氣味同。"]'),
('aa58e9aa-823f-424f-a849-a343ca395bbf','湘西','孔武仲','宋','宋诗','song-poetry','','[]','文園春晚病無聊，剩欲登臨散鬱陶。',64,'全唐诗/poet.song.50000.json','["文園春晚病無聊，剩欲登臨散鬱陶。", "遠野輸凉來宴坐，長岡傾秀入詩毫。", "輕明物態歸仙境，咫尺城闉限海濤。", "勝事滿前難記憶，戯逢香草綴離騷。"]'),
('d43c59c5-2020-4d09-b54d-6884f4b651f7','留題毛成叔持月軒','孔武仲','宋','宋诗','song-poetry','','[]','明月來時遠，騰騰碧海東。',48,'全唐诗/poet.song.50000.json','["明月來時遠，騰騰碧海東。", "雲収萬里外，人在一軒中。", "光泫池塘路，凉生枕簟風。", "相過喜良夜，莫放酒尊空。"]'),
('a11bc7da-3d74-4274-a5f8-132c540d4320','贈長沙僧守節','孔武仲','宋','宋诗','song-poetry','','[]','花木重重鹿苑春，蕭然一室坐安貧。',64,'全唐诗/poet.song.50000.json','["花木重重鹿苑春，蕭然一室坐安貧。", "真乘但要心知灋，喜捨無如藥濟人。", "増損諸方精古義，窺尋六脈玅通神。", "長沙旅泊無聊賴，詩乞刀圭養病身。"]'),
('eb8f6eca-0515-40fd-b16b-0a8292fcbc49','次韻鄧慎思見寄','孔武仲','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','暫寄瀟湘百尺船，誰論竈冷突無煙。',64,'全唐诗/poet.song.50000.json','["暫寄瀟湘百尺船，誰論竈冷突無煙。", "城陰潦積朝慵出，枕底波鳴夜廢眠。", "潭府更看花似錦，洞庭將泛水如天。", "相期盡校蓬山藏，不秖東流酹酒仙。"]'),
('ed04e955-142c-41bf-a460-de90bc3b333a','湘中阻風','孔武仲','宋','宋诗','song-poetry','','[]','夜泊湖南岸，曉開天北風。',48,'全唐诗/poet.song.50000.json','["夜泊湖南岸，曉開天北風。", "愁雲來覆渚，白浪起吞空。", "甕酒霞將薄，瓶花錦带紅。", "鄰舟如隔海，孤坐寂寥中。"]'),
('30d70491-40d5-49f5-80e6-5ee5c516b310','二湘','孔武仲','宋','宋诗','song-poetry','','[]','斯文常絕息，二子振波瀾。',48,'全唐诗/poet.song.50000.json','["斯文常絕息，二子振波瀾。", "舊國清風在，荒阡古木殘。", "蒼苔生閟宇，斜日下長竿。", "求福今無數，不將陳蔡看。"]'),
('dc910d8b-350e-46a8-a0f7-341c8bac3cc5','登湘陰北寺江亭','孔武仲','宋','宋诗','song-poetry','','[]','古縣峨新刹，孤亭占上頭。',48,'全唐诗/poet.song.50000.json','["古縣峨新刹，孤亭占上頭。", "野苔侵坐緑，江水带天流。", "絲斷湘靈瑟，蘋荒帝子洲。", "人寰真是夢，頃刻已千秋。"]'),
('b0179e58-8184-4a53-be04-56e41b914172','辭二妃廟','孔武仲','宋','宋诗','song-poetry','','[]','盤空烏鵲噪叢祠，船上行人半起時。',64,'全唐诗/poet.song.50000.json','["盤空烏鵲噪叢祠，船上行人半起時。", "殘月朦朦傾島嶼，南風嫋嫋透旌旗。", "開帆便欲日千里，别廟仍澆酒一巵。", "岸芷洲蘭俱可薦，新聲翻入九歌詞。"]'),
('cdc4267d-8732-4c93-8a4b-67bcbd0370b5','過洞庭二首  其一','孔武仲','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','朝來四境宿雲披，漸放扁舟入渺瀰。',64,'全唐诗/poet.song.50000.json','["朝來四境宿雲披，漸放扁舟入渺瀰。", "漠漠衣襟凌水霧，悠悠簾幕挂天絲。", "波平自喜看書穏，風軟翻愁出險遲。", "今夜君山興不淺，登臨應及月明時。"]'),
('81c05898-de5c-4afc-9033-ac80f64f4883','過洞庭二首  其二','孔武仲','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','杳杳湖天極目中，波光日暮兩陶鎔。',64,'全唐诗/poet.song.50000.json','["杳杳湖天極目中，波光日暮兩陶鎔。", "舟離廟步灣環水，帆指東山縹緲峰。", "昔日南征期飲馬，今朝北去想騎龍。", "歸來若得醉鄉隠，願化春醪萬頃醲。"]'),
('93563034-6071-49b8-ac0d-f4b4683940a1','自君山還岳陽','孔武仲','宋','宋诗','song-poetry','','[]','雲山深處望瀟湘，巖石沈沈已夕陽。',64,'全唐诗/poet.song.50000.json','["雲山深處望瀟湘，巖石沈沈已夕陽。", "却整舟帆凌浩渺，回看城郭似家鄉。", "揮戈徑欲迴羲馭，散髮今知出吕梁。", "不是浮休動歸興，對眠猶可借禪床。"]'),
('c130735f-33e0-4a34-a5a5-9dc0cb17c943','登涵暉亭','孔武仲','宋','宋诗','song-poetry','','[]','常時洲島隔波瀾，故覔君山直上看。',64,'全唐诗/poet.song.50000.json','["常時洲島隔波瀾，故覔君山直上看。", "罨畫園林春減色，水晶宫闕晝添寒。", "州城斜引羣峰小，湖面平吞數澤寛。", "坐久西風響喬木，扁舟思到武陵灘。"]'),
('ffbeccb4-6070-4843-b579-e2198afc49ee','藤杖贈張從道','孔武仲','宋','宋诗','song-poetry','','[]','羣木蔚蒼蒼，烏藤壽最長。',72,'全唐诗/poet.song.50000.json','["羣木蔚蒼蒼，烏藤壽最長。", "一朝隨翦伐，千里任持將。", "扣觸如金石，摧殘耐雪霜。", "﨑嶇伴蠟屐，閒暇倚巖牆。", "我亦筋骸乏，君方步履强。", "臨岐輒分贈，縞紵莫相忘。"]'),
('92cd2963-3f6e-4bf6-b682-1c70a684eda6','入萬家園','孔武仲','宋','宋诗','song-poetry','','[]','行盡東南郡，重來訪舊居。',48,'全唐诗/poet.song.50000.json','["行盡東南郡，重來訪舊居。", "此心能有止，他境更誰如。", "入徑看生笋，臨池想躍魚。", "仍貪田舍樂，植杖勸芸鋤。"]'),
('02663564-0f64-47db-bfd0-f132c602b7d7','太一宫','孔武仲','宋','宋诗','song-poetry','','[]','江城南畔碧連峰，疇昔貞人寄此中。',64,'全唐诗/poet.song.50000.json','["江城南畔碧連峰，疇昔貞人寄此中。", "琳宇邃深靈迹在，仙壇牢落杏花空。", "池塘自老琴高鯉，巖谷仍回禦冦風。", "共羨碧虚官職好，誰知陰有濟民功。"]'),
('53ce4398-e5f6-42ec-bd1e-13f6f53756ba','紫極宫黙軒','孔武仲','宋','宋诗','song-poetry','','[]','宴坐寂不語，先生心謂何。',48,'全唐诗/poet.song.50000.json','["宴坐寂不語，先生心謂何。", "逍遙疏世味，恬淡養天和。", "一息忘言後，方知得象多。", "壺中藏日月，鼎裏煮山河。"]'),
('d36d91d8-b651-4c13-ab86-34979b0aa9e1','泛清溪入齊山','孔武仲','宋','宋诗','song-poetry','','[]','轉轎南隄大阻長，不如乘興泛輕航。',64,'全唐诗/poet.song.50000.json','["轉轎南隄大阻長，不如乘興泛輕航。", "園林蔭翳清如簟，禽鳥將迎語有簧。", "溪是明河天上去，山疑方丈石中藏。", "衣巾散適心閒暇，更勝登臨逐杜郎。"]'),
('f22125cf-cfdd-4b3c-9153-fc053f9d3d84','又三絕句  其一','孔武仲','宋','宋诗','song-poetry','','[]','風定南溪映碧虚，扁舟選勝百蟠紆。',32,'全唐诗/poet.song.50000.json','["風定南溪映碧虚，扁舟選勝百蟠紆。", "荇花荷葉明人眼，猶記當年入鏡湖。"]'),
('92d75718-3b65-4abb-b6b8-ea57fcb6b57c','又三絕句  其二','孔武仲','宋','宋诗','song-poetry','','[]','咫尺齊山不易登，力驅煩冗得身輕。',32,'全唐诗/poet.song.50000.json','["咫尺齊山不易登，力驅煩冗得身輕。", "瑤巔珉洞須尋遍，從此乘風上玉京。"]'),
('2e8b812e-97d0-4295-8b0a-afef13a90351','又三絕句  其三','孔武仲','宋','宋诗','song-poetry','','[]','舊遊蕭索十年餘，走遍東南雪滿鬚。',32,'全唐诗/poet.song.50000.json','["舊遊蕭索十年餘，走遍東南雪滿鬚。", "醉洒銀鈎題歲月，窺尋猶在壁間無。"]'),
('8c4aaff3-afbf-4e7d-87bb-515fdb399202','登齊山','孔武仲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','路出南隄思洒然，烏藤點點破苔圓。',64,'全唐诗/poet.song.50000.json','["路出南隄思洒然，烏藤點點破苔圓。", "山腰仄塞元無路，洞底虚無别有天。", "六月清風醒客醉，千叢怪石伴僧禪。", "近人登覽方爲貴，従此匡廬不直錢。"]'),
('6236f070-258c-419b-ba71-4df5410540b0','九華山','孔武仲','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71", "\u592a\u6e56"]','扁舟重過九青蓮，極目空明思浩然。',64,'全唐诗/poet.song.50000.json','["扁舟重過九青蓮，極目空明思浩然。", "可是畫工煩刻畫，只因山骨偶枝駢。", "風高迥認龍騰海，雲散初疑劍插天。", "剩採太湖嵌孔石，南窗排列佇飛仙。"]'),
('34a88d4b-bbb0-4284-9940-b4482f54516a','王文玉出清溪圖以示坐客','孔武仲','宋','宋诗','song-poetry','','[]','舟在此溪濱，披圖看愈親。',72,'全唐诗/poet.song.50000.json','["舟在此溪濱，披圖看愈親。", "須知堂上客，便是畫中人。", "瀟洒蒼葭映，舂容碧浪春。", "秀山旁發派，秋浦淨爲鄰。", "飛鷺來窺影，遊魚可數鱗。", "飲闌須卷去，聊以辟京塵。"]'),
('56a185ca-e312-4184-ad44-c8965eaa189e','翠微亭','孔武仲','宋','宋诗','song-poetry','','[]','蠟屐縈紆洞府間，飛甍仍在最高巔。',63,'全唐诗/poet.song.50000.json','["蠟屐縈紆洞府間，飛甍仍在最高巔。", "青山東去餘無地，黄潦西來正接天。", "太子池塘烟漫漫，紫微蹤跡草芊芊。", "松枯朽由來事，莫作常情歎逝川。"]'),
('0e356380-3b77-4b7f-b3cf-ecab513db753','銅陵縣端午日寄兄弟二首 寄經父','孔武仲','宋','宋诗','song-poetry','','[]','柳浦移舟带雨行，奔波南北是平生。',64,'全唐诗/poet.song.50000.json','["柳浦移舟带雨行，奔波南北是平生。", "忽驚佳節臨端午，還記當年客禁城。", "丹杏飣盤深簇火，碧醪傾盞釅堆餳。", "菖蒲角粽俱如舊，何事樽前醉不成。"]'),
('ed35d8bf-c78d-4ee8-832b-8ff12067df50','銅陵縣端午日寄兄弟二首 寄季毅','孔武仲','宋','宋诗','song-poetry','','[]','南北飄然各轉蓬，佳辰無路笑言同。',64,'全唐诗/poet.song.50000.json','["南北飄然各轉蓬，佳辰無路笑言同。", "銅壺縣冷更微雨，白鵲樓高來遠風。", "粽剥雪膚明席上，酒傾玉骨映杯中。", "區區羈旅無歡笑，遙想華堂屢一烘。"]'),
('4521ad1b-54cc-41b4-ba70-1131a5d2c371','清涼寺','孔武仲','宋','宋诗','song-poetry','','[]','白寺荒灣略艤舟，攜笻來作上方遊。',64,'全唐诗/poet.song.50000.json','["白寺荒灣略艤舟，攜笻來作上方遊。", "何年巧匠開山骨，自古精兵聚石頭。", "故壘無人空向久，高堂問話凜生秋。", "雲庵快望窮千里，一借澄江洗客憂。"]'),
('0850b255-6a9d-45a1-8169-7418e62eb017','白雲菴','孔武仲','宋','宋诗','song-poetry','','[]','青山爲路竹爲門，千里江風到此軒。',32,'全唐诗/poet.song.50000.json','["青山爲路竹爲門，千里江風到此軒。", "誰把吳王歌管地，一時分付給孤園。"]'),
('f642bca0-f762-47fc-920b-33e8e7142758','石城祠','孔武仲','宋','宋诗','song-poetry','','[]','門外雲潮去復迴，山頭宫殿鏁蒼苔。',48,'全唐诗/poet.song.50000.json','["門外雲潮去復迴，山頭宫殿鏁蒼苔。", "清風明月無興廢，白鷺烏鴉自往來。", "百戰英雄俱戲劇，悽然空起子山哀。"]'),
('b23ab7dc-bada-44c1-b584-f4538f80ebfc','瓜步解舟','孔武仲','宋','宋诗','song-poetry','','[]','日落怒號息，扁舟従此移。',48,'全唐诗/poet.song.50000.json','["日落怒號息，扁舟従此移。", "巨鱗初脫鼎，勁翮不黏黐。", "歴歴前征路，茫茫北去陂。", "白沙聊繫泊，燈火夜深時。"]'),
('71375c7f-720f-4ef6-8343-668067d71bb5','至樟樹店寄徐安道','孔武仲','宋','宋诗','song-poetry','','[]','逼仄東南路，連天紫翠峰。',48,'全唐诗/poet.song.50000.json','["逼仄東南路，連天紫翠峰。", "微雲還掩日，小雨正催農。", "谷鳥投枝急，山花落澗濃。", "意巖今不遠，談笑喜相逢。"]'),
('41ac79a1-4e3a-4bc3-98aa-31b29e156360','次韻和知郡朝奉登禪月臺書事二首  其一','孔武仲','宋','宋诗','song-poetry','','[]','物有賤而貴，勸公收樺皮。',48,'全唐诗/poet.song.50000.json','["物有賤而貴，勸公收樺皮。", "自能全烈火，何用爇香脂。", "山徑狂風夜，茅簷密雪時。", "金蓮猝難買，唯此頗相宜。"]'),
('d2590243-61ab-4a9c-aa8d-d47b842fff40','次韻和知郡朝奉登禪月臺書事二首  其二','孔武仲','宋','宋诗','song-poetry','','[]','素月寒光好，高齋夜已扄。',48,'全唐诗/poet.song.50000.json','["素月寒光好，高齋夜已扄。", "影難穿密紙，光稍泛疏櫺。", "皎潔臨書案，朦朧到研屏。", "沈吟憶丹桂，更欲步中庭。"]'),
('c343f7f0-1f25-43e0-8478-862a99477a3e','風鐸','孔武仲','宋','宋诗','song-poetry','','[]','瀟洒當簷鐸，凄清不斷風。',48,'全唐诗/poet.song.50000.json','["瀟洒當簷鐸，凄清不斷風。", "高堂人語後，廣殿月明中。", "暫歇還歸靜，重來復滿空。", "羣仙鳴玉佩，初下廣寒宫。"]'),
('f6c0f174-0c79-4815-80c7-0782b79b17fa','明妃','孔武仲','宋','宋诗','song-poetry','','[]','碧落千萬里，輕雲何處來。',48,'全唐诗/poet.song.50000.json','["碧落千萬里，輕雲何處來。", "仙衣行縹緲，海鶴去徘徊。", "映日低秦嶺，隨風過楚臺。", "茅簷看不足，更欲上崔嵬。"]'),
('ec02222a-b576-40ba-9963-0d26523379e0','讀經父所作高承制銘因寄之','孔武仲','宋','宋诗','song-poetry','','[]','征路杳無窮，山川掩映中。',48,'全唐诗/poet.song.50000.json','["征路杳無窮，山川掩映中。", "記程知遠近，分境識西東。", "倦客似浮梗，輕鞍如去鴻。", "平生慣相遇，轉愧坐禪翁。"]'),
('33c10c6f-e569-4711-ad0a-0bdb97eca77f','雜詩四首  其一','孔武仲','宋','宋诗','song-poetry','','[]','春風仰屋卧田廬，海日鮮明柳影疏。',32,'全唐诗/poet.song.50000.json','["春風仰屋卧田廬，海日鮮明柳影疏。", "夢覺不知身處所，此中依約是華胥。"]'),
('10694698-4933-4020-8d2c-9abe800f70ee','雜詩四首  其二','孔武仲','宋','宋诗','song-poetry','','[]','平日扁舟千里行，朅來無地濯塵纓。',32,'全唐诗/poet.song.50000.json','["平日扁舟千里行，朅來無地濯塵纓。", "朝衣趁曉東華路，喜有官橋流水聲。"]'),
('b93e85ae-1a6a-49cb-92d9-62b9e410338b','雜詩四首  其三','孔武仲','宋','宋诗','song-poetry','','[]','霞冠鶴氅一道士，夢半留丹三四粒。',32,'全唐诗/poet.song.50000.json','["霞冠鶴氅一道士，夢半留丹三四粒。", "云是月華宫裏人，掌心微带銀波濕。"]'),
('bbc42957-ab43-4566-8a43-5727ec8e7ccf','雜詩四首  其四','孔武仲','宋','宋诗','song-poetry','','[]','利綰名驅夜廢眠，王城車馬日喧闐。',32,'全唐诗/poet.song.50000.json','["利綰名驅夜廢眠，王城車馬日喧闐。", "誰知坦腹春風裏，醉卧牆陰不計年。"]'),
('212c61a5-f41d-41dc-a6ba-e4abde76b1e9','早朝遇執政於路','孔武仲','宋','宋诗','song-poetry','','[]','紅燭轉沙堤，天門仗未齊。',24,'全唐诗/poet.song.50000.json','["紅燭轉沙堤，天門仗未齊。", "槐陰勒馬待，月在御溝西。"]'),
('242702eb-23ae-4aaf-9725-bef566b3ff41','曉過州橋','孔武仲','宋','宋诗','song-poetry','','[]','曉日蒼涼宿霧東，蓬萊金碧起浮空。',32,'全唐诗/poet.song.50000.json','["曉日蒼涼宿霧東，蓬萊金碧起浮空。", "滄溟萬里排天去，人物紛紛海市中。"]'),
('c9ff64d6-fcfb-47b2-bf41-b39c0a3637b9','祅廟祈晴','孔武仲','宋','宋诗','song-poetry','','[]','叢祠齋澣夜焚香，解带投眠小簟涼。',32,'全唐诗/poet.song.50000.json','["叢祠齋澣夜焚香，解带投眠小簟涼。", "雲色倚秋猶縹緲，雨聲羞曉故摧藏。"]'),
('8faa1dc2-8c85-4468-9fa8-47574db3a67e','陳用之學士挽詞二首  其一','孔武仲','宋','宋诗','song-poetry','','[]','禮學康成後，朝廷復有人。',48,'全唐诗/poet.song.50000.json','["禮學康成後，朝廷復有人。", "詩書奏旒扆，軌物錫朱銀。", "氣象生臺閣，光華動搢紳。", "幽途應不憾，朋友自沾巾。"]'),
('5d05c8ec-94fd-4542-a669-671b71a98629','陳用之學士挽詞二首  其二','孔武仲','宋','宋诗','song-poetry','','[]','小疾謂可起，斯人今則亡。',48,'全唐诗/poet.song.50000.json','["小疾謂可起，斯人今則亡。", "溪山迷故國，妻子寄他鄉。", "館閣應留像，朝廷爲給喪。", "榮華雖不滿，尚勝賈司倉。"]'),
('a61bfe2e-2d7b-4228-99b5-3ba414e02a32','詩送應子發之官吳興','孔武仲','宋','宋诗','song-poetry','','[]','又向吳興去，江湖風雪天。',48,'全唐诗/poet.song.50000.json','["又向吳興去，江湖風雪天。", "萊衣歸戲綵，儉幕看依蓮。", "伉直不隨世，低徊今有年。", "誰將華陰土，一爲拭龍泉。"]'),
('752a57c5-41a3-474d-a0aa-87d5a3215b99','曹家巷稅居三詠 小椿','孔武仲','宋','宋诗','song-poetry','','[]','渺小牆陰數尺栽，兒童欲拔幾徘徊。',32,'全唐诗/poet.song.50000.json','["渺小牆陰數尺栽，兒童欲拔幾徘徊。", "須知造化機闗敏，坐見童童羽扇開。"]'),
('e31b7d2a-0f76-4e87-ad13-78d4ffce6f0a','曹家巷稅居三詠 小槐','孔武仲','宋','宋诗','song-poetry','','[]','合抱庭槐已是奇，何年春色長孫枝。',32,'全唐诗/poet.song.50000.json','["合抱庭槐已是奇，何年春色長孫枝。", "主張莫使隨薪槱，會見繁柯偃蓋時。"]'),
('db5130a6-20fd-4f2c-a12a-21da80df81cd','小井','孔武仲','宋','宋诗','song-poetry','','[]','團團樣學天邊月，汨汨聲迴地底泉。',32,'全唐诗/poet.song.50000.json','["團團樣學天邊月，汨汨聲迴地底泉。", "剩貯黄金還屋稅，此功寧止見山錢。"]'),
('30409ef4-4840-4a5c-bf4a-65ee8c74c622','送祠部劉儀文知穎州','孔武仲','宋','宋诗','song-poetry','','["\u897f\u6e56"]','厭逐京師車馬塵，乞爲林下水邊人。',64,'全唐诗/poet.song.50000.json','["厭逐京師車馬塵，乞爲林下水邊人。", "江湖入夢歸心壯，道路生輝使節新。", "豈弟宜民推善政，清閒無訟稱天真。", "如聞此府多遷擢，剩醉西湖爛漫春。"]'),
('e065cf3c-d457-40c5-b2fa-1541669f3e81','板橋辭太母靈轝三首  其一','孔武仲','宋','宋诗','song-poetry','','[]','吉仗凶儀備古今，哀歌仍雜管簫音。',32,'全唐诗/poet.song.50000.json','["吉仗凶儀備古今，哀歌仍雜管簫音。", "喧闐四海脩同軌，未滿君王孝養心。"]'),
('76e2b2dd-d5f7-463a-8aed-2ab5cc30a309','板橋辭太母靈轝三首  其二','孔武仲','宋','宋诗','song-poetry','','[]','元夕三宫綵仗隨，月華燈彩近瑤池。',32,'全唐诗/poet.song.50000.json','["元夕三宫綵仗隨，月華燈彩近瑤池。", "連昌故老曾經見，似夢如醒恍自疑。"]'),
('b458ff90-323b-4337-9560-4cb0daaa938f','板橋辭太母靈轝三首  其三','孔武仲','宋','宋诗','song-poetry','','[]','鬱鬱陵臺瑞氣多，短簫聲裂想悲歌。',32,'全唐诗/poet.song.50000.json','["鬱鬱陵臺瑞氣多，短簫聲裂想悲歌。", "西郊淚盡身先返，唯有心隨洛水波。"]'),
('71226d17-8254-4885-ba14-a97d4704afc1','宋履中學士挽詞二首  其一','孔武仲','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','朝論方知子，哀哉疾不瘳。',48,'全唐诗/poet.song.50000.json','["朝論方知子，哀哉疾不瘳。", "歌聞湘浦些，魂返岱宗遊。", "文雅承三世，淵源見九流。", "音容如可接，圖像在瀛洲。"]'),
('8c4dd76d-bad6-42f1-bca6-e5bf6a75eafe','宋履中學士挽詞二首  其二','孔武仲','宋','宋诗','song-poetry','','[]','跡忝詞場舊，官俱瀛府仙。',48,'全唐诗/poet.song.50000.json','["跡忝詞場舊，官俱瀛府仙。", "過從常永日，推予更忘年。", "素業期三友，幽途隔九泉。", "春明書史富，貴與弟兄賢。"]'),
('4e673614-6830-484c-a801-544733fab99c','和四弟夏雨','孔武仲','宋','宋诗','song-poetry','','[]','蠶月雨冥冥，愁雲滿太清。',48,'全唐诗/poet.song.50000.json','["蠶月雨冥冥，愁雲滿太清。", "庭階猶積潤，溝港更繁聲。", "嫩緑應浮野，餘涼稍及城。", "隋河今不淺，放艇欲南征。"]'),
('d35c3fc6-e204-4505-89b2-daffa95809a5','之官宣城贈毅父次其韻','孔武仲','宋','宋诗','song-poetry','','[]','幾夕林聲醖造秋，移船回指鳳凰樓。',64,'全唐诗/poet.song.50000.json','["幾夕林聲醖造秋，移船回指鳳凰樓。", "身疲禁內凝嚴地，恩與江南爽塏州。", "歴數近城多異境，問知前政盡名流。", "嘉觀勝賞應難盡，更爲吟哦萬古愁。"]'),
('0a140597-a610-4fd1-bb18-7f19288a3522','除宣城守贈元忠毅父次其韻','孔武仲','宋','宋诗','song-poetry','','[]','垂楊正好移舟看，輕舸何妨出沐遲。',32,'全唐诗/poet.song.50000.json','["垂楊正好移舟看，輕舸何妨出沐遲。", "疊嶂雙溪雖未歴，白雲芳草已相知。"]'),
('df3aaaec-1787-43a7-8511-dd3f5b121a1c','送文潛出守丹陽','孔武仲','宋','宋诗','song-poetry','','[]','山陽驚坐早軒軒，元祐登瀛正少年。',64,'全唐诗/poet.song.50000.json','["山陽驚坐早軒軒，元祐登瀛正少年。", "殿上仍簪侍臣筆，江頭新艤使君船。", "吟哦氣爽滄溟外，曲步心期白日邊。", "守得東南知不負，夢中應作五洲仙。"]'),
('62b399f0-adf0-4745-bd8b-a9afa4534c16','寶應界中絕句三首  其一','孔武仲','宋','宋诗','song-poetry','','[]','倒景虞淵日，餘威澤國霞。',24,'全唐诗/poet.song.50000.json','["倒景虞淵日，餘威澤國霞。", "宵行逐明月，水宿傍人家。"]'),
('b9c8a091-c208-4b4e-b1a6-77a9544bdf41','寶應界中絕句三首  其二','孔武仲','宋','宋诗','song-poetry','','[]','泉水秋浮艇，荒陂暮聽蟬。',24,'全唐诗/poet.song.50000.json','["泉水秋浮艇，荒陂暮聽蟬。", "登瀛從此路，出守已衰年。"]'),
('8bb29c18-4c11-44fd-9240-992cc9dcd182','寶應界中絕句三首  其三','孔武仲','宋','宋诗','song-poetry','','[]','淮天秋日下，水國晚涼中。',24,'全唐诗/poet.song.50000.json','["淮天秋日下，水國晚涼中。", "舟子趨程意，軒軒欲貫虹。"]'),
('08e3dfba-c65a-414c-a260-018fab58dc69','明月亭下作','孔武仲','宋','宋诗','song-poetry','','[]','杳杳蕪城起暮鐘，亭亭華月照秋容。',32,'全唐诗/poet.song.50000.json','["杳杳蕪城起暮鐘，亭亭華月照秋容。", "便疑碧海依牆塹，雲水情知隔萬重。"]'),
('7e103e9a-946f-47ab-a700-f5b2d0e6e646','繫舟長蘆作','孔武仲','宋','宋诗','song-poetry','','[]','夜泊長蘆星滿川，晚來吳楚氣昏然。',64,'全唐诗/poet.song.50000.json','["夜泊長蘆星滿川，晚來吳楚氣昏然。", "雲雷相會還成雨，江海交流獨艤船。", "廢室與人喧白浪，荒村何處起青烟。", "文書滿眼従抛棄，却倚蒲團學坐禪。"]'),
('b2381c06-17a9-4812-a1ed-08f839e50463','長蘆五絕句  其一','孔武仲','宋','宋诗','song-poetry','','[]','吳楚中間天杳茫，愁霖傾卷水洋洋。',32,'全唐诗/poet.song.50000.json','["吳楚中間天杳茫，愁霖傾卷水洋洋。", "千帆渡口低鵬翼，海濶風微不敢翔。"]'),
('e88f8284-182e-41c6-8042-1f98e0729500','長蘆五絕句  其二','孔武仲','宋','宋诗','song-poetry','','[]','扁舟昨出國門東，煩暑端如坐甑中。',32,'全唐诗/poet.song.50000.json','["扁舟昨出國門東，煩暑端如坐甑中。", "一雨一涼皆可喜，只嗔三日打頭風。"]'),
('87afe621-2543-4d73-9977-ad9099b7daf8','長蘆五絕句  其三','孔武仲','宋','宋诗','song-poetry','','[]','白霧應連滄海東，鄰舟相失渺茫中。',32,'全唐诗/poet.song.50000.json','["白霧應連滄海東，鄰舟相失渺茫中。", "時時客子江頭語，社過應須有好風。"]'),
('c02898aa-a41b-43ce-9565-477568970a59','長蘆五絕句  其四','孔武仲','宋','宋诗','song-poetry','','[]','波聲滚滚百川流，七日津亭厭艤舟。',32,'全唐诗/poet.song.50000.json','["波聲滚滚百川流，七日津亭厭艤舟。", "遙望叢祠燒的乳，美風相遣莫淹留。"]'),
('855f141b-a96a-4856-bebe-024f75f3d3a9','長蘆五絕句  其五','孔武仲','宋','宋诗','song-poetry','','[]','去盡江灣伴侣船，整帆徐出浦沙邊。',32,'全唐诗/poet.song.50000.json','["去盡江灣伴侣船，整帆徐出浦沙邊。", "風濤沃日心彌壯，老矣無因似昔年。"]'),
('097a137f-efb1-4227-bf60-e28ad72bfa90','諸葛武侯','孔武仲','宋','宋诗','song-poetry','','[]','天下軍書動，西南霸氣偏。',96,'全唐诗/poet.song.50000.json','["天下軍書動，西南霸氣偏。", "太公謀國妙，伊尹佐時專。", "季漢基還立，强吳勢外連。", "兵従新節制，志復舊山川。", "霜肅關中晚，春浮渭上天。", "恩威人並附，將相器俱全。", "醜虜羞巾幗，遺音被管絃。", "妖星如不墮，功業管簫前。"]'),
('f4610c2c-88f8-40b9-9bfa-876b9dd6366a','宣州吳子權送陵陽酒','孔武仲','宋','宋诗','song-poetry','','[]','夢寐陵陽天上山，曾將心約白雲閒。',64,'全唐诗/poet.song.50000.json','["夢寐陵陽天上山，曾將心約白雲閒。", "仙銜已下青冥裏，塵骨難留縹緲間。", "三尺溪魚如可控，千年遼鶴尚應還。", "多情别後能論舊，遠寄官醪爲解顔。"]'),
('b4ae2d74-8a01-4d35-9796-c6c28357776d','宫詞二首  其一','孔武仲','宋','宋诗','song-poetry','','[]','十頃西池碧近天，春深調馬教龍船。',32,'全唐诗/poet.song.50000.json','["十頃西池碧近天，春深調馬教龍船。", "至尊勤政歡嬉少，企望鑾輿又七年。"]'),
('04f82ac6-7252-48cd-87ab-96d3518879e1','宫詞二首  其二','孔武仲','宋','宋诗','song-poetry','','[]','雲霧猊香錦繡堆，千官重列序賓儀。',32,'全唐诗/poet.song.50000.json','["雲霧猊香錦繡堆，千官重列序賓儀。", "欲知湛露零蕭處，盡在天杯側勸時。"]'),
('196248f0-8b21-400e-a786-b6e6ecc9965b','池州山','孔武仲','宋','宋诗','song-poetry','','[]','水際天邊盡畫屏，廣寒宫闕玉爲城。',32,'全唐诗/poet.song.50000.json','["水際天邊盡畫屏，廣寒宫闕玉爲城。", "南來已爲江山助，到此逢山眼更明。"]'),
('6c331686-2ed6-473e-a7e2-51a9bd4d0607','三山磯','孔武仲','宋','宋诗','song-poetry','','[]','磯下長川欲倒流，江豚出没水禽浮。',32,'全唐诗/poet.song.50000.json','["磯下長川欲倒流，江豚出没水禽浮。", "憑誰爲告詩仙道，今到青天盡處遊。"]'),
('6a984bf2-8d4a-4823-9a7b-acc083181ff7','彭澤山','孔武仲','宋','宋诗','song-poetry','','[]','山磯環合闢鯨虯，白水如湯動地流。',32,'全唐诗/poet.song.50000.json','["山磯環合闢鯨虯，白水如湯動地流。", "崖崿盡成斤斧迹，當年誰與化工謀。"]'),
('1e74ad28-9a9f-4e7c-97f5-407a7f2b7857','發彭澤','孔武仲','宋','宋诗','song-poetry','','[]','御風南去覺泠然，今日無慚禦冦仙。',64,'全唐诗/poet.song.50000.json','["御風南去覺泠然，今日無慚禦冦仙。", "廬嶽奇峰將出地，豐城寶氣已連天。", "詩書未敢當謀帥，忠信由來可涉川。", "止仗江神扶羽翮，解帆江浦夕陽邊。"]'),
('fcd1a2ef-8bda-4e23-ba22-a9854c3d1529','橙子','孔武仲','宋','宋诗','song-poetry','','[]','秋露凝漿細，朝陽入色深。',24,'全唐诗/poet.song.50000.json','["秋露凝漿細，朝陽入色深。", "冰虀不須搗，恐碎褭蹄金。"]'),
('33a4eb56-40a7-4683-ab89-a41339b175e6','將至湖口作','孔武仲','宋','宋诗','song-poetry','','[]','一帆安穏轉汀洲，吞吐波瀾畫鷁遒。',32,'全唐诗/poet.song.50000.json','["一帆安穏轉汀洲，吞吐波瀾畫鷁遒。", "三尺龍文光景動，川平何處有蛟虯。"]'),
('5d5551f4-74fe-4b4d-ad6c-f137be5af6c7','次韻馬中玉春日偶成','孔武仲','宋','宋诗','song-poetry','','[]','京都久客憶歸頻，凖擬江南看早春。',64,'全唐诗/poet.song.50000.json','["京都久客憶歸頻，凖擬江南看早春。", "多病餘生萬事已，起驚芳意一番新。", "東湖水滿魚應樂，南浦波明柳自匀。", "玉臉芙蕖容易得，要須叮囑養花人。"]'),
('d94b3a22-a2be-465a-b0bc-0e3ce2a4cd6e','草石寺','孔武仲','宋','宋诗','song-poetry','','[]','高士去已久，餘蹤猶可知。',48,'全唐诗/poet.song.50000.json','["高士去已久，餘蹤猶可知。", "竹陰侵晏坐，山影在平池。", "塵蝕參軍墨，苔侵相國碑。", "漫尋瀟洒趣，俯仰愜心期。"]'),
('a857abef-c165-45b4-93d0-7a9bacacd718','太霞宫','孔武仲','宋','宋诗','song-poetry','','[]','誰氏夸豪力，琳宫一手開。',48,'全唐诗/poet.song.50000.json','["誰氏夸豪力，琳宫一手開。", "光輝動金碧，瀟洒絕塵埃。", "煮石洞中火，流霞天上杯。", "籃輿穿翠樾，只爲聽琴來。"]'),
('cbe915c6-d258-4112-9e16-eaff0975abdf','送李端叔定州機宜','孔武仲','宋','宋诗','song-poetry','','[]','才高秖合住蓬瀛，步武優游地望清。',64,'全唐诗/poet.song.50000.json','["才高秖合住蓬瀛，步武優游地望清。", "何事塵埃久京國，却衝雨雪向邊城。", "軍書落筆千毫秃，談席揮犀四座傾。", "早曉封章來薦鶚，一鳴從此使人驚。"]'),
('aaf757d5-c548-4d72-8be5-421e32eee922','癸酉臘雪','孔武仲','宋','宋诗','song-poetry','','[]','又見同雲合，朝來雪滿天。',48,'全唐诗/poet.song.50000.json','["又見同雲合，朝來雪滿天。", "寒生梁苑席，興在越溪船。", "不復風鳴屋，應須澤到泉。", "農家相慶喜，處處畝鍾田。"]'),
('e178eb0d-816e-4ee7-9805-31f8e07b1c03','惜竹','孔武仲','宋','宋诗','song-poetry','','[]','老蘚牆陰夕照間，何人折我翠琅玕。',64,'全唐诗/poet.song.50000.json','["老蘚牆陰夕照間，何人折我翠琅玕。", "即兹緑葉隨塵化，猶有低枝带露殘。", "不放雲梢侵霰雪，因嗟世故足波瀾。", "故園未乏篔簹品，十頃繁陰六月寒。"]'),
('342ec423-7ede-47a1-a7fc-61df12a075de','贈夢符朝議','孔武仲','宋','宋诗','song-poetry','','[]','人笑公衣不浣濯，我憚公心霜雪明。',64,'全唐诗/poet.song.50000.json','["人笑公衣不浣濯，我憚公心霜雪明。", "青衫仕宦有真氣，白首鄉閭無惡聲。", "相逢回首又再歲，暫去還來觀太平。", "何事南歸太果決，蕭然遠作玉溪生。"]'),
('7ababa4c-83a5-479c-b6fa-eda325426dc0','駕自宣光殿還內','孔武仲','宋','宋诗','song-poetry','','[]','直午開金闕，中天動玉輿。',72,'全唐诗/poet.song.50000.json','["直午開金闕，中天動玉輿。", "千官星拱極，萬乘斗回車。", "瑞氣春妍後，清風雨霽初。", "鳴鞭嚮寥廓，彩仗正蘇舒。", "古禮觀瞻始，皇情酌獻餘。", "書林俊遊盛，拜舞爛袍魚。"]'),
('2e160235-ca5f-4961-9227-e2cb115356a0','景靈宫奉安神考御容','孔武仲','宋','宋诗','song-poetry','','[]','先帝遺弓劍，威靈在九州。',72,'全唐诗/poet.song.50000.json','["先帝遺弓劍，威靈在九州。", "方悲風馭遠，已見月衣遊。", "别殿笙歌動，中天彩翠浮。", "觚稜參魏闕，氣象擬蓬丘。", "羽衛生幢蓋，都人識冕旒。", "吾君孝心遠，文考百無憂。"]'),
('31829182-9a19-453b-ba33-072772c6b7a7','題山光樓','孔武仲','宋','宋诗','song-poetry','','[]','山靜圍平野，樓高映碧空。',48,'全唐诗/poet.song.50000.json','["山靜圍平野，樓高映碧空。", "人居仙島曲，天入畫屏中。", "倚檻雲蟾近，傾觴客興同。", "扁舟期一到，須借五湖風。"]'),
('d4d06ae7-d8a6-4568-ba83-c76fb7c233b2','芍藥','孔武仲','宋','宋诗','song-poetry','','[]','樓上看紅藥，都城值晚春。',72,'全唐诗/poet.song.50000.json','["樓上看紅藥，都城值晚春。", "風葩低永晝，露臉泣芳晨。", "憶昨淮南客，曾爲詩社人。", "輕明是樓子，閒澹有天真。", "此地雖都會，兹花莫等倫。", "維揚不復夢，羸馬禁城塵。"]'),
('c8d475c4-28e5-47ce-b2a1-7ed4f68f8c4e','大風','孔武仲','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','萬竅軒軒漸怒號，坐來渾怕屋山搖。',64,'全唐诗/poet.song.50000.json','["萬竅軒軒漸怒號，坐來渾怕屋山搖。", "洞庭曾聽咸池樂，吳會飽聞滄海潮。", "此地風聲真有似，殘春人意正無聊。", "雲師又洒天街雨，明日千宫好上朝。"]'),
('d24e6070-9743-4118-921c-f2024abe792e','洪福寺藤架','孔武仲','宋','宋诗','song-poetry','','[]','生長應毫末，敷腴忽十尋。',48,'全唐诗/poet.song.50000.json','["生長應毫末，敷腴忽十尋。", "繁花春不歇，密葉晝長陰。", "風過龍蛇動，雲開洞府深。", "時來學晏坐，朝市不闗心。"]'),
('bb100a6d-5451-4fa3-9aed-a8aa9d27e9ca','讀梁武帝紀二首  其一','孔武仲','宋','宋诗','song-poetry','','[]','破除綱紀事虚空，可恨蕭家一老翁。',32,'全唐诗/poet.song.50000.json','["破除綱紀事虚空，可恨蕭家一老翁。", "魚爛土崩俱自取，不須侯景到江東。"]'),
('33909838-d25b-4de1-88da-b175558442bd','讀梁武帝紀二首  其二','孔武仲','宋','宋诗','song-poetry','','[]','鉏決隄防縱怒濤，横流四海盡滔滔。',32,'全唐诗/poet.song.50000.json','["鉏決隄防縱怒濤，横流四海盡滔滔。", "單于已入朝陽殿，軟語空疑定力高。"]'),
('5a9b410c-d848-4b6f-ae4b-a2425ff402de','楸花','孔武仲','宋','宋诗','song-poetry','','[]','淡薄已無俗，秋高真出羣。',48,'全唐诗/poet.song.50000.json','["淡薄已無俗，秋高真出羣。", "峨峨掲翠藻，漫漫綴紅雲。", "遠色天街盡，餘香省户聞。", "狂風曉來劇，惆悵落紛紛。"]'),
('1ec18789-aca9-45d3-838d-1ea0cc7635a4','送望聖監南嶽廟','孔武仲','宋','宋诗','song-poetry','','["\u8861\u5c71"]','還鄉同赴紫宸朝，笑語從容慰寂寥。',64,'全唐诗/poet.song.50000.json','["還鄉同赴紫宸朝，笑語從容慰寂寥。", "白髮侵凌今滿鑑，青春羈旅舊連鑣。", "易江小隠西園在，湘浦新除道路遙。", "老境不堪論契濶，東風官柳亂隄橋。"]'),
('aa76fba6-1342-4005-af0a-286c23115b98','景靈宫殿多植荼䕷清香遠聞','孔武仲','宋','宋诗','song-poetry','','[]','宫殿沈沈鏁碧雲，仙葩相倚正敷芬。',32,'全唐诗/poet.song.50000.json','["宫殿沈沈鏁碧雲，仙葩相倚正敷芬。", "珠簾翠幄知多少，不礙清香處處聞。"]'),
('87d657e5-9057-457b-b30c-e30e3be380a5','送韓密學知定州','孔武仲','宋','宋诗','song-poetry','','[]','聞說公家閱古堂，于今出守似還鄉。',64,'全唐诗/poet.song.50000.json','["聞說公家閱古堂，于今出守似還鄉。", "營開細柳旌旗動，山假臙脂苜蓿長。", "北府貔貅瞻玉節，南樓風月寄胡床。", "親朋出祖無惆悵，早晚韓侯對未央。"]'),
('11e0ea44-e930-4a7f-ab15-f7737ee5774d','遊凝祥池同晁無咎作','孔武仲','宋','宋诗','song-poetry','','[]','平時念京國，此地愜幽情。',48,'全唐诗/poet.song.50000.json','["平時念京國，此地愜幽情。", "楊柳繁無路，鳬鷖遠有聲。", "郊原斜日下，襟袂好風生。", "把酒須拌醉，還家不隔城。"]'),
('221f2314-d901-47ef-883b-362feb686a55','送郟公甫通判睦州','孔武仲','宋','宋诗','song-poetry','','[]','又向東南去，都門奈若何。',48,'全唐诗/poet.song.50000.json','["又向東南去，都門奈若何。", "塵埃京洛久，山水富春多。", "宴俎誇魚美，書帷待雁過。", "鵬程休暫息，九萬看騰波。"]'),
('d086f16b-0422-449f-b2fb-c6d62f58826f','遊洪福寺','孔武仲','宋','宋诗','song-poetry','','[]','清晨戒童僕，匹馬出皇州。',48,'全唐诗/poet.song.50000.json','["清晨戒童僕，匹馬出皇州。", "欲探逍遙趣，因成爛漫遊。", "藤蘿回晝暝，雲雨送春愁。", "傍近緋桃塢，尋春亦少留。"]'),
('d4c79b2a-10ff-4bbf-97f1-98e76fafee8f','睡椅','孔武仲','宋','宋诗','song-poetry','','[]','非馬亦非船，可坐兼可眠。',36,'全唐诗/poet.song.50000.json','["非馬亦非船，可坐兼可眠。", "客來呼不應，睡美腹便便。", "書慵食飽後，還作定中禪。"]'),
('03c160f7-75e7-48e8-8b8c-de73be43a00c','次無咎凝祥春遊三首  其一','孔武仲','宋','宋诗','song-poetry','','[]','芸編校罷得嬉遊，池館雖春爽似秋。',32,'全唐诗/poet.song.50000.json','["芸編校罷得嬉遊，池館雖春爽似秋。", "同舍病郎追不及，喜傳佳句到瀛洲。"]'),
('70bd92bf-4e43-4710-a287-3439b72fa732','次無咎凝祥春遊三首  其二','孔武仲','宋','宋诗','song-poetry','','[]','浴日池光初炯炯，三春禽語已關關。',32,'全唐诗/poet.song.50000.json','["浴日池光初炯炯，三春禽語已關關。", "珍臺閒館波濤接，太液昆明伯仲間。"]'),
('d4b789de-0633-4dad-9a69-64394567c488','次無咎凝祥春遊三首  其三','孔武仲','宋','宋诗','song-poetry','','[]','奉靈池館鏁幽深，遺跡凄涼故老心。',32,'全唐诗/poet.song.50000.json','["奉靈池館鏁幽深，遺跡凄涼故老心。", "維嶽雲車時一下，直疑絃管有來音。"]'),
('cb6c9afd-2d12-48bc-9fb0-9070e326529a','遊州南同文潛作','孔武仲','宋','宋诗','song-poetry','','[]','峨峨宫殿列仙居，深水方圓氣象殊。',64,'全唐诗/poet.song.50000.json','["峨峨宫殿列仙居，深水方圓氣象殊。", "萬里舟船會京洛，幾人詩酒到蓬壺。", "日斜清弄來幽谷，風定蔫紅滿緑蕪。", "語罷恍然真夢幻，不應天邑有江湖。"]'),
('cce001d9-e74b-439e-a9ce-4f9976f2c1a9','館中桃花','孔武仲','宋','宋诗','song-poetry','','[]','蓬壺深絕鏁方菲，初見仙桃第一枝。',64,'全唐诗/poet.song.50000.json','["蓬壺深絕鏁方菲，初見仙桃第一枝。", "天近自應風景别，春長莫恨化工遲。", "相重朱户人稀到，半掩香苞蝶未知。", "想像江南今盛發，亦經頻雨稍離披。"]'),
('dbe54f76-0ed5-4304-b5b5-ff7426daedfa','早春','孔武仲','宋','宋诗','song-poetry','','[]','欲探年光好，春風入酒帘。',48,'全唐诗/poet.song.50000.json','["欲探年光好，春風入酒帘。", "寒威隨雪解，芳意逐情添。", "塞雁今回陣，冰魚稍出潛。", "王孫幽興動，顔巷自安恬。"]'),
('7ecd7df5-5ba1-40be-a345-2077b73d997f','謁吳傳正因贈','孔武仲','宋','宋诗','song-poetry','','[]','宴坐足觀妙，朝歸還閉門。',48,'全唐诗/poet.song.50000.json','["宴坐足觀妙，朝歸還閉門。", "身居丞相第，室似給孤園。", "競逐浮雲駛，難揩古鏡昏。", "相期荷君厚，商榷有清言。"]'),
('95169b5a-b21c-4ddb-be18-efe6479cbff1','立春晚會呈經父','孔武仲','宋','宋诗','song-poetry','','[]','侍史新從天上歸，相逢忻喜著春衣。',64,'全唐诗/poet.song.50000.json','["侍史新從天上歸，相逢忻喜著春衣。", "萱芽刺土占芳節，蘭醑傾觴亂夕暉。", "兄弟幾人華萼聚，歲時經眼羽翰飛。", "東風處處吹嘘到，從此鄉園笋蕨肥。"]'),
('71ef60d0-69a6-4c32-b411-db4955a5541f','石榴','孔武仲','宋','宋诗','song-poetry','','[]','造物巧雕鎪，慇懃在石榴。',48,'全唐诗/poet.song.50000.json','["造物巧雕鎪，慇懃在石榴。", "中妍寧暴露，外穏不輕浮。", "露液甘凝蜜，瓊房密貯秋。", "非徒適人口，飣坐亦風流。"]'),
('c916e1f0-1cbe-4905-904f-c9daf97a16be','送何司封知壽州','孔武仲','宋','宋诗','song-poetry','','[]','清淮带城郭，形勝壓吳天。',48,'全唐诗/poet.song.50000.json','["清淮带城郭，形勝壓吳天。", "人苦懷襄後，帝求師帥賢。", "郎官已分竹，畫鷁似登仙。", "昨夜驚烏坐，星輝共黯然。"]'),
('a5040000-f2a2-4c55-830b-bb13e9ba28b4','送傳正之官禮部','孔武仲','宋','宋诗','song-poetry','','[]','妙道微言早自知，鈞衡何事器君遲。',64,'全唐诗/poet.song.50000.json','["妙道微言早自知，鈞衡何事器君遲。", "連牆並屋相從久，聳壑昻霄此去宜。", "畫省含香脩故事，雲臺呼仗請私儀。", "想君清直家風在，好爲朝廷作伯夷。"]'),
('2f1bb8c4-ac96-4307-ace5-3b64082af771','十二月朔入局','孔武仲','宋','宋诗','song-poetry','','[]','坐聽禪林叩曉鐘，官曹遙指禁城東。',64,'全唐诗/poet.song.50000.json','["坐聽禪林叩曉鐘，官曹遙指禁城東。", "千門洒掃冰鑱路，萬木號呼葉受風。", "金殿放朝閒虎士，蟾泓揮翰冷瑤宫。", "春暉閉目無多日，預草新文擬送窮。"]'),
('7073c96e-8c39-4789-b2d1-0cc6a39631bd','送歐陽仲勉通判渭州','孔武仲','宋','宋诗','song-poetry','','[]','當年筆戰共詞場，老大聨袪振鷺行。',64,'全唐诗/poet.song.50000.json','["當年筆戰共詞場，老大聨袪振鷺行。", "薦牘北來當玉座，軺車西去擁銀章。", "潼關曉色雲藏市，渭曲春寒菜有霜。", "公退登臨多絕唱，解因風月記江鄉。"]'),
('4bebd4be-2059-4d1c-86e2-4092ecc2d0bb','至日拜表','孔武仲','宋','宋诗','song-poetry','','[]','絳闕横霄瑞靄重，千官拜表未央宫。',64,'全唐诗/poet.song.50000.json','["絳闕横霄瑞靄重，千官拜表未央宫。", "琤瑽玉佩侵寒漏，縹緲爐烟壓曉風。", "漢曆敢期隨日永，堯齡共祝與天同。", "賤生亦與華封祝，遙望清光斗極中。"]'),
('eda05ed9-3bdd-4b64-acfd-1eeac0cf2f78','送希甫使蜀','孔武仲','宋','宋诗','song-poetry','','[]','漢節西南出，征鞍萬里賖。',48,'全唐诗/poet.song.50000.json','["漢節西南出，征鞍萬里賖。", "清朝早敭歴，遠使更光華。", "山壯蠶叢國，雲深杜宇家。", "暫宣寛大詔，恩信及天涯。"]'),
('ab3de30d-47bf-42ad-bf19-7c7aa1d173be','苦寒','孔武仲','宋','宋诗','song-poetry','','[]','十年被冷東南方，未慣清寒客帝鄉。',64,'全唐诗/poet.song.50000.json','["十年被冷東南方，未慣清寒客帝鄉。", "碧落有聲飛夜霰，輕裘無力拒晨霜。", "鯨依海凍先摧鬛，雁起邊沙易失行。", "蒲柳脆肌尤不耐，暫憑盃酒作春陽。"]'),
('f8704b4e-9714-4fb5-a4c0-466afbda820a','大雪','孔武仲','宋','宋诗','song-poetry','','[]','窮年闕雨謾悲歌，喜見凌晨雪意多。',64,'全唐诗/poet.song.50000.json','["窮年闕雨謾悲歌，喜見凌晨雪意多。", "天上亂花初翦玉，樓頭密影已翻波。", "輪蹄著路纖塵斷，庭宇無風凛氣和。", "寄語雲師勤覆護，莫令光景漏銀河。"]'),
('0f639e9e-cf16-46e1-bf99-fb54cbccc2c9','寓目','孔武仲','宋','宋诗','song-poetry','','[]','啾啾黄雀在枝間，歲晚荒郊怨苦寒。',32,'全唐诗/poet.song.50000.json','["啾啾黄雀在枝間，歲晚荒郊怨苦寒。", "容易驚飛無處所，人家曾借畫圖看。"]'),
('679f1a42-4c46-43b2-81ab-e046ca4db661','立春日','孔武仲','宋','宋诗','song-poetry','','[]','開歲春寒便有花，官閒只飲酒如霞。',32,'全唐诗/poet.song.50000.json','["開歲春寒便有花，官閒只飲酒如霞。", "殿門促賀新幡勝，書館年來事事嘉。"]'),
('8feca212-5768-4e35-b143-9b53f30290bf','次韻瀛倅鄧慎思見寄','孔武仲','宋','宋诗','song-poetry','','[]','官是麟臺却佐州，蓬瀛俱稱列仙遊。',64,'全唐诗/poet.song.50000.json','["官是麟臺却佐州，蓬瀛俱稱列仙遊。", "憶分曉色趨天闕，想對春風倚郡樓。", "書付塞鴻應易到，人如隴水正分流。", "江湖未有歸耕處，何日相逢說旅愁。"]'),
('35c20769-688e-4592-b4f7-0667e48af7e5','初賜幡勝戲和諸公二首  其一','孔武仲','宋','宋诗','song-poetry','','[]','鏤幡翦勝喜傾朝，不問紆藍與珥貂。',64,'全唐诗/poet.song.50000.json','["鏤幡翦勝喜傾朝，不問紆藍與珥貂。", "羣玉參差排晚日，萬花瑣碎動春霄。", "蕙風已轉東郊緑，柳雪猶低北苑條。", "從此恩波與温律，併隨歌頌入咸韶。"]'),
('b44fa021-8ec0-414a-8c83-7a52152d6fbe','初賜幡勝戲和諸公二首  其二','孔武仲','宋','宋诗','song-poetry','','[]','拜賜匆匆早上朝，公卿前列盡金貂。',64,'全唐诗/poet.song.50000.json','["拜賜匆匆早上朝，公卿前列盡金貂。", "日留愛景明雙闕，春逐恩輝下九霄。", "靈沼輕凘猶覆水，上林微緑已縈條。", "自慚羽翮非鸞鳳，亦預彤庭舞舜韶。"]'),
('97fc3cef-bc92-4571-9001-e01304a33701','冬至夜飲','孔武仲','宋','宋诗','song-poetry','','[]','翠帟排銀燭，金爐飄篆香。',48,'全唐诗/poet.song.50000.json','["翠帟排銀燭，金爐飄篆香。", "人情感佳節，天氣踏新陽。", "醉怯醇醪酒，寒知碧瓦霜。", "明朝指天闕，萬壽獻君王。"]'),
('17c903de-2dfe-4f7c-956a-85605073c939','至節小雨','孔武仲','宋','宋诗','song-poetry','','[]','半醉聽銀漏，輕寒解罽裘。',48,'全唐诗/poet.song.50000.json','["半醉聽銀漏，輕寒解罽裘。", "新陽萬物動，小雨五更收。", "宿潤青槐道，晨輝紫禁樓。", "皇恩與天澤，渾逐管絃流。"]'),
('7fca4f62-53a2-4ec8-83d0-bdad7d6a4dac','游建隆觀','孔武仲','宋','宋诗','song-poetry','','[]','瑞雲靈迹久荒蕪，琳館重開聳碧虚。',64,'全唐诗/poet.song.50000.json','["瑞雲靈迹久荒蕪，琳館重開聳碧虚。", "邂逅馬蹄過勝境，紛紜人世得仙居。", "異花重疊春輝早，喬木森陰晚景疏。", "金闕瑤臺不容久，歸來風馭冷襟裾。"]'),
('5045a3d6-d6a3-45b8-8736-b23f583e2b53','淨因院赴浴','孔武仲','宋','宋诗','song-poetry','','[]','漢客疲江海，乘槎萬里歸。',48,'全唐诗/poet.song.50000.json','["漢客疲江海，乘槎萬里歸。", "重尋象王舍，一浣洛城衣。", "壞壁凝香靄，明軒泛暮暉。", "紅塵不相貸，歸路驟驂騑。"]'),
('595f1643-f005-4dce-ab86-ed8864128656','次韻宋履中歲晏言懷','孔武仲','宋','宋诗','song-poetry','','[]','寂寞郊居遠，晨晡四馬馳。',48,'全唐诗/poet.song.50000.json','["寂寞郊居遠，晨晡四馬馳。", "日驚東逝水，心感歲寒枝。", "霜色朝如洗，雲容莫不怡。", "梁園將密雪，不飲亦奚爲。"]'),
('4c6de816-3f93-46d9-aacc-4da40007770a','次韻李至之席上作','孔武仲','宋','宋诗','song-poetry','','[]','歲月翩翩插羽過，十年依舊歎蹉跎。',64,'全唐诗/poet.song.50000.json','["歲月翩翩插羽過，十年依舊歎蹉跎。", "雁回燕塞鄉書少，雪滿梁園雅集多。", "取樂醉鄉聊邂逅，爭新談藪任紛羅。", "慇懃尚託摳衣舊，遙許巴吟續郢歌。"]'),
('e1ed8d83-7158-4816-9bfc-058d6b806279','送曹千方奉使閩中','孔武仲','宋','宋诗','song-poetry','','[]','聞說乘軺美，全囗勝赴囗。',48,'全唐诗/poet.song.50000.json','["聞說乘軺美，全囗勝赴囗。", "先聲馳嶺海，和氣入山川。", "路束籃輿過，書憑塞雁傳。", "祝君求荈草，醒我北窗眠。"]'),
('1ab60a80-8ca4-48b6-9c99-3bffe8e1074c','五鼓','孔武仲','宋','宋诗','song-poetry','','[]','永夜無塵事，閒眠似道堂。',48,'全唐诗/poet.song.50000.json','["永夜無塵事，閒眠似道堂。", "紙窗分曉色，絮被借春陽。", "萬慮此中息，一身今可忘。", "周公不足夢，佳趣在羲皇。"]'),
('3e274cb4-1655-46e0-b717-9b3a21e69d67','孔周翰挽詞三首  其一','孔武仲','宋','宋诗','song-poetry','','[]','邂逅湓江口，方知叔父親。',48,'全唐诗/poet.song.50000.json','["邂逅湓江口，方知叔父親。", "榮華纔一夢，奄忽幾千春。", "白玉沽何晚，精金鍛愈真。", "耆年所宜得，天苦奪斯人。"]'),
('f1df586b-6805-42db-a10d-bdb8306a8446','孔周翰挽詞三首  其二','孔武仲','宋','宋诗','song-poetry','','[]','循吏今之選，皇華使者軺。',48,'全唐诗/poet.song.50000.json','["循吏今之選，皇華使者軺。", "闗河初異路，巾笏偶同朝。", "急景催遲莫，清魂返泬寥。", "一哀慚不達，生理故風飇。"]'),
('9a1f1b69-e96d-47d6-ae5b-cf9eed0b5c91','孔周翰挽詞三首  其三','孔武仲','宋','宋诗','song-poetry','','[]','晚歲班朝列，光華動士林。',48,'全唐诗/poet.song.50000.json','["晚歲班朝列，光華動士林。", "家風當冠豸，官序正腰金。", "霄漢亨衢淺，膏肓積沴深。", "凄涼哭門館，笑語尚餘音。"]'),
('2bb0bb12-6e6b-494d-9097-7e22ae6c0b24','黄幾道挽詞','孔武仲','宋','宋诗','song-poetry','','[]','當時京右盛朋従，邂逅經旬託泮宫。',64,'全唐诗/poet.song.50000.json','["當時京右盛朋従，邂逅經旬託泮宫。", "詩社苦吟霜月白，離亭縦飲酒盃空。", "十年契濶江湖外，百歲推遷夢幻中。", "行已臨民俱可述，仍高孝友古人風。"]'),
('68d6c74f-3320-4fc7-8673-8ac165faf54f','施夫人挽詩','孔武仲','宋','宋诗','song-poetry','','[]','有子紆朝服，平居奉典彞。',48,'全唐诗/poet.song.50000.json','["有子紆朝服，平居奉典彞。", "蹉跎五鼎養，奄忽百年期。", "故宅萱堂掩，新阡薤露悲。", "遺芳託虀臼，髣髴九泉知。"]'),
('a69f1990-839d-490c-bde2-a169bdfc28e7','司馬溫公挽詩五首  其一','孔武仲','宋','宋诗','song-poetry','','[]','龍卧南陽久，天回北斗高。',48,'全唐诗/poet.song.50000.json','["龍卧南陽久，天回北斗高。", "廟堂更政化，巖谷起英髦。", "正色朝端肅，華巔國務勞。", "西州忽移翣，風木動悲號。"]'),
('625ae0b3-3bd2-4a71-a925-8a669add25c4','司馬溫公挽詩五首  其二','孔武仲','宋','宋诗','song-poetry','','[]','鼎鼐華元老，朝廷倚上台。',48,'全唐诗/poet.song.50000.json','["鼎鼐華元老，朝廷倚上台。", "除疴得鍼砭，作解有風雷。", "尚冀松椿壽，誰令柱石摧。", "英靈參列宿，餘惠在春臺。"]'),
('90c27028-ca26-40c9-baae-bf6e4500a1cb','司馬溫公挽詩五首  其三','孔武仲','宋','宋诗','song-poetry','','[]','賜告恩稠疊，聞喪上震驚。',48,'全唐诗/poet.song.50000.json','["賜告恩稠疊，聞喪上震驚。", "秋原無喜色，夜雨有悲聲。", "世路嗟存没，公心達死生。", "蓬山預讎校，新見史書成。"]'),
('e677d96b-12fe-42a5-a41f-1d5202850bc0','司馬溫公挽詩五首  其四','孔武仲','宋','宋诗','song-poetry','','[]','高步朝廷上，羽儀鵷鷺行。',48,'全唐诗/poet.song.50000.json','["高步朝廷上，羽儀鵷鷺行。", "精誠貫金石，素節履冰霜。", "爽氣今仍在，斯人没不亡。", "嵩雲自閒暇，長映讀書堂。"]'),
('27f4091d-5cc7-4fa5-862b-a05f14192116','司馬溫公挽詩五首  其五','孔武仲','宋','宋诗','song-poetry','','[]','拙與世沈浮，登門二十秋。',48,'全唐诗/poet.song.50000.json','["拙與世沈浮，登門二十秋。", "雲天曾送上，風壑此來遊。", "霄漢三台坐，江湖萬里舟。", "摳衣已不及，慘愴逝川流。"]'),
('528163a3-ccb5-40b1-a1be-12b20a07f085','龜山寺納涼呈宗衍師','孔武仲','宋','宋诗','song-poetry','','[]','寶洞然香罷，山堂問話中。',48,'全唐诗/poet.song.50000.json','["寶洞然香罷，山堂問話中。", "日將秋共淡，心與境渾空。", "彈指看浮世，披襟納遠風。", "因知宴坐者，白首樂無窮。"]'),
('c184be7c-5339-4fe6-8dad-7660587bd9ca','泗州','孔武仲','宋','宋诗','song-poetry','','[]','天都佳氣鬱葱葱，轉盼江河萬斛通。',64,'全唐诗/poet.song.50000.json','["天都佳氣鬱葱葱，轉盼江河萬斛通。", "可但臨淮稱要地，直因排泗有神功。", "僧伽普照靈如在，寶櫝都梁翠倚空。", "慚愧使星留客厚，塵埃揮手各西東。"]'),
('ce10a3ec-810a-4f97-bf18-00394081072a','寄武昌簿孫彦常','孔武仲','宋','宋诗','song-poetry','','[]','羈旅悠悠歲月殘，勝遊無復似西山。',64,'全唐诗/poet.song.50000.json','["羈旅悠悠歲月殘，勝遊無復似西山。", "從容把酒來天上，滴瀝鳴泉滿坐間。", "醉思隨風飄碧落，離襟和月堕荒灣。", "遙應蠟屐頻登覽，簿領無憂多晝閒。"]'),
('319a7133-ff5d-4b2d-ac91-753713084307','館中呈魯直','孔武仲','宋','宋诗','song-poetry','','[]','日過鼇山三丈紅，陳編相對鬢如蓬。',32,'全唐诗/poet.song.50000.json','["日過鼇山三丈紅，陳編相對鬢如蓬。", "朱門請謁無時了，且訪東鄰慢𧦧翁。"]'),
('efbd176f-e015-4fa1-81e2-d347eb490c17','試院書事呈子駿明叔三篇  其一','孔武仲','宋','宋诗','song-poetry','','[]','憶初懷詔下天街，紅燭相隨御史來。',64,'全唐诗/poet.song.50000.json','["憶初懷詔下天街，紅燭相隨御史來。", "場屋喜遵新定格，朝廷思見已成材。", "誅鋤險異歸平坦，洗濯英華出草萊。", "文藻諸生皆足用，更期儒行比騫回。"]'),
('a7d78d01-be73-40d1-a2fd-ef6ce86ccaf1','試院書事呈子駿明叔三篇  其二','孔武仲','宋','宋诗','song-poetry','','[]','當年場屋未分袍，文陣今將逸對勞。',64,'全唐诗/poet.song.50000.json','["當年場屋未分袍，文陣今將逸對勞。", "紫案飄香還序拜，畫堂横幕看揮毫。", "心遊造化羣囂靜，筆吐虹霓萬丈高。", "長育人材今久矣，行看中選盡英豪。"]'),
('6d4fd3d5-c065-4383-82d9-caf408703816','試院書事呈子駿明叔三篇  其三','孔武仲','宋','宋诗','song-poetry','','[]','汾陽韋曲盡名臣，邂逅羣居得遠孫。',64,'全唐诗/poet.song.50000.json','["汾陽韋曲盡名臣，邂逅羣居得遠孫。", "玉琢兩圭看德器，河傾千里瞰詞源。", "鴛行平日隨朝謁，鼎立今朝定討論。", "只恐門開便分散，追風難認馬蹄痕。"]'),
('3f669b57-9908-42fd-a815-a48910ff3c4f','試院呈上官御史','孔武仲','宋','宋诗','song-poetry','','[]','當年容與樂虞庠，今日掄才道更光。',64,'全唐诗/poet.song.50000.json','["當年容與樂虞庠，今日掄才道更光。", "但愛襟懷無岸谷，不知銜位带風霜。", "氣鍾海上仙山秀，袍擁天邊玉樹香。", "衡鑑賴公歸一律，明朝歸馬快騰驤。"]'),
('a7b85018-912c-4bfe-9616-bb5bb467e7a2','試院書事呈同僚諸公','孔武仲','宋','宋诗','song-poetry','','[]','九衢奔走厭紅塵，官舍連朝得閉門。',64,'全唐诗/poet.song.50000.json','["九衢奔走厭紅塵，官舍連朝得閉門。", "瑩靜軒窗移白日，青熒燈火送黄昏。", "披衣已愛星辰爛，奉御方瞻斗極尊。", "早晚虞庠誇得士，相隨笑語入天閽。"]'),
('f5c37959-1686-46dd-9a29-c30c680b83fa','送梅子明還吳','孔武仲','宋','宋诗','song-poetry','','[]','姑蘇限雲水，官舍隠蓬萊。',48,'全唐诗/poet.song.50000.json','["姑蘇限雲水，官舍隠蓬萊。", "出汴青山湧，横江畫舸開。", "家園雖渴别，書社早歸來。", "新命鄉人喜，神仙舊姓梅。"]'),
('eacd3f71-5644-4abc-847f-bb4472be4a19','大業二絕  其一','孔武仲','宋','宋诗','song-poetry','','[]','西苑池塘涸海流，君王十騎月中遊。',32,'全唐诗/poet.song.50000.json','["西苑池塘涸海流，君王十騎月中遊。", "蛾眉排户爭新寵，不道迷藏自有樓。"]'),
('da7fc77d-0861-466d-a267-0ba21dcbc97a','大業二絕  其二','孔武仲','宋','宋诗','song-poetry','','[]','杳杳揚州只隔淮，龍舟彩舸映天來。',32,'全唐诗/poet.song.50000.json','["杳杳揚州只隔淮，龍舟彩舸映天來。", "春風咫尺伊川路，不放君王殿脚回。"]'),
('7f02f5ca-588c-405a-a275-268c5d1a4f50','夏日入館','孔武仲','宋','宋诗','song-poetry','','[]','青驄曉轉緑槐陰，金碧重重魏闕深。',64,'全唐诗/poet.song.50000.json','["青驄曉轉緑槐陰，金碧重重魏闕深。", "洞裏天花長带露，門前畏日自流金。", "雲臺朱檻鄰星斗，石室牙籤照古今。", "宦學從來難兩得，君恩優假是書林。"]'),
('4e0a532a-a58a-479e-b329-d882c16d6013','四月二十二日拜第二表請御正殿','孔武仲','宋','宋诗','song-poetry','','[]','驟雨鳴宫瓦，新槐密禁城。',48,'全唐诗/poet.song.50000.json','["驟雨鳴宫瓦，新槐密禁城。", "鴛行趨曉肅，雞唱入雲清。", "日晃千袍影，風傳萬歲聲。", "天心求允協，飛奏入承明。"]'),
('10b218f4-bf55-4eb6-a3b5-b5ff7ada201d','大熱歸城西止于興國戒壇院','孔武仲','宋','宋诗','song-poetry','','[]','紅塵迎馬盡飛浮，日脚横天凝不流。',32,'全唐诗/poet.song.50000.json','["紅塵迎馬盡飛浮，日脚横天凝不流。", "金碧崢嶸涼意動，歸軒聊作化城游。"]'),
('b58d3702-cd68-498b-81c5-97f477105d20','館中夏日','孔武仲','宋','宋诗','song-poetry','','[]','珍簟舒明玉，涼窗納碧天。',48,'全唐诗/poet.song.50000.json','["珍簟舒明玉，涼窗納碧天。", "殿樓傳遠鼓，宫井取深泉。", "竹籜風頻脫，榴房晚更鮮。", "却驚非故國，五月未聞蟬。"]'),
('a8120117-eb58-4ce4-9e44-02f365e63c8c','直舍新闢西窗二首  其一','孔武仲','宋','宋诗','song-poetry','','[]','推倒西牆平日功，暑天饒作一窗風。',32,'全唐诗/poet.song.50000.json','["推倒西牆平日功，暑天饒作一窗風。", "人間豈有炎涼隔，只在施爲向背中。"]'),
('d2539e41-8c19-449d-b1da-449b42ac5520','直舍新闢西窗二首  其二','孔武仲','宋','宋诗','song-poetry','','[]','幾歲榴花蔽曲隈，繁陰初逼坐中來。',32,'全唐诗/poet.song.50000.json','["幾歲榴花蔽曲隈，繁陰初逼坐中來。", "西鄰小檻如圖畫，偷入簾帷次第開。"]'),
('04f2e3b0-fc46-4dd0-9674-c4b6035c708e','待朝','孔武仲','宋','宋诗','song-poetry','','[]','山軒斜透山南月，坐看天邊桂影移。',32,'全唐诗/poet.song.50000.json','["山軒斜透山南月，坐看天邊桂影移。", "圓扇矮床涼透骨，怱怱無奈上朝時。"]'),
('80d16d74-98f6-4a2f-ad36-1f445ec2d13c','次韻天覺行縣','孔武仲','宋','宋诗','song-poetry','','[]','餘涼凜凜認乘驄，分走郊圻督事功。',64,'全唐诗/poet.song.50000.json','["餘涼凜凜認乘驄，分走郊圻督事功。", "照路官儀驚衆目，快襟詩思有清風。", "隋河楊柳縈天上，魏闕觚稜在夢中。", "朝會相逢勞行色，滑稽酬對興無窮。"]'),
('59599eed-8d9b-4beb-838c-a9e7957b05c9','碧蘆蓼花在天慶觀','孔武仲','宋','宋诗','song-poetry','','[]','御水泱泱繞禁闈，碧蘆紅蓼轉相宜。',32,'全唐诗/poet.song.50000.json','["御水泱泱繞禁闈，碧蘆紅蓼轉相宜。", "玉堂金闕非人世，亦有繁華具盡時。"]'),
('54d4fded-3faf-4c61-923c-42697441ca46','遊籍田三首  其一','孔武仲','宋','宋诗','song-poetry','','[]','酷暑不可逭，天郊聊共尋。',48,'全唐诗/poet.song.50000.json','["酷暑不可逭，天郊聊共尋。", "雲繁當飛蓋，風好得披襟。", "白水田疇遠，紅蕖浦溆深。", "斜川陶靖節，千載想知心。"]'),
('bf7944dd-7c89-4682-9897-e36f0389c296','遊籍田三首  其二','孔武仲','宋','宋诗','song-poetry','','[]','杖履重林外，樽罍曲水邊。',48,'全唐诗/poet.song.50000.json','["杖履重林外，樽罍曲水邊。", "深荷時下鷺，喬木正嘶蟬。", "敏捷文楸戰，清涼竹簟眠。", "浮瓜復沈李，况有主人賢。"]'),
('88698d24-4c26-4b16-92c7-853a6c7c2a55','遊籍田三首  其三','孔武仲','宋','宋诗','song-poetry','','[]','落日隠山谷，清風來户庭。',48,'全唐诗/poet.song.50000.json','["落日隠山谷，清風來户庭。", "爛柯棋已罷，伏檻酒初醒。", "歸轡須長騖，都門偶未扄。", "辛勤到蓬蓽，林表已華星。"]'),
('77850ca6-bcc7-490e-8188-a2bd976f9ea5','書省即事','孔武仲','宋','宋诗','song-poetry','','[]','恩旨讎書到午休，笑談連手得優游。',64,'全唐诗/poet.song.50000.json','["恩旨讎書到午休，笑談連手得優游。", "窗聲漸漸回脩竹，庭實鮮鮮嚲石榴。", "風色洗清天畔闕，鼓聲遙轉日邊樓。", "羣仙暫駕飛鸞去，從此蓬山更少留。"]'),
('fa4e3420-2316-488e-b248-3c85bb0083f5','六月望參','孔武仲','宋','宋诗','song-poetry','','[]','宿露初晞物向陽，袍鞋如水轉迴廊。',64,'全唐诗/poet.song.50000.json','["宿露初晞物向陽，袍鞋如水轉迴廊。", "天開北極星辰正，風應南薰殿閣涼。", "蓂莢已瞻圓魄就，槐花初覆廣庭香。", "朝廷禮數優元老，獨後千官拜未央。"]'),
('1a557a22-8518-4dd8-a13a-fa754a49f4e7','謝彦成子姪四人同時登科調官南歸','孔武仲','宋','宋诗','song-poetry','','[]','處士好孫子，秘書賢弟兄。',48,'全唐诗/poet.song.50000.json','["處士好孫子，秘書賢弟兄。", "弓旌萬里會，蘭玉一家榮。", "盛事酬先志，清風警後生。", "田園何足道，力學是功名。"]'),
('1c5c9c73-9d2c-40aa-8778-87c021a0a651','馬上有作','孔武仲','宋','宋诗','song-poetry','','[]','宫城北轉亂蟬嘶，喬木陰雲水滿陂。',32,'全唐诗/poet.song.50000.json','["宫城北轉亂蟬嘶，喬木陰雲水滿陂。", "一陣風來掠華鬢，江湖清興有誰知。"]'),
('807d7348-ff7a-4836-ae5f-34afdb0c3092','送傅龍圖帥秦','孔武仲','宋','宋诗','song-poetry','','[]','公才卓犖有施爲，鎮俗安邊正及時。',64,'全唐诗/poet.song.50000.json','["公才卓犖有施爲，鎮俗安邊正及時。", "東壁圖書遷秩峻，西州父老歎來遲。", "門開細柳軍無匹，劍下樓蘭敵未知。", "聞道秦州多勝迹，登高能廣少陵詩。"]'),
('8d7418af-21be-4cc0-8701-85b430e9a904','送景文之官明州','孔武仲','宋','宋诗','song-poetry','','[]','京塵不可久，得地海潮東。',48,'全唐诗/poet.song.50000.json','["京塵不可久，得地海潮東。", "市郭滄溟上，庵巖翠嶂中。", "江瑤如切玉，越女不施紅。", "官事從容了，時當作醉翁。"]'),
('1f7ef2d7-1b3e-4a87-bdfc-66ba95a4a745','送天覺使河東','孔武仲','宋','宋诗','song-poetry','','[]','張郎肥馬衣輕裘，俊氣軒軒不解愁。',64,'全唐诗/poet.song.50000.json','["張郎肥馬衣輕裘，俊氣軒軒不解愁。", "曾立玉墀聨近侍，新持金節領諸侯。", "屠龍伎倆終須用，探虎功名未肯休。", "去矣范滂聊緩轡，太行雲路戒摧舟。"]'),
('1cd29712-f68b-4ded-a8d4-5f7de05acb9a','坤成節南宫賜宴','孔武仲','宋','宋诗','song-poetry','','[]','盛德千齡會，坤成四海觀。',144,'全唐诗/poet.song.50000.json','["盛德千齡會，坤成四海觀。", "南琛走交趾，北賮引呼韓。", "紫極經躔近，文昌步武寛。", "横天起嵩華，照地集琅玕。", "美酒來天禄，珍殽賜大官。", "鑪煙凝棟宇，冰雪襲盃槃。", "瞻拜戎心服，山呼士氣歡。", "風清百尺廡，花壓兩梁冠。", "雷作聞撾鼓，猱升看戲竿。", "華裀舒霧靄，妙舞起波瀾。", "喬木秋聲遠，高城夕照殘。", "天街淡佳氣，振鷺杳歸翰。"]'),
('3e1bd338-4ef4-4cd5-8f80-ee54dad9d8eb','送芸老通判','孔武仲','宋','宋诗','song-poetry','','[]','御史連章乞此行，制書優遣副專城。',64,'全唐诗/poet.song.50000.json','["御史連章乞此行，制書優遣副專城。", "京都豈乏翺翔處，忠義先期去就明。", "祖帳盃槃留晚色，關山草木動秋聲。", "西州莫作經年計，早晚君王召賈生。"]'),
('eeed3ad0-3853-43d9-9949-2510bb60bd68','有旨放八月朔參','孔武仲','宋','宋诗','song-poetry','','[]','八月大明宫，朝班放會同。',48,'全唐诗/poet.song.50000.json','["八月大明宫，朝班放會同。", "天時鬱殘暑，聖語似清風。", "蕙帳便秋睡，沙隄緩曉驄。", "葵心終不已，長望日升東。"]'),
('1dab6c79-6e91-4916-be60-14d5b1ca1c88','聞王師破洮河城獲鬼章','孔武仲','宋','宋诗','song-poetry','','[]','盛德包荒與古同，十年關塞古洮戎。',64,'全唐诗/poet.song.50000.json','["盛德包荒與古同，十年關塞古洮戎。", "神兵合？來天上，猛虎逡巡落檻中。", "蜀境粗償關羽恨，漢津今奏武皇功。", "城陰却歎周南滯，夢想鵷行紫禁東。"]'),
('fbe6afa4-ff59-47f9-915f-e833c83b5b1a','次韻鄧慎思初入同文館','孔武仲','宋','宋诗','song-poetry','','[]','十載江湖萬里行，偶來西館閱豪英。',64,'全唐诗/poet.song.50000.json','["十載江湖萬里行，偶來西館閱豪英。", "雲龍九闕晨書詔，燈火千門夜出城。", "瀟洒庭除當月色，重稠幕帟斷人聲。", "年家兄弟今同舍，會見河南起賈生。"]'),
('5f85cf83-d954-4ee1-a6dc-0c3636c4226c','次韻余樗年同文館書事','孔武仲','宋','宋诗','song-poetry','','[]','衡門咫尺限闗河，此地平時匹馬過。',64,'全唐诗/poet.song.50000.json','["衡門咫尺限闗河，此地平時匹馬過。", "欲把塵埃比山嶽，寧辭羽翮寄罝羅。", "華堂翠幕供閒燕，明月清風伴嘯歌。", "擬寫秋容須筆力，新詩句句似陰何。"]'),
('82023fd4-cdfb-4f87-9465-a6b13737a930','酒帘','孔武仲','宋','宋诗','song-poetry','','[]','閃閃風中誇緑醽，當年匹馬下旗亭。',32,'全唐诗/poet.song.50000.json','["閃閃風中誇緑醽，當年匹馬下旗亭。", "秋原敗葉聲如掃，只有雲山伴醉醒。"]'),
('f81f776c-324e-41d6-8d83-c324f5b89f4b','吕推卿出孔雀畫圖','孔武仲','宋','宋诗','song-poetry','','[]','晝卧蓬山禁漏長，起觀名畫得心降。',64,'全唐诗/poet.song.50000.json','["晝卧蓬山禁漏長，起觀名畫得心降。", "曾聞飲啄依南海，頗怪飛鳴到北窗。", "峭格正宜風作馭，脩翎堪與鳳爲雙。", "知公物外尋幽好，不戀榮華擁節幢。"]'),
('639ea4dd-6e62-46e9-9365-8aa93e5fd781','上禫除恭謝迎駕有作','孔武仲','宋','宋诗','song-poetry','','[]','仗衛風生下玉宸，傾都瞻望屬車塵。',64,'全唐诗/poet.song.50000.json','["仗衛風生下玉宸，傾都瞻望屬車塵。", "乾龍已應飛翔始，震鬯方觀薦奠新。", "星象低回隨曲蓋，天閶蒼莽入鈎陳。", "麟臺亦與班迎末，不美甘泉作賦人。"]'),
('9ba68442-4902-4f0e-b17c-495debaef78f','送張文潛之淮南','孔武仲','宋','宋诗','song-poetry','','[]','瀛館登仙俊，金閨引籍優。',48,'全唐诗/poet.song.50000.json','["瀛館登仙俊，金閨引籍優。", "辭班見天子，行色動諸侯。", "楚日籃輿暖，淮南畫舸遒。", "歸時春已好，遲子曲江頭。"]'),
('05125126-ed0c-41c0-93a5-d6e65ee35521','蛤蜊','孔武仲','宋','宋诗','song-poetry','','[]','去年曾賦蛤蜊篇，旅館霜高月正圓。',64,'全唐诗/poet.song.50000.json','["去年曾賦蛤蜊篇，旅館霜高月正圓。", "舊舍朋從今好在，新時節物故依然。", "棲身未厭泥沙穏，爽口還充鼎俎鮮。", "適意四方無不可，若思鱸鱠未應賢。"]'),
('b9d3d6e1-1b3b-4a96-a040-8341f5da4449','送崔伯陽守潁州','孔武仲','宋','宋诗','song-poetry','','[]','聽說州除美，州臨潁水清。',48,'全唐诗/poet.song.50000.json','["聽說州除美，州臨潁水清。", "風謠带京洛，湖島似蓬瀛。", "昔泛扁舟下，今聞太守行。", "山川應好在，爲道旅人情。"]'),
('e99411de-8c7b-4de5-9f8d-a4c0c52ffbeb','十一月十六日入館','孔武仲','宋','宋诗','song-poetry','','[]','一雪初乾曉日紅，行人爭道已憧憧。',64,'全唐诗/poet.song.50000.json','["一雪初乾曉日紅，行人爭道已憧憧。", "泥縈馬足行初躓，寒犯貂裘力正濃。", "地逼新陽雖喜氣，雲垂滄海更愁容。", "便應買酒邀儔侣，爛醉高眠羣玉峰。"]'),
('1694ddf4-ce9b-4427-882c-8f3a1377e529','送游景叔使陜西','孔武仲','宋','宋诗','song-poetry','','[]','諭指嚴生不憚勞，爲君談笑取臨洮。',64,'全唐诗/poet.song.50000.json','["諭指嚴生不憚勞，爲君談笑取臨洮。", "軺車復歴秦關險，繡扆新瞻漢殿高。", "直使三農歸隴畝，勤將尺紙薦英豪。", "峰嵐澗水香山路，想見春風動錦袍。"]'),
('da8d6cc4-e4d4-44e5-8623-6c6261356628','臘月三日','孔武仲','宋','宋诗','song-poetry','','[]','寒窗勁色曉覃覃，又見京華臘月三。',32,'全唐诗/poet.song.50000.json','["寒窗勁色曉覃覃，又見京華臘月三。", "官渡梅花應照水，香清回首憶江南。"]'),
('46ba77c0-cbce-47b3-bb2c-3973ba054fe3','雪後','孔武仲','宋','宋诗','song-poetry','','[]','萬里屯雲一夜收，天街累日未通牛。',64,'全唐诗/poet.song.50000.json','["萬里屯雲一夜收，天街累日未通牛。", "峨峨正覺嚴冰起，㶁㶁還同澗水流。", "色變荒郊迎日媚，氣蒸黄壤逼春浮。", "農家不用藏乾麫，相與新年飽麥麰。"]'),
('e960b2f5-1a63-4320-8463-18af494b913d','興龍節上壽','孔武仲','宋','宋诗','song-poetry','','[]','瑞雪峨峨宫殿明，千秋佳節會公卿。',64,'全唐诗/poet.song.50000.json','["瑞雪峨峨宫殿明，千秋佳節會公卿。", "香飄彩霧縈天仗，酒浥流霞滿壽觥。", "密勿華封多好語，鏘洋鈞奏盡和聲。", "自憐初預稱觴樂，江海飄萍已半生。"]'),
('36271eec-bd0f-4036-9c4f-1e1be51fe42c','葡萄','孔武仲','宋','宋诗','song-poetry','','[]','萬里殊方種，東隨漢節歸。',48,'全唐诗/poet.song.50000.json','["萬里殊方種，東隨漢節歸。", "露珠凝作骨，雲粉漬爲衣。", "柔緑因風長，圓青带雨肥。", "金盤堆馬乳，樽俎爲増輝。"]'),
('9de94c2e-e260-4917-a475-178f58fbadb7','金橘','孔武仲','宋','宋诗','song-poetry','','[]','暑岸千株緑，秋庭萬點黄。',48,'全唐诗/poet.song.50000.json','["暑岸千株緑，秋庭萬點黄。", "明晶能奪目，圓滿要經霜。", "瑞露凝膚滿，甘泉沃肺涼。", "美滄不解事，金椀薦檳榔。"]'),
('f77fa431-d428-41a0-b252-bd547fd915eb','送王頤赴官八桂','孔武仲','宋','宋诗','song-poetry','','[]','欠不憶桂海，因君還起予。',48,'全唐诗/poet.song.50000.json','["欠不憶桂海，因君還起予。", "江光平漫石，山翠上凌虚。", "黄港窺尋舊，青衫黽勉初。", "年豐桴鼓息，清趣在琴書。"]'),
('f2a4f37f-2741-4a6f-abe7-375a5584fda6','獻西俘','孔武仲','宋','宋诗','song-poetry','','[]','先帝謀西域，邊功未告成。',288,'全唐诗/poet.song.50000.json','["先帝謀西域，邊功未告成。", "一朝鋤狡穴，萬里振天聲。", "漢獄宜歸死，湯羅尚借生。", "淮陰甘就縛，頡利許留京。", "雲氣占中國，星辰闢大明。", "珠簾垂後殿，玉座肅西清。", "二帝臨朝會，千官響珮珩。", "理司來執訊，譯者爲通名。", "殊俗衣冠異，渠魁口眼獰。", "孽狐仍俯聽，窮鳥尚悲鳴。", "上德均乾覆，臚傳貸鼎烹。", "大廷觀舞獸，滄海息波鯨。", "禄給朝晡糒，書通父子情。", "熊羆已馴伏，螻蟻敢縦横。", "憶昨初擒冦，無慚古用兵。", "謀謨維素決，軍事許專征。", "蕃漢心諧會，人祗力混并。", "波濤迷古渚，氛霧壓洮城。", "慘淡移天陣，逡巡却冦營。", "空拳槌猰貐，隻矢隕攙槍。", "雜種降無數，良民市不驚。", "旂常配方召，干羽繼韶莖。", "奏捷公卿賀，酬勲將佐榮。", "夏戎幾失筯，遼主願尋盟。"]'),
('559154fd-6f71-4198-8604-7786d437e219','送仲至學士使北','孔武仲','宋','宋诗','song-poetry','','[]','聖策招懷萬里戎，累年南向不彎弓。',64,'全唐诗/poet.song.50000.json','["聖策招懷萬里戎，累年南向不彎弓。", "休論邊使千金費，絕勝爭城百戰功。", "古驛玻瓈晨煖酒，隆山狐貉暮排風。", "歸途剩記殊方事，付與麟臺逸史中。"]'),
('eb885df3-c049-421c-8e1d-2c2d9787b6fb','喜雪十韻','孔武仲','宋','宋诗','song-poetry','','[]','此夜不成雪，明朝應作霖。',120,'全唐诗/poet.song.50000.json','["此夜不成雪，明朝應作霖。", "細聲來户牖，爽氣入裯衾。", "窺隙疑相射，循簷覺更深。", "因風成倒陣，過竹有餘音。", "畫閣迷釵玉，旗亭付酒金。", "封漫碧澗曲，點綴假山岑。", "鶴氅行何麗，牛衣卧不任。", "漁罨平易失，樵逕浩難尋。", "却赴明光賀，潛追霢霂吟。", "天街立馬望，雙闕正球琳。"]'),
('850afac5-85e2-4b53-b398-c8398e61b2e5','答宋履中見贈','孔武仲','宋','宋诗','song-poetry','','[]','粉袍如雪會羣英，往歲曾當月旦評。',64,'全唐诗/poet.song.50000.json','["粉袍如雪會羣英，往歲曾當月旦評。", "夢想十年嗟舊事，翺翔三舍羨新榮。", "相如素擅爲文麗，班固終期作史成。", "潦倒詎堪君借重，篇詩今見古人情。"]'),
('63186464-f4c9-4d7f-8916-8054185abf50','元日值雪','孔武仲','宋','宋诗','song-poetry','','[]','東皇點綴一何工，飛下琪花頃刻中。',64,'全唐诗/poet.song.50000.json','["東皇點綴一何工，飛下琪花頃刻中。", "變盡樓臺成夜月，不容車馬競春風。", "崎嶇廣市黄泥汚，冷淡羣山彩日紅。", "野叟相逢應更喜，從來盈尺瑞年豐。"]'),
('c7e9162e-7937-4ab0-bb45-0dd372e39362','次韻李端叔見贈','孔武仲','宋','宋诗','song-poetry','','[]','君才瀟洒應時流，久滯寧非命壓頭。',64,'全唐诗/poet.song.50000.json','["君才瀟洒應時流，久滯寧非命壓頭。", "昨見河南推賈誼，行聞天子召吾丘。", "已無痛飲觀風味，猶有新詩講報投。", "京洛塵沙著人甚，清涼高爽憶宣州。"]'),
('5f9b40ae-2f26-4584-ba62-fce0d13758dc','留題無咎卧陶軒','孔武仲','宋','宋诗','song-poetry','','[]','南陌塵如霧，北窗清有餘。',48,'全唐诗/poet.song.50000.json','["南陌塵如霧，北窗清有餘。", "雖無彭澤柳，已富鄴侯書。", "晝永禽音緩，門閒馬跡疏。", "翛然即高枕，嘉興擬湓廬。"]'),
('10c8e10d-f980-4752-b3eb-bbfd2cc45c5f','直舍之西植竹兩叢經歲甚茂','孔武仲','宋','宋诗','song-poetry','','[]','去歲披雲自訪尋，交加緑玉已成林。',64,'全唐诗/poet.song.50000.json','["去歲披雲自訪尋，交加緑玉已成林。", "肯隨春圃羣芳老，喜對秋庭數畝陰。", "巴峽盧峰聲淅瀝，渭川斜谷氣蕭森。", "軒窗咫尺收佳趣，不負東南萬里心。"]'),
('2d844114-8966-48b6-9ff9-15f1d55cfe39','寄會稽丞趙振道','孔武仲','宋','宋诗','song-poetry','','[]','龜峰琬琰翠成堆，軒檻前當秀色開。',64,'全唐诗/poet.song.50000.json','["龜峰琬琰翠成堆，軒檻前當秀色開。", "此地登臨比圖畫，與君談笑繼樽罍。", "傳聞佳景無時乏，依舊清江不斷來。", "今日關河隔千里，相逢何處少徘徊。"]'),
('bec31f4a-868d-4a00-b3ad-648e40fd2c48','寄題程郎中家圓石','孔武仲','宋','宋诗','song-poetry','','[]','翦斸蒿萊得好峰，縈紆裝點思無窮。',64,'全唐诗/poet.song.50000.json','["翦斸蒿萊得好峰，縈紆裝點思無窮。", "尋幽已到神仙境，發秘渾争造化功。", "官序隠登臺閤上，夢思遙寄水雲中。", "扁舟我亦謀歸去，暫向巖前作醉翁。"]'),
('f0c174df-2152-461a-88f1-123780079c17','送高善時赴官','孔武仲','宋','宋诗','song-poetry','','[]','王國方登俊，清才尚折腰。',48,'全唐诗/poet.song.50000.json','["王國方登俊，清才尚折腰。", "萱堂餘愴在，瘴海此行遙。", "宴語無疏濶，離懷但黯銷。", "紅塵一羈旅，風馭羨飄飄。"]'),
('970ecdfb-599c-4a66-8141-2f2129137f28','次韻李端叔','孔武仲','宋','宋诗','song-poetry','','[]','此身萍梗厭漂流，慚寄潯陽江上頭。',64,'全唐诗/poet.song.50000.json','["此身萍梗厭漂流，慚寄潯陽江上頭。", "勝景長年闗夢寐，輕裘何日返林丘。", "扶搖莫作扶搖計，樸樕應容樸樕投。", "徙倚高樓情不極，恰如王粲在荆州。"]'),
('189c8a51-1fd5-473d-864c-60f49b7ed7ba','文德朝參退舉觴觥于幕下歸館中頽然醉卧官曹多暇未有如此因作四韻以識','孔武仲','宋','宋诗','song-poetry','','[]','朝罷千官卷舄行，袍衣猶带御前香。',64,'全唐诗/poet.song.50000.json','["朝罷千官卷舄行，袍衣猶带御前香。", "偶傾天上流霞美，便忘壺中白日長。", "叢竹娟娟簾繞碧，回風淅淅殿分涼。", "翛然不與人間事，未信無何别有鄉。"]'),
('236c236f-a516-4618-8e46-cfd4666f1059','休日出城西','孔武仲','宋','宋诗','song-poetry','','[]','秋懷不可奈，驅馬漕河邊。',48,'全唐诗/poet.song.50000.json','["秋懷不可奈，驅馬漕河邊。", "川躍時聞鯉，林嘶已斷蟬。", "勞心逐外物，回首是殘年。", "强作遨遊計，登臨却黯然。"]'),
('f96c9081-6eda-4adc-a755-bd0b8c6d1a83','聞袁思正卒于宿州','孔武仲','宋','宋诗','song-poetry','','[]','畫舸西河載酒回，東籬持菊待君來。',64,'全唐诗/poet.song.50000.json','["畫舸西河載酒回，東籬持菊待君來。", "何知頃刻成千古，不及従容共一盃。", "羈旅夢魂難際接，平生交分但悲哀。", "中年萬事長心惡，何處愁眉得暫開。"]'),
('fd28f230-022d-408c-a32e-91f4bff7cb70','偶書','孔武仲','宋','宋诗','song-poetry','','[]','夜枕唯便睡，晨窗不展書。',48,'全唐诗/poet.song.50000.json','["夜枕唯便睡，晨窗不展書。", "學文真漸懶，與世况全疏。", "老合耕山澗，恩容寄石渠。", "飡氊亦堪飽，不歎食無魚。"]'),
('8ef78d50-b15a-49a2-89ea-dda901b9fd01','夜直東觀','孔武仲','宋','宋诗','song-poetry','','[]','蕭散愛閒官，因循亦厚顔。',48,'全唐诗/poet.song.50000.json','["蕭散愛閒官，因循亦厚顔。", "聊休俗士駕，獨宿道家山。", "風幔自舒卷，月窗重閉闗。", "其如江海夢，已與雁飛還。"]'),
('61f366ce-cd3a-49d5-bb69-934393f0e92d','次韻宋履中兄弟九日詩','孔武仲','宋','宋诗','song-poetry','','[]','遙知把酒對重陽，簷外秋聲葉半黄。',64,'全唐诗/poet.song.50000.json','["遙知把酒對重陽，簷外秋聲葉半黄。", "落帽想當追故事，披襟仍喜得新涼。", "自憐僻處真匏繫，只羨清吟屬雁行。", "聞說家楹増壯麗，落成應許到華堂。"]'),
('b2f3e0f3-6c0d-48d7-a4b3-fab896fa39f8','送范中發知蘄州','孔武仲','宋','宋诗','song-poetry','','[]','漢南行樂不可復，殿中立班時會君。',64,'全唐诗/poet.song.50000.json','["漢南行樂不可復，殿中立班時會君。", "華省方看列宿貴，名州歘見左符分。", "飄蓬聚散古難必，塞馬去來烏足云。", "出處行藏君素達，吟情聊對祖山雲。"]'),
('de0c6782-530d-4ef5-b7b2-bc2f49460e55','寄題徐季叔桂香亭','孔武仲','宋','宋诗','song-poetry','','[]','淮縣築居好，桂亭牽興長。',48,'全唐诗/poet.song.50000.json','["淮縣築居好，桂亭牽興長。", "偶分巖下影，别有月中香。", "瀟洒欺松竹，嚴凝耐雪霜。", "従君酌樽酒，歲晚玩幽芳。"]'),
('1d5dc2b5-8a34-4887-b854-9ef6b6c52e7c','十月朔過殿','孔武仲','宋','宋诗','song-poetry','','[]','平曉清風響北林，大明宫殿肅陰陰。',64,'全唐诗/poet.song.50000.json','["平曉清風響北林，大明宫殿肅陰陰。", "雕輿來息雲天上，黼座遙瞻斗極深。", "庭廣袍衣自相照，朝回幡蓋尚餘音。", "太平文物多師古，想望漢唐猶視今。"]'),
('73c27b38-2186-4129-b954-2d2557f16695','十二月十二日後殿朝參','孔武仲','宋','宋诗','song-poetry','','[]','廣殿泬寥邊，鳴靴趁靜鞭。',48,'全唐诗/poet.song.50000.json','["廣殿泬寥邊，鳴靴趁靜鞭。", "中霄黄道直，諸御錦袍鮮。", "夜雨塵如洗，秋槐影尚圓。", "銀臺不奏事，人樂太平年。"]'),
('9678f1f3-9ac5-406b-8d66-bb816a742d57','十二月十六日後殿朝謁','孔武仲','宋','宋诗','song-poetry','','[]','晨光先到帝王州，别殿珠簾不上鈎。',64,'全唐诗/poet.song.50000.json','["晨光先到帝王州，别殿珠簾不上鈎。", "萬歲聲齊山獻壽，九門朝退海分流。", "參差雉尾回丹陛，杳遠雞聲下禁樓。", "年少曾來奏詞賦，鈞天却記夢中遊。"]'),
('c547a254-3b6c-445f-b895-2df7de34463d','苦寒','孔武仲','宋','宋诗','song-poetry','','[]','晨風獵獵卷書堂，坐愛松筠耐雪霜。',64,'全唐诗/poet.song.50000.json','["晨風獵獵卷書堂，坐愛松筠耐雪霜。", "歲律峥嶸催暮景，時光宛轉逼新陽。", "金巵滿引顔雖解，石火深籠焰不長。", "安得仙家却寒術，吸吞霞氣赤城傍。"]'),
('0e484462-9cd5-4b0b-b8b3-30ec1ac86427','武仲伏蒙寵寄新篇不忘往事恩誼甚厚謹依嚴韻和酬伏惟台慈特賜采覽','孔武仲','宋','宋诗','song-poetry','','[]','治才優似尹京年，餘思吟哦入彩牋。',64,'全唐诗/poet.song.50000.json','["治才優似尹京年，餘思吟哦入彩牋。", "元帥子孫真將種，翰林風格自天仙。", "追隨盡臘無留刻，揮染香煤有剩妍。", "盡是從容雅歌事，銘功何苦勒燕然。"]'),
('463edaa5-a28f-4d56-b610-896f04ae8bcc','壬申仲秋與東觀曝書之會謹賦五言四韻律詩一首','孔武仲','宋','宋诗','song-poetry','','[]','秋風解煩暑，尊俎可從容。',48,'全唐诗/poet.song.50000.json','["秋風解煩暑，尊俎可從容。", "盡會青雲士，來遊羣玉峰。", "琅函窺一一，金鑰發重重。", "四庫傳觀喜，惟應吏困供。"]'),
('c6d61683-4cff-4672-b8fa-cdeb488a173c','武仲伏蒙知府待制寵示新詩課成短篇以獻左右','孔武仲','宋','宋诗','song-poetry','','[]','侍從榮依日月光，更因盤錯試鋒鋩。',64,'全唐诗/poet.song.50000.json','["侍從榮依日月光，更因盤錯試鋒鋩。", "諫書不上時無事，訟缿無留日倍長。", "舊好葭莩容間見，新篇錦繡得家藏。", "自慚思涸無高韻，蒿管何因擬鳳凰。"]'),
('2079ea16-a2f0-4e88-8435-7e2fbe633ac1','寄子由','孔武仲','宋','宋诗','song-poetry','','[]','江上怱怱别，孤舟誰與言。',48,'全唐诗/poet.song.50000.json','["江上怱怱别，孤舟誰與言。", "塵今生我甑，盜肯過君門。", "水石吳山好，風嵐楚澤昏。", "相望欲命駕，何日爲東轅。"]'),
('59e0c21d-010b-4a4a-b8e7-9852fde934cb','極目亭有作','孔武仲','宋','宋诗','song-poetry','','[]','浩蕩江風動客襟，短亭清晚一登臨。',64,'全唐诗/poet.song.50000.json','["浩蕩江風動客襟，短亭清晚一登臨。", "亂霞藏日半天纈，渌水浸空千頃金。", "壯志未成游學恨，素交將散别離心。", "前山更有難尋景，試爲閒來一苦吟。"]'),
('85bc1dc7-b1e1-4124-a5bc-f6905760e0d4','次韻介之','孔武仲','宋','宋诗','song-poetry','','[]','亭上掀簾試解襟，遠山崷崒勢前臨。',64,'全唐诗/poet.song.50000.json','["亭上掀簾試解襟，遠山崷崒勢前臨。", "前灘濺沫鏘鳴玉，落照蒸霞映翠金。", "運筆欲回天地力，高談直造聖賢心。", "於中覽景宜誰預，願結夫君此笑吟。"]'),
('c8843560-1a11-438c-ba40-3920f525dc22','江上晚行寄介之','孔武仲','宋','宋诗','song-poetry','','[]','廉纖一雨適春閒，擊劍悲歌氣滿顔。',64,'全唐诗/poet.song.50000.json','["廉纖一雨適春閒，擊劍悲歌氣滿顔。", "消破古今惟日月，補完風雅只江山。", "我因爲旅成拘滯，君此安居得往還。", "一夕竹窗燈燭照，論文談易兩俱閒。"]'),
('a5940bff-598e-4014-be14-00cd8ef5faa3','早春','孔武仲','宋','宋诗','song-poetry','','[]','密雨霏霏欲結霖，洒開青帝發生心。',64,'全唐诗/poet.song.50000.json','["密雨霏霏欲結霖，洒開青帝發生心。", "風吹嫩草迸微緑，雷碾長空破積陰。", "啼鳥隨陽聲自得，卧龍思海意尤深。", "更看三月桃花浪，舊鬛凌雲在尺尋。"]'),
('c747e33a-0007-4472-bae4-44c27a8f6fbd','介之會徐氏家飲薄暮不歸爲詩招之','孔武仲','宋','宋诗','song-poetry','','[]','金鞍駿馬照朱門，樂會高張晉楚軍。',64,'全唐诗/poet.song.50000.json','["金鞍駿馬照朱門，樂會高張晉楚軍。", "狂客浩歌翻白雪，艷姬醉舞轉紅裙。", "花光灼爍筵前錦，酒韻氤氳盞上雲。", "爭似竹窗風月夜，青燈殘茗細論文。"]'),
('63bcb759-300c-4c86-b60f-b693fb5beec8','次韻酬昌俠見貺之句','孔武仲','宋','宋诗','song-poetry','','[]','讀君詩句骨毛寒，直恐吟來得意難。',64,'全唐诗/poet.song.50000.json','["讀君詩句骨毛寒，直恐吟來得意難。", "劃若震雷驚蟄户，爛如奎宿照雲端。", "鋒鋩剸截崑山玉，意氣騰凌大海瀾。", "欲識詞源最清處，露珠新滴水精盤。"]'),
('80ff76e9-9671-4f9b-97c2-670d4cd4fdfe','偶成','孔武仲','宋','宋诗','song-poetry','','[]','翦斷長翎入網羅，十年光景怨蹉跎。',64,'全唐诗/poet.song.50000.json','["翦斷長翎入網羅，十年光景怨蹉跎。", "欲提長劍爲游說，且卧空山學揣摩。", "砧杵夜寒醒醉夢，風霜秋緊役詩魔。", "不須計較當時事，黄卷書中寵辱多。"]'),
('3572f0f4-67bf-40cd-80f2-0b25dae1f635','秋日感懷','孔武仲','宋','宋诗','song-poetry','','[]','萬山松色鎖蟬鳴，日透林陰上下清。',64,'全唐诗/poet.song.50000.json','["萬山松色鎖蟬鳴，日透林陰上下清。", "霜壓蒹葭連地白，風吹河漢滿天聲。", "穹廬夜動陰山虜，玉甲朝屯紫塞兵。", "願漱單于一杯血，心隨鵰鶚過長城。"]'),
('e2c06fb5-0062-4616-8e03-627faa710c99','贈子通','孔武仲','宋','宋诗','song-poetry','','[]','金石論交古所希，朱顔相結少年時。',64,'全唐诗/poet.song.50000.json','["金石論交古所希，朱顔相結少年時。", "自嗟齷齪逢人少，尤喜軒昻出衆奇。", "文字往來諧律吕，笑談錯雜和塤篪。", "近聞俗語多讒間，願子高歌錦與箕。"]'),
('0de8a2be-749a-4b18-9e78-9bedc50e9422','和介之登樓見寄','孔武仲','宋','宋诗','song-poetry','','[]','俯瞰江城十萬家，舊居却歎久荒遐。',64,'全唐诗/poet.song.50000.json','["俯瞰江城十萬家，舊居却歎久荒遐。", "秋空雲片歸飛鶴，古木藤陰屈結虵。", "卧愛灘聲長在耳，望窮山色接無涯。", "憑君命句天然景，流落人間與衆誇。"]'),
('a4613502-8187-415a-96d1-ede277de3a9e','題介之小閣','孔武仲','宋','宋诗','song-poetry','','[]','畫簾初卷碧山低，面面青藍翠拂衣。',64,'全唐诗/poet.song.50000.json','["畫簾初卷碧山低，面面青藍翠拂衣。", "秋水暮天長一色，渚鷗沙雁或雙飛。", "煙霞逗眼光相亂，松竹敲風韻更微。", "却笑屈原顦顇甚，漁歌何苦淚交揮。"]'),
('cd97b43d-80da-4d36-9cbb-15fac19f0770','江上','孔武仲','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','萬里長江一葉舟，客心蕭索已驚秋。',64,'全唐诗/poet.song.50000.json','["萬里長江一葉舟，客心蕭索已驚秋。", "亂霞影照山根寺，落日光翻水面樓。", "淺浦耀金知躍鯉，前灘點雪見棲鷗。", "少年壯氣悲寥廓，未忍滄江下釣鈎。"]'),
('52f31168-1b36-42ab-b9fb-33a12bee0c49','夜歸口占示同行者','孔武仲','宋','宋诗','song-poetry','','[]','一天星月明如晝，萬樹杉篁吟戛秋。',64,'全唐诗/poet.song.50000.json','["一天星月明如晝，萬樹杉篁吟戛秋。", "隠約棹歌聞别浦，青熒漁火見孤舟。", "身居簡册三冬學，心入滄溟萬里游。", "髣髴重陽正明日，與君攜酒豫登樓。"]'),
('4eec0e5f-35c7-4107-80e5-4c1f66227c6a','秋夕感懷','孔武仲','宋','宋诗','song-poetry','','[]','秋空雨過一掀簾，萬象森森夜氣嚴。',64,'全唐诗/poet.song.50000.json','["秋空雨過一掀簾，萬象森森夜氣嚴。", "皓露滴人珠滿袖，金風吹月鑑開奩。", "荒階蟋蟀動相感，大海虬龍方退潛。", "物理窮通何足歎，試開閶闔問洪纖。"]'),
('7d003907-c483-4f7a-b9d4-765a5b6ed11d','寄聶正甫','孔武仲','宋','宋诗','song-poetry','','[]','虎髯兩頰狀貌古，開口論議辭非今。',64,'全唐诗/poet.song.50000.json','["虎髯兩頰狀貌古，開口論議辭非今。", "尚藏折劍萬丈氣，空馳老驥千里心。", "六印他年新將相，一瓢今日舊山林。", "黄雲斷天望不極，想君何處方悲吟。"]'),
('2e3555c7-d1f6-42be-a09e-a1cbf9d698f0','送周正儒知梓州','孔武仲','宋','宋诗','song-poetry','','[]','東蜀國巨屏，梓州天一方。',48,'全唐诗/poet.song.50000.json','["東蜀國巨屏，梓州天一方。", "浯川點城郭，劍閣護池隍。", "鎮撫須賢守，吁俞輟省郎。", "不應嗟遠别，垂組正誇鄉。"]'),
('eece52d2-7983-4130-b27a-924cb1b5664c','溽暑','孔武仲','宋','宋诗','song-poetry','','[]','頑雲積穹蒼，天宇晝沉黄。',132,'全唐诗/poet.song.50000.json','["頑雲積穹蒼，天宇晝沉黄。", "日車亦徘徊，風力軟不揚。", "亭午猶蒸溽，汗瀉如沃漿。", "裋褐無所投，返坐閉深房。", "外觀俱遣絕，欲以進清涼。", "煩襟竟不解，號呼投空床。", "安得引扶搖，大鵬共翱翔。", "拔石移三山，回波沃扶桑。", "炎官喪精魄，火蛾潛遁藏。", "披襟閶闔畔，爽氣盈衣裳。", "誰能守環堵，執熱徒自傷。"]'),
('5b39c7f0-3c52-483b-b250-239aad083c8f','大熱息於官亭','孔武仲','宋','宋诗','song-poetry','','[]','大暑投官亭，堂皇已頽折。',129,'全唐诗/poet.song.50000.json','["大暑投官亭，堂皇已頽折。", "盤桓倚門戶，坐以一筦席。", "昊天多清風，至此何慳惜。", "及我無分寸，揮汗已盈尺。", "較之渴仆長途間，猶賴此中容少息。", "嗟我不如亭前馬，穩嚼青芻柳陰下。", "又不如東家養畫眉，雕籠彩畫近簾帷。", "一身擾擾南復北，凌寒涉暑常奔馳。", "寒猶幸可沃以酒，暑真可畏非良時。"]'),
('db5351d7-58dc-4fe2-886c-50c9df80ac63','水上清風覆以喬木','孔武仲','宋','宋诗','song-poetry','','[]','喬木張帷幄，小溪環珮聲。',156,'全唐诗/poet.song.50000.json','["喬木張帷幄，小溪環珮聲。", "清風復颯然，三者固難幷。", "而我兼得之，世俗亦不爭。", "逍遙萬慮廢，俯仰一身輕。", "豁若發醯雞，悟然虛白生。", "萬里涉山川，三伏值炎蒸。", "赤日正流天，籃輿須駐行。", "波明金沙露，渡仄畫舫橫。", "上飄以淅淅，下濺以泠泠。", "中有翠影浮，蓊蔚如畫屏。", "頃刻諧我意，翛然已忘形。", "濯足臨潺湲，披襟望青冥。", "山中真可樂，世路空營營。"]'),
('db6500f3-47ac-47ed-89f6-29dafc55fc5a','白公草堂','孔武仲','宋','宋诗','song-poetry','','[]','朝貴偶謫宦，郡侯真好賢。',72,'全唐诗/poet.song.50000.json','["朝貴偶謫宦，郡侯真好賢。", "吏事不到門，身與白雲閑。", "堂下有流水，堂前俱青山。", "時攜孟光來，冷語夕陽間。", "登覽興已盡，浩然亦俱還。", "頗笑沉湘人，戚戚多愁顔。"]'),
('2bb712da-2347-4b14-bd74-a87dd79896ef','三峽橋','孔武仲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山到此深，面面皆疊嶂。',192,'全唐诗/poet.song.50000.json','["廬山到此深，面面皆疊嶂。", "安知九江濱，自有三峽壯。", "層崖合飛流，深谷呀百丈。", "頗聞開闢初，融結固異狀。", "帝遣六天丁，開鑿就空曠。", "劃爲雙門關，拔作兩城障。", "喬林疊帷幄，怪石蹲犀象。", "高泉落其間，快若翻甕盎。", "雷動正轟磕，龍吟更悽愴。", "縈流十里間，餘怒猶奔放。", "詩人細評品，價出瀑布上。", "山祇苦悶蓄，可探不可望。", "我來搜奇古，秋色正明亮。", "初觀雖震慴，少定亦恬蕩。", "復值朝日升，光景相蕩漾。", "如倚明月宮，俯看銀河浪。"]'),
('ad6daab9-0563-4b32-8dbe-642d682d00bc','嘉魚遇順風','孔武仲','宋','宋诗','song-poetry','','[]','晚雨落雖收，夜風鳴未已。',168,'全唐诗/poet.song.50000.json','["晚雨落雖收，夜風鳴未已。", "輕寒破秋夢，亦逐征人起。", "闖篷問篙師，開帆已數里。", "喧喧波拍岸，漠漠雲覆水。", "濺點如珠翻，湧瀾若山峙。", "白鳥亦回翔，江豚相助喜。", "餘聲更澎汃，掀兀席與几。", "孤舟沒復出，輕捷如可恃。", "我生遊四方，大半江湖裏。", "吳會弔胥臣，瀟湘尋帝子。", "詠歌懷曩昔，往往成詩史。", "此行又壯觀，快欲插翼比。", "雄豪愛宗慤，瀟散追范蠡。", "搥鼓佐傾觴，呼兒斫金鯉。"]'),
('fd08bda5-8c4e-4517-9e67-a40e902ae417','晚步西園','孔武仲','宋','宋诗','song-poetry','','[]','今日曷不樂，吾園來頗疏。',84,'全唐诗/poet.song.50000.json','["今日曷不樂，吾園來頗疏。", "向晚門庭空，杖策到城隅。", "林噪其飛禽，池躍其遊魚。", "似怪我來遲，晨朝何往乎。", "寂默不應答，暫一爾輩俱。", "唼波窺噞喁，集灌聽相呼。", "復倚逍遙亭，悠然觀太虛。"]'),
('8ef94192-f905-416e-be9a-798a256d7057','奉酬李時發岳麓見寄','孔武仲','宋','宋诗','song-poetry','','[]','秋風入荒城，落葉如飛雨。',288,'全唐诗/poet.song.50000.json','["秋風入荒城，落葉如飛雨。", "夢寐湘西遊，晻曖不可睹。", "昨日得君詩，諷詠日欹午。", "山光相隨來，瀟灑入庭戶。", "憶昨尋此山，扁舟戛平浦。", "白鷗爲前軀，丹霞隨步武。", "漸入空曠中，輕清欲飛舉。", "幽泉落石鳴，喬杉得風舞。", "峰巒半明滅，雲月相吞吐。", "巖巖仙佛家，殿塔羅翠塢。", "半壁聞棋聲，深林傳鳥語。", "清境造已極，更上最高處。", "朱欄插青冥，華屋橫險阻。", "雲夢吞八九，天衢量尺五。", "卻視長沙城，迫仄真環堵。", "淥水带縈洄，青煙絲一縷。", "平時事干謁，白晝走塵土。", "到此覺沉迷，直欲棄簪組。", "尚愧節不高，空然賦歸去。", "朅來巖邑居，擾擾變寒暑。", "回旋盡朱墨，應接煩箠楚。", "何嘗略尋幽，曾不暇窺圃。", "引望西絕堂，曠若隔今古。", "夫君今俊秀，爽氣發眉宇。"]'),
('716a7631-21dd-4a3a-8fd1-8b109f3e9e2d','句  其一','孔武仲','宋','宋诗','song-poetry','','[]','煎點徑須煩綠珠。',8,'全唐诗/poet.song.50000.json','["煎點徑須煩綠珠。"]'),
('8831a921-233e-4317-aa7f-83087e83e0ef','句  其二','孔武仲','宋','宋诗','song-poetry','','[]','黄公山下官悰冷，應有新吟續七哀。',16,'全唐诗/poet.song.50000.json','["黄公山下官悰冷，應有新吟續七哀。"]'),
('3637f8a0-312b-44b7-931d-ba2460a9bd40','樂通神明','范祖禹','宋','宋诗','song-poetry','','[]','世治興和樂，陽來符正聲。',72,'全唐诗/poet.song.50000.json','["世治興和樂，陽來符正聲。", "純能格天地，幽可逮神明。", "協氣流無外，靈心識太平。", "九歌人鬼享，八變地祇迎。", "翕縱多祥集，欣歡萬祉生。", "須知勲德大，聖作掩英莖。"]'),
('2e8ca1da-8653-49c7-9b3c-9fa042d3b91d','春鮪初登','范祖禹','宋','宋诗','song-poetry','','[]','風煦陽和候，冰消水澤春。',72,'全唐诗/poet.song.50000.json','["風煦陽和候，冰消水澤春。", "乘舟施密罟，豋鮪薦明神。", "大壑翻紅鬛，長波失錦鱗。", "味參籩實美，羞與澗毛新。", "事異觀棠日，時非濫泗辰。", "猗歟潛有頌，率職自人。"]'),
('6378f5b2-9465-43d9-bd73-8ee244be53c1','游先主祠堂置酒','范祖禹','宋','宋诗','song-poetry','','[]','驅車出郊坰，涉谿上青岑。',204,'全唐诗/poet.song.50000.json','["驅車出郊坰，涉谿上青岑。", "峰頭野寺不足到，先主祠堂猶可尋。", "祠堂之前流水長，翠屏重疊揺清光。", "老松窈窕入雲漢，五月鬱鬱炎天凉。", "廟中女巫日歌舞，神去神來何處所。", "龍吟虎嘯生風雲，未似當時臣遇主。", "三分割據霸業開，山河氣象皆西來。", "功名烜赫陵宇宙，顧盼可使彊敵摧。", "西南歴數俄遷改，岷峨霸氣今何在。", "萬里浮雲卷壯圗，空餘江水東流海。", "山風吹月海上来，松間雲氣嘘酒盃。", "高歌且醉一杯酒，昔日英雄安在哉。", "此時分散已陳迹，何足慘愴令心哀。"]'),
('7562fe4d-e73d-466d-8024-a319675cf92c','四皓','范祖禹','宋','宋诗','song-poetry','','[]','南山石壁陵蒼蒼，中有四老眉如霜。',112,'全唐诗/poet.song.50000.json','["南山石壁陵蒼蒼，中有四老眉如霜。", "中原龍虎困格鬭，九霄鸞鳯高飄翔。", "赤精斬蛇入咸陽，南極老人轉遁藏。", "一朝相顧下雲巘，共爲羽翼安儲皇。", "白雲黄鵠高飛揚，雖有矰繳安能傷。", "君王慷慨但飲酒，戚姫起舞無輝光。", "古人不見雖已遠，吾将杖策登崇岡。"]'),
('6e1ff3c4-2529-4045-9d83-d36ae20c4c01','席上探題二首  其一','范祖禹','宋','宋诗','song-poetry','','[]','紅蕉花誰植，風流太守家。',28,'全唐诗/poet.song.50000.json','["紅蕉花誰植，風流太守家。", "爍爍犀燈燃晚雨，亭亭蜜炬照晴霞。"]'),
('f06161b2-7cf2-42f5-a418-dc8b3f9e1cd3','席上探題二首  其二','范祖禹','宋','宋诗','song-poetry','','[]','秋夜雨點滴，梧桐亂人語。',28,'全唐诗/poet.song.50000.json','["秋夜雨點滴，梧桐亂人語。", "幾行寒雁起沙汀，萬里漁舟泊煙渚。"]'),
('88b61bdc-595c-4fcc-ac28-2f2af629f681','資水','范祖禹','宋','宋诗','song-poetry','','[]','資水通巫峽，誰家萬里船。',48,'全唐诗/poet.song.50000.json','["資水通巫峽，誰家萬里船。", "隨雲排楚氣，隠几上吳天。", "神女迷朝雨，湘娥泣暮煙。", "何時一飛檝，長嘯下牢邊。"]'),
('44140fe9-cf3f-4d2c-a7ad-7983e02abfa5','資中八首  其一','范祖禹','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','劍閣横空鏁蜀門，資中巖岫若雲屯。',32,'全唐诗/poet.song.50000.json','["劍閣横空鏁蜀門，資中巖岫若雲屯。", "天傾白日千山砥，峽束長江萬里奔。"]'),
('d786d4f2-a6ac-478c-90ec-401849473bbc','資中八首  其二','范祖禹','宋','宋诗','song-poetry','','[]','資山巖谷多神仙，鸞車鳳馬隨飛煙。',32,'全唐诗/poet.song.50000.json','["資山巖谷多神仙，鸞車鳳馬隨飛煙。", "神女蕭蕭來暮雨，浮丘往往下雲軿。"]'),
('78a42497-30be-4ca4-a2ed-1aa1091e6390','資中八首  其三','范祖禹','宋','宋诗','song-poetry','','[]','醮壇高倚碧天開，中有清都白玉臺。',32,'全唐诗/poet.song.50000.json','["醮壇高倚碧天開，中有清都白玉臺。", "霧擁霓旌乘月去，風吹仙樂下天來。"]'),
('10e2e613-98ea-40ee-aea5-3cd90c5fcf71','資中八首  其四','范祖禹','宋','宋诗','song-poetry','','[]','五月江流萬賈船，迅如飛電擘羣山。',32,'全唐诗/poet.song.50000.json','["五月江流萬賈船，迅如飛電擘羣山。", "荆雲峽雨須臾過，白帝江陵朝暮間。"]'),
('464d413a-9345-45b8-acf6-85fa0f94591d','資中八首  其五','范祖禹','宋','宋诗','song-poetry','','[]','六月炎蒸烈火高，黑雲驅雨駕波濤。',32,'全唐诗/poet.song.50000.json','["六月炎蒸烈火高，黑雲驅雨駕波濤。", "千崖雪浪飛泉吼，萬壑陰雲古木號。"]'),
('61bf0a2b-e449-4551-b527-b5473f12ae13','資中八首  其六','范祖禹','宋','宋诗','song-poetry','','[]','風定江澄境象閒，水清波影倒雲山。',32,'全唐诗/poet.song.50000.json','["風定江澄境象閒，水清波影倒雲山。", "漁舟蕩漾清光裏，白鷺驚飛杳靄間。"]'),
('0fb2ff4b-b8a7-459a-892d-800047a96cae','資中八首  其七','范祖禹','宋','宋诗','song-poetry','','[]','夷界荒山幾萬重，西窮月窟與天通。',32,'全唐诗/poet.song.50000.json','["夷界荒山幾萬重，西窮月窟與天通。", "何時漢使還持節，從此乘槎上碧空。"]'),
('1b297b3a-12d2-43ed-86e6-47e76465ce59','資中八首  其八','范祖禹','宋','宋诗','song-poetry','','[]','武侯祠廟徧空山，萬古名垂宇宙間。',32,'全唐诗/poet.song.50000.json','["武侯祠廟徧空山，萬古名垂宇宙間。", "昔日南人皆稽首，至今歌舞聚夷蠻。"]'),
('49f69e04-cc1a-45eb-b8dc-9eb2268a725d','資州路月山亭','范祖禹','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','軒亭枕蒼峰，縹緲視空濶。',120,'全唐诗/poet.song.50000.json','["軒亭枕蒼峰，縹緲視空濶。", "長江飜天去，迴斡地軸折。", "洪濤破山門，崖谷盡争裂。", "孤雲行無蹤，飛鳥去自没。", "游子怨路長，煩襟此披豁。", "昔觀黄河流，浩蕩窺禹穴。", "乾坤何壯觀，永歎舊遊絕。", "兹亭雖非匹，山水頗秀發。", "茫茫八紘內，所歴但毫末。", "安得乘飛颷，人寰恣超越。"]'),
('d4c14509-72c1-44dd-9c1f-8701abdab1d7','資州路東津寺','范祖禹','宋','宋诗','song-poetry','','[]','山行無晨暮，日暝崖谷昏。',144,'全唐诗/poet.song.50000.json','["山行無晨暮，日暝崖谷昏。", "哀猿落客淚，永路驚旅魂。", "憑陵高山巔，俯視大江奔。", "迥環島嶼合，縈轉洲渚屯。", "行雲赴楚天，飛鳥下蜀門。", "地遐怪物聚，寺古深殿存。", "憶昔李氏末，煙塵暗中原。", "姦雄競草竊，割據窮海根。", "干戈百年後，見此敗屋垣。", "我來屬清秋，登覽無俗喧。", "山深虎豹歸，水静蛟鼉騫。", "臨風獨笑吒，浩蕩欲飛飜。"]'),
('57bedbad-1970-46a3-a27f-f91d472456da','月夜船行入資州','范祖禹','宋','宋诗','song-poetry','','[]','憶昨卧碧山，蒼蒼叢桂間。',92,'全唐诗/poet.song.50000.json','["憶昨卧碧山，蒼蒼叢桂間。", "白雲爲屏石爲枕，緑蘿長掛明月閒。", "忽乘輕舟泛江水，山月隨人還在此。", "白鷺驚飛宿靄間，青山倒卧滄波砥。", "此時孤棹發中流，川后停波聽棹謳。", "不學子猷中夜返，欲乘眀月向資州。"]'),
('c48925d4-a283-4c9b-970d-9a2e4c30728c','七月五日熱退喜凉資中有懷二十四韻','范祖禹','宋','宋诗','song-poetry','','[]','仲夏金火争，陰陽勢相奪。',288,'全唐诗/poet.song.50000.json','["仲夏金火争，陰陽勢相奪。", "乾坤鼓洪鑪，夸父死奔渴。", "普天無纎雲，厚土萬丈裂。", "亭亭太陽午，安得日車跌。", "清冷想寒門，浩蕩思舞雪。", "嘆彼老農耕，有苖不得活。", "乞雨禱潭龍，望雲驅旱魃。", "帝車俄廻指，四序苦飄忽。", "木落天地秋，清霜洗空濶。", "凉風破閶闔，勢欲捲溟渤。", "衆鳥盡不飛，峥嶸見孤鶻。", "登臨滌魂神，颯爽動毛骨。", "因懷京洛間，車馬填城闕。", "紅塵暗天宇，愚智共汩沒。", "出門無所適，肝肺爲枯竭。", "平生喜林泉，瀟灑愛風月。", "滄浪有漁父，逸步脱羈紲。", "超然思遠遊，萬古訪遺轍。", "安能公侯間，俯僂事干謁。", "及来山水縣，素志得少豁。", "白石拂雲眠，芳蓀乘露擷。", "尋山喜幽勝，照水翫澄澈。", "雖無巢許操，夙慕夷齊潔。", "庶以保吾真，無爲事其末。"]'),
('08788f3d-c4d5-4025-9a82-b73cf77b13ed','文潞公生日','范祖禹','宋','宋诗','song-poetry','','[]','天監仁皇德，惟時嶽降神。',240,'全唐诗/poet.song.50000.json','["天監仁皇德，惟時嶽降神。", "英姿備文武，賢業富經綸。", "夢賚求巖野，于畋載渭濵。", "三朝瞻上宰，四海入洪鈞。", "謨烈重光啓，樞衡萬化新。", "珪璋扶日月，劍履上星辰。", "述職分東陜，宣威震北垠。", "長城萬里遠，奠枕四夷賓。", "自昔登儲后，惟公秉國均。", "川河賴舟檝，霜雪見松筠。", "閶闔朝黄道，雲龍對紫宸。", "忠勲藏廟祏，異禮冠臣鄰。", "風雨王城會，煙花洛苑春。", "麾幢近泉石，袞繡出埃塵。", "照社祥光盛，充閭慶旦臻。", "御鑪熏黼黻，天廐輟騏驎。", "帝念深元老，邦基屬柄臣。", "公雖慕前哲，天欲覺斯民。", "左右蕭何手，安危晉國身。", "濟時歸壽域，遐筭等靈椿。"]'),
('ed2757af-e124-4849-81b0-e5402e4707ab','送趙清憲入蜀','范祖禹','宋','宋诗','song-poetry','','[]','上聖隆西眷，中朝報鉅賢。',192,'全唐诗/poet.song.50000.json','["上聖隆西眷，中朝報鉅賢。", "三刀重夢寐，四國賴蕃宣。", "自昔方隅遠，惟公惠澤偏。", "絃歌初撫字，使節再聨翩。", "召父深仁浹，文翁美化全。", "南圗廻海浪，北極上星躔。", "霖雨蘇羣物，卿雲被八埏。", "從容方論道，引避不居權。", "忠馭何頻叱，行帷义一褰。", "漏天開霧雨，燒棧掃雲煙。", "玉壘山横雪，羅江水映緜。", "閭閻瞻冕服，父老識旌旃。", "清静嘗能理，煩苛冀盡蠲。", "銷兵無吠警，含哺但安眠。", "富庶寧加此，功名固有焉。", "豈惟私蜀土，佇更秉陶甄。"]'),
('cd484811-9994-4062-a0f6-d5d0791aa937','送聖徒入京兼呈紀常子進','范祖禹','宋','宋诗','song-poetry','','[]','二年隔京洛，思見亦已久。',168,'全唐诗/poet.song.50000.json','["二年隔京洛，思見亦已久。", "驪駒将戒行，姑共一杯酒。", "君来買園林，山川既富有。", "顧我猶旅人，安排卧林藪。", "不意嵩嶺雲，輸君先入手。", "謀生已知拙，高遁慚居後。", "貴富等浮雲，名聲似箕斗。", "終當結茅屋，鄰舍聞雞狗。", "杖屨作往還，過從惟野叟。", "愛君修竹間，一水似崖口。", "掃除石上月，寒檜揺青箒。", "早賦歸去来，無爲事奔走。", "前期知非遠，同集待諸友。", "寄我思洛詩，東風想回首。"]'),
('b7737d4c-a9d5-4d91-95e7-421f3c36ba3f','大雪入洛陽','范祖禹','宋','宋诗','song-poetry','','[]','昨夜關山雪，僕夫晨起驚。',120,'全唐诗/poet.song.50000.json','["昨夜關山雪，僕夫晨起驚。", "揮鞭騎紫馬，曉入洛陽城。", "川原渺茫茫，長嘯視八紘。", "有如乘風馭，迢逓奔玉京。", "伊水象天河，雲濤向東傾。", "喧然古都市，沽酒吹玉笙。", "予心正浩蕩，萬里赴歸程。", "遥望嵩峰頂，連天凍峥嶸。", "欲攀玉女窗，舉手摩太清。", "思之不可去，悵望空含情。"]'),
('7e816183-08ee-43ad-b9a8-c77b796256d5','寄名山李著作','范祖禹','宋','宋诗','song-poetry','','[]','劍外雖云遠，名山信日聞。',48,'全唐诗/poet.song.50000.json','["劍外雖云遠，名山信日聞。", "漏天常洩雨，蒙頂半藏雲。", "萬里飛鳬舄，三年隠豹文。", "茗芽春後好，應許故人分。"]'),
('47cfd6a8-6783-4d1c-aea9-4ccd4ce181bc','砥柱四首  其一','范祖禹','宋','宋诗','song-poetry','','[]','黄河傾落九天来，砥柱三山立欲摧。',32,'全唐诗/poet.song.50000.json','["黄河傾落九天来，砥柱三山立欲摧。", "崖谷吐吞成霧雨，蛟龍戰鬬作風雷。"]'),
('ad58a04e-32b3-4345-8e3a-37e919b51922','砥柱四首  其二','范祖禹','宋','宋诗','song-poetry','','[]','巨靈贔屭兩山開，東放黄河萬里來。',32,'全唐诗/poet.song.50000.json','["巨靈贔屭兩山開，東放黄河萬里來。", "地軸横斜争斡轉，天維欹側恐傾摧。"]'),
('baccdb9f-c217-4a73-8a1e-59a95e516fc2','砥柱四首  其三','范祖禹','宋','宋诗','song-poetry','','[]','禹開砥柱放河奔，濁浪軒軒日月昏。',32,'全唐诗/poet.song.50000.json','["禹開砥柱放河奔，濁浪軒軒日月昏。", "唯有三門君不見，驚波一起動乾坤。"]'),
('f52a0120-1581-4ed9-bd23-14c20c2c1cdd','砥柱四首  其四','范祖禹','宋','宋诗','song-poetry','','[]','砥柱初開禹力窮，黄河從此去朝宗。',32,'全唐诗/poet.song.50000.json','["砥柱初開禹力窮，黄河從此去朝宗。", "長鯨一噴連山起，岌嶪高於太華峰。"]'),
('c0e861e1-377b-41a1-8fcf-c5f01e6edd0c','望嶽','范祖禹','宋','宋诗','song-poetry','','[]','客行西入函關道，秀氣東来滿關好。',96,'全唐诗/poet.song.50000.json','["客行西入函關道，秀氣東来滿關好。", "北顧黄河天際流，回望荆山欲傾倒。", "前瞻太華三峰高，中天屹立争雄豪。", "羣山朝嶽皆西走，勢似長風驅海濤。", "金天殺氣何蕭爽，羽駕颷輪應可往。", "安得雲梯倚碧空，上拂煙霞看仙掌。"]'),
('7ba2cae5-399d-4a20-bd04-e59e4c0afb55','希夷陳先生祠堂','范祖禹','宋','宋诗','song-poetry','','[]','太華朝紫清，蓮花開緑烟。',132,'全唐诗/poet.song.50000.json','["太華朝紫清，蓮花開緑烟。", "嘗聞希夷隱，欲學南華仙。", "道與寥廓友，形隨變化遷。", "餐霞倚八極，御氣遊九天。", "静夜披蘂笈，清晨潄瑶泉。", "閒臨日谷嘯，下拂雲窗眠。", "一朝玉棺墜，委體同蛻蟬。", "霓旌自宛轉，羽駕何飄翩。", "空餘故館在，遺像猶依然。", "嗟吾生已後，不得見當年。", "扶揺若可借，永謝區中緣。"]'),
('3fd312c0-04bb-4b27-8e08-30df3f97bf90','望朝元閣','范祖禹','宋','宋诗','song-poetry','','[]','昔年曾上閣邊行，步步凌霞出太清。',64,'全唐诗/poet.song.50000.json','["昔年曾上閣邊行，步步凌霞出太清。", "鶴駕不歸雲縹緲，鳳簫空斷目分明。", "秦川錯繡孤煙媚，渭水浮銀落日横。", "惆悵重遊今未遂，參差天半望飛甍。"]'),
('4c9f8780-3fd9-43a6-91e3-ce14a230e17a','長安','范祖禹','宋','宋诗','song-poetry','','[]','東風吹塵客心起，京華去蜀三千里。',224,'全唐诗/poet.song.50000.json','["東風吹塵客心起，京華去蜀三千里。", "我来踏雪走函關，下視秦川坦如坻。", "曉登太華三峰寒，憑高始覺天地寛。", "却惜京華不可見，煙花二月過長安。", "長安通衢十二陌，出入九州横八極。", "行人来往但西東，莫問興亡與今昔。", "昔人富貴高臺傾，今人歌舞曲池平。", "終南虚繞帝王宅，壯氣空蟠佳麗城。", "黄河之水東流海，漢家已去唐家改。", "茂陵秋草春更多，豪傑今無一人在。", "細觀此事何足愁，不如飲酒登高樓。", "秦王何苦求九鼎，魏武空勞營八州。", "當年富貴一時事，身後寂寞餘高丘。", "春風開花不易得，一醉何必封公侯。"]'),
('b2bc42cc-b9a8-42d2-b8ec-85803720b1a7','過朝天嶺二首  其一','范祖禹','宋','宋诗','song-poetry','','[]','夜上朝天曉不極，舉頭唯見蒼蒼色。',32,'全唐诗/poet.song.50000.json','["夜上朝天曉不極，舉頭唯見蒼蒼色。", "廻看初日半輪明，下視嘉陵千丈黑。"]'),
('44af2821-d021-4865-90d7-6e08b5a1f4a6','過朝天嶺二首  其二','范祖禹','宋','宋诗','song-poetry','','[]','地拆天開此險成，飄蕭毛髪壯心驚。',32,'全唐诗/poet.song.50000.json','["地拆天開此險成，飄蕭毛髪壯心驚。", "人間行路難如此，嘆息何時險阻平。"]'),
('58e149fe-a926-4958-9ad8-619558261c6f','遊李少師園十題 松島','范祖禹','宋','宋诗','song-poetry','','[]','孤嶼何亭亭，蒼松鬱相對。',24,'全唐诗/poet.song.50000.json','["孤嶼何亭亭，蒼松鬱相對。", "池中蛟龍起，天際風雨會。"]'),
('8a5baab7-8829-452b-a6ee-58b6ebc655e1','遊李少師園十題 芡池','范祖禹','宋','宋诗','song-poetry','','[]','向日鋪青蓋，浮波散緑盤。',24,'全唐诗/poet.song.50000.json','["向日鋪青蓋，浮波散緑盤。", "明珠洛浦珮，白玉水仙丹。"]'),
('8e42f2ba-243b-4a5e-a5cb-235765561ffa','遊李少師園十題 笛竹','范祖禹','宋','宋诗','song-poetry','','[]','鳳食實已美，龍吟聲更奇。',24,'全唐诗/poet.song.50000.json','["鳳食實已美，龍吟聲更奇。", "惜無蔡邕識，那得馬融吹。"]'),
('1f209fd0-b098-4ed2-8af9-4a06ec045ceb','遊李少師園十題 鶴','范祖禹','宋','宋诗','song-poetry','','[]','王子吹笙去，仙禽下雲端。',24,'全唐诗/poet.song.50000.json','["王子吹笙去，仙禽下雲端。", "夜棲松月静，朝舞檜風寒。"]'),
('49257598-2acf-4bb8-a7d7-307b3481b156','遊李少師園十題 水輪','范祖禹','宋','宋诗','song-poetry','','[]','崩騰噴雪浪，晝夜無停息。',24,'全唐诗/poet.song.50000.json','["崩騰噴雪浪，晝夜無停息。", "廻旋天磨轉，運動日卓側。"]'),
('84bc7cd7-9423-4f1e-a9f7-69124a3f0f53','遊李少師園十題 竹逕','范祖禹','宋','宋诗','song-poetry','','[]','整整植翠旗，森森列羽衛。',24,'全唐诗/poet.song.50000.json','["整整植翠旗，森森列羽衛。", "微風羣玉動，赫日蒼雲翳。"]'),
('c818d2d6-95ae-47dc-a433-7aca84db0ec2','遊李少師園十題 蓮池','范祖禹','宋','宋诗','song-poetry','','[]','藻荇徧廻塘，芙蕖出清水。',24,'全唐诗/poet.song.50000.json','["藻荇徧廻塘，芙蕖出清水。", "紅燈迭照映，翠蓋相磨倚。"]'),
('9adf80b8-f12c-466f-bea4-59fc636074fa','遊李少師園十題 月桂','范祖禹','宋','宋诗','song-poetry','','[]','天寒桂子墮，花發向庭中。',24,'全唐诗/poet.song.50000.json','["天寒桂子墮，花發向庭中。", "月華十二滿，常照此芳叢。"]'),
('7f833dd0-00f4-43ec-9404-eb2462dc3e8c','遊李少師園十題 雁翅柏','范祖禹','宋','宋诗','song-poetry','','[]','高枝含煙霧，密葉張羽翼。',24,'全唐诗/poet.song.50000.json','["高枝含煙霧，密葉張羽翼。", "參差隨風勢，慘澹入雲色。"]'),
('7fb1613c-b87e-41eb-aa7d-adf9f63cacf4','遊李少師園十題 茅菴','范祖禹','宋','宋诗','song-poetry','','[]','結茅深林下，開户流水邊。',24,'全唐诗/poet.song.50000.json','["結茅深林下，開户流水邊。", "曉聽松風坐，夜枕雲濤眠。"]'),
('2a4e7a0d-3d2e-4aa5-a006-a6aaff16c9c0','遊李少師園十題 和張二十五遊白龍谿甘水谷郊居雜咏七首 其一','范祖禹','宋','宋诗','song-poetry','','[]','君家瀟灑住園林，更入青山逕路深。',32,'全唐诗/poet.song.50000.json','["君家瀟灑住園林，更入青山逕路深。", "唯有白雲爲得侣，祗應流水是知音。"]'),
('b3a142e1-b085-4a27-bd2a-803172891fd3','遊李少師園十題 和張二十五遊白龍谿甘水谷郊居雜咏七首 其二','范祖禹','宋','宋诗','song-poetry','','[]','松姿鶴性自宜閒，天與幽奇避俗喧。',32,'全唐诗/poet.song.50000.json','["松姿鶴性自宜閒，天與幽奇避俗喧。", "謝客風流臨海嶠，秦人歌嘯入花源。"]'),
('d4f864e9-88bf-4dde-a68f-71384739fbbf','遊李少師園十題 和張二十五遊白龍谿甘水谷郊居雜咏七首 其三','范祖禹','宋','宋诗','song-poetry','','[]','南窗高卧看雲生，日暮廻風動紫荆。',32,'全唐诗/poet.song.50000.json','["南窗高卧看雲生，日暮廻風動紫荆。", "鼓吹不須過野塢，青蛙雨後自能鳴。"]'),
('47fbfb68-b3e7-44df-ac32-e823c6876d6b','遊李少師園十題 和張二十五遊白龍谿甘水谷郊居雜咏七首 其四','范祖禹','宋','宋诗','song-poetry','','[]','田家何所樂，野老飯蒿藜。',48,'全唐诗/poet.song.50000.json','["田家何所樂，野老飯蒿藜。", "沙月鷺投宿，松風猿亂啼。", "侵衣青竹冷，拂面緑蘿低。", "幽步無車馬，唯應杖可攜。"]'),
('2e18ff2e-ca6e-4a7c-9ca1-7a15ad5f8ea6','遊李少師園十題 和張二十五遊白龍谿甘水谷郊居雜咏七首 其五','范祖禹','宋','宋诗','song-poetry','','[]','石逕人行少，山雲袖拂看。',48,'全唐诗/poet.song.50000.json','["石逕人行少，山雲袖拂看。", "水流情共遠，天濶望隨寛。", "笙磬珍禽響，龍蛇怪蔓盤。", "洛川回首處，烟靄暮漫漫。"]'),
('2f03f96a-f019-4144-984a-f63de3dccb37','遊李少師園十題 和張二十五遊白龍谿甘水谷郊居雜咏七首 其六','范祖禹','宋','宋诗','song-poetry','','[]','夜静月明谿水喧，先秋風物已蕭然。',32,'全唐诗/poet.song.50000.json','["夜静月明谿水喧，先秋風物已蕭然。", "藤蘿作帳雲爲枕，冷掛絺衣石上眠。"]');
